-- Poems batch 48
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('1bf9bc7b-e420-4e63-9c3e-acf66a6b4497','楊柳枝詞四首 四','孫光憲','唐','唐诗','tang','','[]','萬株枯槁怨亡隋，似弔吳臺各自垂。',32,'全唐诗/poet.tang.42000.json','["萬株枯槁怨亡隋，似弔吳臺各自垂。", "好是淮陰明月裏，酒樓橫笛不勝吹。"]'),
('5cc308c6-36fd-4be3-9cd6-2014d484b745','採蓮','孫光憲','唐','唐诗','tang','','["\u5b8b\u8bcd\u4e09\u767e\u9996", "\u5973\u5b50", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd"]','菡萏香連十頃陂，小姑貪戲採蓮遲。',32,'全唐诗/poet.tang.42000.json','["菡萏香連十頃陂，小姑貪戲採蓮遲。", "晚來弄水船頭濕，更脫紅裙裹鴨兒。"]'),
('715ce261-c362-4414-909b-4f5e3acde69a','八拍蠻','孫光憲','唐','唐诗','tang','','[]','孔雀尾拖金線長，怕人飛起入丁香。',32,'全唐诗/poet.tang.42000.json','["孔雀尾拖金線長，怕人飛起入丁香。", "越女沙頭爭拾翠，相呼歸去背斜陽。"]'),
('16b53b15-5d6f-4dab-9aa1-7e30a93474b4','句','孫光憲','唐','唐诗','tang','','[]','晚廚烹淡菜，春杼種橦花。',12,'全唐诗/poet.tang.42000.json','["晚廚烹淡菜，春杼種橦花。"]'),
('e7b56285-cbac-4d1a-ac48-8ac94f721ff3','詠蒲鞋','劉章','唐','唐诗','tang','','[]','吳江浪浸白蒲春，越女初挑一樣新。',64,'全唐诗/poet.tang.42000.json','["吳江浪浸白蒲春，越女初挑一樣新。", "纔自繡窗離玉指，便隨羅襪上香塵。", "石榴裙下從容久，玳瑁筵前整頓頻。", "今日高樓鴛瓦上，不知拋擲是何人。"]'),
('25688791-c0d2-4122-99a3-c43f4a81ed74','夜坐','路洵美','唐','唐诗','tang','','[]','簾捲竹軒清，四鄰無語聲。',48,'全唐诗/poet.tang.42000.json','["簾捲竹軒清，四鄰無語聲。", "漏從吟裏轉，月自坐來明。", "草木露華濕，衣裳寒氣生。", "難逢知鑒者，空悅此時情。"]'),
('0a0cbb5c-4d31-4233-9e47-33c62f382dcb','荆臺道院','梁震','唐','唐诗','tang','','[]','桑田一變賦歸來，爵祿焉能凂我哉。',32,'全唐诗/poet.tang.42000.json','["桑田一變賦歸來，爵祿焉能凂我哉。", "黃犢依然花竹外，清風萬古凜荆臺。"]'),
('cc774e43-41a8-4f2c-9403-0d2bc3b97af0','寧州道中','楊夔','唐','唐诗','tang','','[]','城枕蕭關路，胡兵日夕臨。',48,'全唐诗/poet.tang.42000.json','["城枕蕭關路，胡兵日夕臨。", "唯憑一炬火，以慰萬人心。", "春老雪猶重，沙寒草不深。", "如何驅匹馬，向此獨閑吟。"]'),
('cfeff78b-6dd5-4ac4-b3e4-ac3d9d25a5c7','尋九華王山人','楊夔','唐','唐诗','tang','','[]','下馬扣荆扉，相尋春半時。',48,'全唐诗/poet.tang.42000.json','["下馬扣荆扉，相尋春半時。", "捫蘿盤磴險，疊石度溪危。", "松夾莓苔逕，花藏薜荔籬。", "臥雲情自逸，名姓厭人知。"]'),
('0f775508-c849-4a82-8144-778a07957286','金陵逢張喬','楊夔','唐','唐诗','tang','','[]','殊鄉會面時，辛苦兩情知。',48,'全唐诗/poet.tang.42000.json','["殊鄉會面時，辛苦兩情知。", "有志年空過，無媒命共奇。", "吟餘春漏急，語舊酒巡遲。", "天爵如堪倚，休驚鬢上絲。"]'),
('6604b1d2-09eb-4e98-85f4-3a58e033552a','送鄒尊師歸洞庭','楊夔','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','衆島在波心，曾居舊隱林。',48,'全唐诗/poet.tang.42000.json','["衆島在波心，曾居舊隱林。", "近聞飛檄急，轉憶臥雲深。", "賣藥唯供酒，歸舟只載琴。", "遙知明月夜，坐石自開襟。"]'),
('e5326422-4669-4ebb-a98b-e82e8c0dcb69','送日東僧遊天台','楊夔','唐','唐诗','tang','','[]','一瓶離日外，行指赤城中。',48,'全唐诗/poet.tang.42000.json','["一瓶離日外，行指赤城中。", "去自重雲下，來從積水東。", "攀蘿躋石徑，挂錫憩松風。", "迴首雞林道，唯應夢想通。"]'),
('472a45e3-d501-4c0c-8baf-694a965b9948','題甘露寺','楊夔','唐','唐诗','tang','','[]','高殿拂雲霓，登臨想虎溪。',72,'全唐诗/poet.tang.42000.json','["高殿拂雲霓，登臨想虎溪。", "風勻帆影衆，煙亂鳥行迷。", "北倚波濤闊，南窺井邑低。", "滿城塵漠漠，隔岸草萋萋。", "虛閣延秋磐，澄江響暮鼙。", "客心還惜去，新月挂樓西。"]'),
('fe665d82-69e7-478d-a14b-c722edc600ca','送張相公出征','楊夔','唐','唐诗','tang','','[]','得意在當年，登壇秉國權。',120,'全唐诗/poet.tang.42000.json','["得意在當年，登壇秉國權。", "漢推周勃重，晉讓趙宣賢。", "儒德尼丘降，兵鈐太白傳。", "援毫飛鳳藻，發匣吼龍泉。", "歷火金難耗，零霜桂益堅。", "從來稱玉潔，此更讓朱妍。", "鴛鷺臻門下，貔貅擁帳前。", "去知清朔漠，行不費陶甄。", "獻畫符中旨，推誠契上玄。", "願將班固筆，書頌勒燕然。"]'),
('9b1a65f6-ce42-4e58-9d11-fbb5f4a9fbc9','題鄭山人郊居','楊夔','唐','唐诗','tang','','[]','谷口今逢避世才，入門瀟灑絕塵埃。',64,'全唐诗/poet.tang.42000.json','["谷口今逢避世才，入門瀟灑絕塵埃。", "漁舟下釣乘風去，藥醞留賓待月開。", "數片石從青嶂得，一條泉自白雲來。", "竹軒相對無言語，盡日南山不欲迴。"]'),
('03f121b3-ce20-48eb-ab67-2f5aeaf37617','題宣州延慶寺益公院','楊夔','唐','唐诗','tang','','[]','嘿坐能除萬種情，臘高兼有賜衣榮。',64,'全唐诗/poet.tang.42000.json','["嘿坐能除萬種情，臘高兼有賜衣榮。", "講經舊說傾朝聽，登殿曾聞降輦迎。", "幽逕北連千嶂碧，虛窗東望一川平。", "長年門外無塵客，時見元戎駐斾旌。"]'),
('6d0d93bf-937d-419a-8124-d69b874c2852','寄當陽袁皓明府','楊夔','唐','唐诗','tang','','[]','高人爲縣在南京，竹遶琴堂水遶城。',64,'全唐诗/poet.tang.42000.json','["高人爲縣在南京，竹遶琴堂水遶城。", "地古既資攜酒興，務閑偏長看山情。", "松軒待月僧同坐，藥圃尋花鶴伴行。", "百里甚堪留惠愛，莫教空說魯恭名。"]'),
('a27ad4fa-825a-41ee-9bf5-4a606879b430','送杜郎中入茶山修貢','楊夔','唐','唐诗','tang','','[]','一道澄瀾徹底清，仙郎輕棹出重城。',64,'全唐诗/poet.tang.42000.json','["一道澄瀾徹底清，仙郎輕棹出重城。", "採蘋虛得當時稱，述職那同此日榮。", "劍戟步經高障黑，綺羅光動百花明。", "謝公攜妓東山去，何似乘春奉昭行。"]'),
('994a97c9-d9ae-4e87-ba69-2c71b2f1ec99','送鄭谷','楊夔','唐','唐诗','tang','','[]','春江瀲瀲清且急，春雨濛濛密復疎。',32,'全唐诗/poet.tang.42000.json','["春江瀲瀲清且急，春雨濛濛密復疎。", "一曲狂歌兩行淚，送君兼寄故鄉書。"]'),
('24295bb5-bc88-483f-8832-61c3492962a5','自敘','杜建徽','唐','唐诗','tang','','[]','中劍斫耳缺，被箭射胛過。',24,'全唐诗/poet.tang.42000.json','["中劍斫耳缺，被箭射胛過。", "爲將須有膽，有膽即無賈。"]'),
('f096b926-50af-4ea6-9476-3e38e9d91046','游西湖','沈韜文','唐','唐诗','tang','','["\u897f\u6e56"]','□□□□□□□，菰米蘋花似故鄉。',32,'全唐诗/poet.tang.42000.json','["□□□□□□□，菰米蘋花似故鄉。", "不是不歸歸未得，好風明月一思量。"]'),
('a3a7ffa4-dd17-492e-9a67-219ccf0d6797','贈和龍妙空禪師','王繼勳','唐','唐诗','tang','','[]','白面山南靈慶院，茅齋道者雪峰禪。',64,'全唐诗/poet.tang.42000.json','["白面山南靈慶院，茅齋道者雪峰禪。", "只棲雲樹兩三畝，不下煙蘿四五年。", "猨鳥認聲呼喚易，龍神降伏住持堅。", "誰知今日秋江畔，獨步醫王闡法筵。"]'),
('43592b95-2043-41f6-aa40-20302d19006d','題建造寺','王繼勳','唐','唐诗','tang','','[]','曾看畫圖勞健羨，如今親見畫猶麄。',64,'全唐诗/poet.tang.42000.json','["曾看畫圖勞健羨，如今親見畫猶麄。", "減除天半石初泐，欠却幾株松未枯。", "題像閣人漁浦叟，集生臺鳥謝城烏。", "我來一聽支公論，自是吾身幻得吾。"]'),
('1a5f8013-cae3-4b86-b794-4621760aa0c2','句','王繼勳','唐','唐诗','tang','','[]','掃石雲隨帚，耕山鳥傍人。',12,'全唐诗/poet.tang.42000.json','["掃石雲隨帚，耕山鳥傍人。"]'),
('97fcd646-dfca-408b-b751-38a0e6f7db44','和贈和龍妙空禪師','夏鴻','唐','唐诗','tang','','[]','翰林遺跡鏡潭前，孤峭高僧此處禪。',64,'全唐诗/poet.tang.42000.json','["翰林遺跡鏡潭前，孤峭高僧此處禪。", "出爲信門興化日，坐當吾國太平年。", "身同瑩澈尼珠淨，語並鋒鋩慧劒堅。", "道果已圓名已遂，即看千匝遶香筵。"]'),
('dcd73268-dd29-4948-823b-3e659b372901','題青草湖神祠','劉山甫','唐','唐诗','tang','','[]','壞牆風雨幾經春，草色盈庭一座塵。',32,'全唐诗/poet.tang.42000.json','["壞牆風雨幾經春，草色盈庭一座塵。", "自是神明無感應，盛衰何得却由人。"]'),
('63d98bf0-16c0-44ba-a264-09d3f6e9b906','漢宗廟樂舞辭','張昭','唐','唐诗','tang','','[]','高廟明靈再啓圖，金根玉輅幸神都。',128,'全唐诗/poet.tang.42000.json','["高廟明靈再啓圖，金根玉輅幸神都。", "巢阿丹鳳銜書命，入昴飛星獻寶符。", "正撫薰弦娛赤子，忽登仙駕泣蒼梧。", "薦櫻鶴館笳簫咽，酌鬯金楹劒珮趨。", "星俎雲罍兼魯禮，朱干象箾雜巴渝。", "氤氳龍麝交青瑣，髣髴錫鑾下蘂珠。", "薦豆奉觴親玉几，配天合祖耀璿樞。", "受釐飲酒皇歡洽，仰俟餘靈泰九區。"]'),
('31427f17-532e-4aa3-8c52-a70ec72b5588','農家','顏仁郁','唐','唐诗','tang','','[]','夜半呼兒趁曉耕，羸牛無力漸艱行。',32,'全唐诗/poet.tang.42000.json','["夜半呼兒趁曉耕，羸牛無力漸艱行。", "時人不識農家苦，將謂田中穀自生。"]'),
('a90f799a-ec06-4064-bcd3-e58c0f4e9240','山居','顏仁郁','唐','唐诗','tang','','[]','栢樹松陰覆竹齋，罷燒藥竈縱高懷。',32,'全唐诗/poet.tang.42000.json','["栢樹松陰覆竹齋，罷燒藥竈縱高懷。", "世間應少山間景，雲遶青松水遶堦。"]'),
('0754a2f4-407d-4f84-9ec6-23eeca619c9e','春日寓感','王延彬','唐','唐诗','tang','','[]','兩衙前後訟堂清，軟錦披袍擁鼻行。',64,'全唐诗/poet.tang.42000.json','["兩衙前後訟堂清，軟錦披袍擁鼻行。", "雨後綠苔侵履跡，春深紅杏鎖鶯聲。", "因攜久醞松醪酒，自煮新抽竹筍羹。", "也解爲詩也爲政，儂家何似謝宣城。"]'),
('f38412bc-17aa-4870-b73b-e823ab8f77d4','哭徐夤','王延彬','唐','唐诗','tang','','[]','延壽溪頭歎逝波，古今人事半銷磨。',32,'全唐诗/poet.tang.42000.json','["延壽溪頭歎逝波，古今人事半銷磨。", "昔除正字今何在，所謂人生能幾何。"]'),
('d3a88977-cdaf-4b98-a354-df1455f62106','塞上 一','譚用之','唐','唐诗','tang','','[]','秋風漢北雁飛天，單騎那堪遶賀蘭。',64,'全唐诗/poet.tang.42000.json','["秋風漢北雁飛天，單騎那堪遶賀蘭。", "磧暗更無巖樹影，地平時有野燒瘢。", "貂披寒色和衣冷，劒佩胡霜隔匣寒。", "早晚橫戈似飛尉，擁旄深入異田單。"]'),
('3b6343ba-5951-4501-a0f9-4d3eb18bea8e','塞上 二','譚用之','唐','唐诗','tang','','[]','鉢略城邊日欲西，遊人却憶舊山歸。',64,'全唐诗/poet.tang.42000.json','["鉢略城邊日欲西，遊人却憶舊山歸。", "牛羊集水煙黏步，鵰鶚盤空雪滿圍。", "獵騎靜逢邊氣薄，戍樓寒對暮煙微。", "橫行總是男兒事，早晚重來似漢飛。"]'),
('1a18180f-bc27-4a22-b633-56912b5f4845','贈索處士','譚用之','唐','唐诗','tang','','[]','不將桂子種諸天，長得尋君水石邊。',64,'全唐诗/poet.tang.42000.json','["不將桂子種諸天，長得尋君水石邊。", "玄豹夜寒和霧隱，驪龍春暖抱珠眠。", "山中宰相陶弘景，洞裏真人葛稚川。", "一度相思一惆悵，水寒煙澹落花前。"]'),
('d08421bc-b993-42bd-9293-84de33af3dde','別雒下一二知己','譚用之','唐','唐诗','tang','','[]','金鼎光輝照雪袍，雒陽春夢憶波濤。',64,'全唐诗/poet.tang.42000.json','["金鼎光輝照雪袍，雒陽春夢憶波濤。", "塵埃滿眼人情異，風雨前程馬足勞。", "接塞峨眉通蜀險，過山仙掌倚秦高。", "別來無限幽求子，應笑區區味六韜。"]'),
('79883e4d-9f24-4ec1-8116-00328b108dce','約張處士遊梁','譚用之','唐','唐诗','tang','','[]','莫學區區老一經，夷門關吏舊書生。',64,'全唐诗/poet.tang.42000.json','["莫學區區老一經，夷門關吏舊書生。", "晉朝滅後無中散，韓國亡來絕上卿。", "龍變洞中千谷冷，劒橫天外八風清。", "好攜長策干時去，免逐漁樵度太平。"]'),
('a11697ae-8d15-4e35-bbbc-c9dd9f227a4f','送友人歸青社','譚用之','唐','唐诗','tang','','[]','鵰鶚途程在碧天，綵衣東去復何言。',64,'全唐诗/poet.tang.42000.json','["鵰鶚途程在碧天，綵衣東去復何言。", "二千賓客舊知己，十二山河新故園。", "吟看桂生溪月上，醉聽鯤化海濤翻。", "好期聖代重相見，莫學袁生老竹軒。"]'),
('10c16cc5-de29-47ea-9ccc-63b2fcc2580b','送丁道士歸南中','譚用之','唐','唐诗','tang','','[]','孤雲無定鶴辭巢，自負焦桐不說勞。',64,'全唐诗/poet.tang.42000.json','["孤雲無定鶴辭巢，自負焦桐不說勞。", "服藥幾年期碧落，驗符何處呪丹毫。", "子陵山曉紅雲密，青草湖平雪浪高。", "從此人稀見蹤跡，還應選地種仙桃。"]'),
('d956b477-89b3-48dc-8064-8cfb1dced543','月夜懷寄友人','譚用之','唐','唐诗','tang','','[]','劒氣徒勞望斗牛，故人別後阻仙舟。',64,'全唐诗/poet.tang.42000.json','["劒氣徒勞望斗牛，故人別後阻仙舟。", "殘春謾道深傾酒，好月那堪獨上樓。", "何處是非隨馬足，由來得喪白人頭。", "清風未許重攜手，幾度高吟寄水流。"]'),
('8652e814-2fda-4e22-9d08-753e0e01e8ee','閑居寄陳山人','譚用之','唐','唐诗','tang','','[]','閑居何處得閑名，坐掩衡茅損性靈。',66,'全唐诗/poet.tang.42000.json','["閑居何處得閑名，坐掩衡茅損性靈。", "破夢曉鐘聞竹寺，沁心秋雨浸莎庭。", "甕邊難負千杯綠，海上終眠萬仞青。", "珍重先生全太古，應看名利似浮[萍]。"]'),
('c8f0a4d8-c0b2-480a-9f87-78504832fc26','憶南中','譚用之','唐','唐诗','tang','','[]','碧江頭與白雲門，別後秋霜點鬢根。',64,'全唐诗/poet.tang.42000.json','["碧江頭與白雲門，別後秋霜點鬢根。", "長記學禪青石寺，最思共醉落花村。", "林間竹有湘妃淚，窗外禽多杜宇魂。", "未棹扁舟重回首，采薇收橘不堪論。"]'),
('4109bc76-ad12-4d37-8fd0-459c3599f208','寄友人','譚用之','唐','唐诗','tang','','[]','病多慵引架書看，官職無才思已闌。',64,'全唐诗/poet.tang.42000.json','["病多慵引架書看，官職無才思已闌。", "穴鳳瑞時來却易，人龍別後見何難。", "琴樽風月閑生計，金玉松筠舊歲寒。", "早晚煙村碧江畔，挂罾重對蓼花灘。"]'),
('954fbc7a-2615-42b8-94fa-49d4158a5a12','別江上一二友生','譚用之','唐','唐诗','tang','','[]','國風千載務重華，須逐浮雲背若耶。',64,'全唐诗/poet.tang.42000.json','["國風千載務重華，須逐浮雲背若耶。", "無地可歸堪種玉，有天教上且乘槎。", "白綸巾卸蘇門月，紅錦衣裁御苑花。", "他日成都却回首，東山看取謝鯤家。"]'),
('4ed040e9-0c8d-4370-a5ed-63002d4568f6','寄岐山林逢吉明府','譚用之','唐','唐诗','tang','','[]','岐山高與隴山連，製錦無私服晏眠。',64,'全唐诗/poet.tang.42000.json','["岐山高與隴山連，製錦無私服晏眠。", "鸚鵡語中分百里，鳳凰聲裏過三年。", "秦無舊俗雲煙媚，周有遺風父老賢。", "莫役生靈種楊柳，一枝枝折灞橋邊。"]'),
('fb845bb5-2ae9-4d16-bef1-a49d27bce731','感懷呈所知','譚用之','唐','唐诗','tang','','[]','十年流落賦歸鴻，誰傍昏衢駕燭龍。',64,'全唐诗/poet.tang.42000.json','["十年流落賦歸鴻，誰傍昏衢駕燭龍。", "竹屋亂煙思梓澤，酒家疎雨夢臨邛。", "千年別恨調琴懶，一片年光覽鏡慵。", "早晚休歌白石爛，放教歸去臥羣峰。"]'),
('cd8057a1-0811-46b9-adc7-a53bd6af094e','江上聞笛','譚用之','唐','唐诗','tang','','[]','誰爲梅花怨未平，一聲高喚百龍驚。',64,'全唐诗/poet.tang.42000.json','["誰爲梅花怨未平，一聲高喚百龍驚。", "風當閶闔庭初靜，月在姑蘇秋正明。", "曲盡綠楊涵野渡，管吹青玉動江城。", "臨流不欲殷勤聽，芳草王孫舊有情。"]'),
('68dbfdcd-54c9-473e-b0f5-32775afabaac','寄孟進士','譚用之','唐','唐诗','tang','','[]','依舊池邊草色芳，故人何處憶山陽。',64,'全唐诗/poet.tang.42000.json','["依舊池邊草色芳，故人何處憶山陽。", "書回科斗江帆暮，曲罷騶虞海樹蒼。", "吟望曉煙思桂渚，醉依殘月夢餘杭。", "別來南國知誰在，空對襜褕一斷腸。"]'),
('1e33ac15-1801-40e4-bc21-f49c2fb66a1f','寄閻記室','譚用之','唐','唐诗','tang','','[]','織錦歌成下翠微，豈勞西去問搘機。',64,'全唐诗/poet.tang.42000.json','["織錦歌成下翠微，豈勞西去問搘機。", "未開水府珠先見，不掘豐城劒自輝。", "鼇逐玉蟾攀桂上，馬隨青帝踏花歸。", "相逢半是雲霄客，應笑歌牛一布衣。"]'),
('e751f62a-c733-4126-bd5b-ed000d4eea67','幽居寄李祕書','譚用之','唐','唐诗','tang','','[]','幾年帝里阻煙波，敢向明時叩角歌。',64,'全唐诗/poet.tang.42000.json','["幾年帝里阻煙波，敢向明時叩角歌。", "看盡好花春臥穩，醉殘紅日夜吟多。", "印開夕照垂楊柳，畫破寒潭老芰荷。", "昨夜前溪有龍鬬，石橋風雨少人過。"]'),
('fe9ed2e7-f3e1-47cb-b382-e0e1a8338eb7','貽釣魚李處士','譚用之','唐','唐诗','tang','','[]','罷吟鸚鵡草芊芊，又泛鴛鴦水上天。',64,'全唐诗/poet.tang.42000.json','["罷吟鸚鵡草芊芊，又泛鴛鴦水上天。", "一棹冷涵楊柳雨，片帆香挂芰荷煙。", "綠搖江澹萍離岸，紅點雲疎橘滿川。", "何處邈將歸畫府，數莖紅蓼一漁船。"]'),
('e595921f-d85b-41cb-ac74-fcacbb367e55','河橋樓賦得羣公夜讌','譚用之','唐','唐诗','tang','','[]','芙蓉簾幕扇秋紅，蠻府新郎夜讌同。',64,'全唐诗/poet.tang.42000.json','["芙蓉簾幕扇秋紅，蠻府新郎夜讌同。", "滿座馬融吹笛月，一樓張翰過江風。", "杯黏紫酒金螺重，談轉琱璫玉麈空。", "深荷良宵慰顦顇，德星池館在江東。"]'),
('a6cb2d85-b8c5-4610-88a5-683111b70f01','寄左先輩','譚用之','唐','唐诗','tang','','[]','狂歌白鹿上青天，何似蘭塘釣紫煙。',64,'全唐诗/poet.tang.42000.json','["狂歌白鹿上青天，何似蘭塘釣紫煙。", "萬卷祖龍坑外物，一泓孫楚耳中泉。", "翩翾蠻榼薰晴浦，轂轆魚車響夜船。", "學取青蓮李居士，一生杯酒在神仙。"]'),
('5f14490e-3ac2-4a00-bc12-244411457d72','貽費道人','譚用之','唐','唐诗','tang','','[]','誰如南浦傲煙霞，白葛衣青稱帽紗。',64,'全唐诗/poet.tang.42000.json','["誰如南浦傲煙霞，白葛衣青稱帽紗。", "碧玉蜉蝣迎客酒，黃金轂轆釣魚車。", "吟歌雲鳥歸樵谷，臥愛神仙入畫家。", "他日鳳書何處覓，武陵煙樹半桃花。"]'),
('50cbc98b-de29-4682-96dc-6b745abf1a00','寄許下前管記王侍御','譚用之','唐','唐诗','tang','','[]','昔年南去得娛賓，頓遜杯前共好春。',64,'全唐诗/poet.tang.42000.json','["昔年南去得娛賓，頓遜杯前共好春。", "螘泛羽觴蠻酒膩，鳳銜瑤句蜀牋新。", "花憐遊騎紅隨轡，草戀征車碧遶輪。", "別後青青鄭南陌，不知風月屬何人。"]'),
('d03a8244-7fdf-4415-874c-85c8de64a49b','秋日圃田送人隨計','譚用之','唐','唐诗','tang','','[]','僕射陂前是傳郵，去程鵰鶚弄高秋。',64,'全唐诗/poet.tang.42000.json','["僕射陂前是傳郵，去程鵰鶚弄高秋。", "吟拋芍藥裁詩圃，醉下茱萸飲酒樓。", "向日迥飛駒皎皎，臨風誰和鹿呦呦。", "明年二月仙山下，莫遣桃花逐水流。"]'),
('38cbdfcd-fe34-4e15-b2e5-e2594156d018','途次宿友人別墅','譚用之','唐','唐诗','tang','','[]','千里崤函一夢勞，豈知雲館共蕭騷。',64,'全唐诗/poet.tang.42000.json','["千里崤函一夢勞，豈知雲館共蕭騷。", "半簾綠透偎寒竹，一榻紅侵墜晚桃。", "蠻酒客稀知味長，蜀琴風定覺弦高。", "感君巖下閑招隱，細縷金盤鱠錯刀。"]'),
('b0d42eb3-a8e9-4fe7-a1a7-c527330cc62c','春日期巢湖舊事','譚用之','唐','唐诗','tang','','[]','暖掠紅香燕燕飛，五雲仙珮曉相攜。',64,'全唐诗/poet.tang.42000.json','["暖掠紅香燕燕飛，五雲仙珮曉相攜。", "花開鸚鵡韋郎曲，竹亞虬龍白帝溪。", "富貴萬場歸紫酒，是非千載逐芳泥。", "不知多少開元事，露泣春叢向日低。"]'),
('0403745c-78f8-4d78-9213-f00dd4ef2681','再遊韋曲山寺','譚用之','唐','唐诗','tang','','[]','鵲巖煙斷玉巢欹，罨畫春塘太白低。',64,'全唐诗/poet.tang.42000.json','["鵲巖煙斷玉巢欹，罨畫春塘太白低。", "馬踏翠開垂柳寺，人耕紅破落花蹊。", "千年勝概咸原上，幾代荒涼繡嶺西。", "碧吐紅芳舊行處，豈堪回首草萋萋。"]'),
('b5931bd5-62a4-4bd1-b87f-d993d8e3c084','寄徐拾遺','譚用之','唐','唐诗','tang','','[]','長竿一繫白龍吟，誰和騶虞發素琴。',64,'全唐诗/poet.tang.42000.json','["長竿一繫白龍吟，誰和騶虞發素琴。", "野客碧雲魂易斷，故人芳草夢難尋。", "天從補後星辰穩，海自潮來島嶼深。", "好向明庭拾遺事，莫教玄豹老泉林。"]'),
('e9a4a9d6-5dab-43f2-bd05-009dc5712b62','秋宿湘江遇雨','譚用之','唐','唐诗','tang','','["\u5199\u96e8", "\u79cb\u5929", "\u96e8", "\u6000\u624d\u4e0d\u9047"]','江上陰雲鎖夢魂，江邊深夜舞劉琨。',64,'全唐诗/poet.tang.42000.json','["江上陰雲鎖夢魂，江邊深夜舞劉琨。", "秋風萬里芙蓉國，暮雨千家薜荔村。", "鄉思不堪悲橘柚，旅遊誰肯重王孫。", "漁人相見不相問，長笛一聲歸島門。"]'),
('fcc8b48a-691d-4af3-8155-28d22f5f0432','貽南康陳處士陶','譚用之','唐','唐诗','tang','','[]','白玉堆邊蔣逕橫，空涵二十四灘聲。',64,'全唐诗/poet.tang.42000.json','["白玉堆邊蔣逕橫，空涵二十四灘聲。", "老無征戰軒轅國，貧有茅茨帝舜城。", "丹鳳晝飛羣木冷，一龍秋臥九江清。", "時人莫笑非經濟，還待中原致太平。"]'),
('527ad3af-c6b3-4d0b-9986-435da77e6041','渭城春晚','譚用之','唐','唐诗','tang','','[]','秦樹朦朧春色微，香風煙煖樹依依。',64,'全唐诗/poet.tang.42000.json','["秦樹朦朧春色微，香風煙煖樹依依。", "邊城夜靜月初上，芳草路長人未歸。", "折柳且堪吟晚檻，弄花何處醉殘暉。", "釣鄉千里斷消息，滿目碧雲空自飛。"]'),
('74acc08d-d1b6-415d-98ed-dd84959f28b4','山中春晚寄賈員外','譚用之','唐','唐诗','tang','','[]','不隨黃鶴起煙波，應笑無成返薜蘿。',64,'全唐诗/poet.tang.42000.json','["不隨黃鶴起煙波，應笑無成返薜蘿。", "看盡好花春臥穩，醉殘紅日夜吟多。", "高添雅興松千尺，暗養清音竹數科。", "珍重仙曹舊知己，往來星騎一相過。"]'),
('5b776fd4-28ac-4c6a-a84d-2babe0bbc17a','貽淨居寺新及第','譚用之','唐','唐诗','tang','','[]','秋池雲下白蓮香，池上吟仙寄竹房。',64,'全唐诗/poet.tang.42000.json','["秋池雲下白蓮香，池上吟仙寄竹房。", "閑頌國風文字古，靜消心火夢魂涼。", "三春蓬島花無限，八月銀河路更長。", "此境空門不曾有，從頭好語與醫王。"]'),
('051a88e1-e5db-4feb-a8d3-2b11d9f9ddef','江邊秋夕','譚用之','唐','唐诗','tang','','[]','千鍾紫酒薦菖蒲，松島蘭舟瀲灩居。',64,'全唐诗/poet.tang.42000.json','["千鍾紫酒薦菖蒲，松島蘭舟瀲灩居。", "曲內橘香江客笛，字中嵐氣岳僧書。", "吟期汗漫驅金虎，坐約丹青跨玉魚。", "七色花虬一聲鶴，幾時乘興上清虛。"]'),
('a3a57110-6617-42c4-884f-bc1ee5591edb','送僧中孚南歸','譚用之','唐','唐诗','tang','','[]','琵琶峽口月溪邊，玉乳頭佗憶舊川。',64,'全唐诗/poet.tang.42000.json','["琵琶峽口月溪邊，玉乳頭佗憶舊川。", "一錫冷涵蘭徑路，片帆香挂橘洲煙。", "苔封石錦棲霞室，水迸衣珠噴玉蟬。", "莫道翩翩去如夢，本來吟鳥在林泉。"]'),
('376f0416-146f-4c98-af12-b5dba587fd42','江館秋夕','譚用之','唐','唐诗','tang','','[]','耿耿銀河鴈半橫，夢欹金碧轆轤輕。',64,'全唐诗/poet.tang.42000.json','["耿耿銀河鴈半橫，夢欹金碧轆轤輕。", "滿窗謝練江風白，一枕齊紈海月明。", "楊柳敗梢飛葉響，芰荷香柄折秋鳴。", "誰人更唱陽關曲，牢落煙霞夢不成。"]'),
('be9522df-c600-404e-a022-71045b77fff9','秋夜同友人話舊','譚用之','唐','唐诗','tang','','[]','露下銀河鴈度頻，囊中壚火幾時真。',64,'全唐诗/poet.tang.42000.json','["露下銀河鴈度頻，囊中壚火幾時真。", "數莖白髮生浮世，一盞寒燈共故人。", "雲外簟涼吟嶠月，島邊花暖釣江春。", "何當歸去重攜手，依舊紅霞作近鄰。"]'),
('7df0c4e2-5e24-4021-aae3-b25b66129fd6','古劍','譚用之','唐','唐诗','tang','','[]','鑄時天匠待英豪，紫焰寒星匣倍牢。',64,'全唐诗/poet.tang.42000.json','["鑄時天匠待英豪，紫焰寒星匣倍牢。", "三尺何年拂塵土，四溟今日絕波濤。", "雄應垓下收蛇陣，滯想溪頭伴豹韜。", "惜是真龍懶拋擲，夜來衝斗氣何高。"]'),
('c586d8b2-d403-4237-88b5-b1337c6b48d9','寄王侍御','譚用之','唐','唐诗','tang','','[]','鳥盡弓藏良可哀，誰知歸釣子陵臺。',64,'全唐诗/poet.tang.42000.json','["鳥盡弓藏良可哀，誰知歸釣子陵臺。", "鍊多不信黃金耗，吟苦須驚白髮催。", "喘月吳牛知夜至，嘶風胡馬識秋來。", "燕歌別後休惆悵，黍已成畦菊已開。"]'),
('f51fc6e1-c699-47a6-a71b-fc5e9d5845d8','別何處士陵俊老','譚用之','唐','唐诗','tang','','[]','三皇上人春夢醒，東侯老大麒麟生。',64,'全唐诗/poet.tang.42000.json','["三皇上人春夢醒，東侯老大麒麟生。", "洞連龍穴全山冷，窗透鼇波盡室清。", "計拙恥居巖麓老，氣狂慙與斗牛平。", "誰人爲向青編上，直傍巢由寫一名。"]'),
('0d761762-f5ee-4a31-af1c-718a4b839c63','句','譚用之','唐','唐诗','tang','','[]','流水物情諳世態，落花春夢壓塵勞。',64,'全唐诗/poet.tang.42000.json','["流水物情諳世態，落花春夢壓塵勞。", "織檻錦紋苔乍結，墮書花印菊初殘。", "光陰老去無成事，富貴不來爭奈何。", "眠雲無限好知己，應笑不歸花滿樽。"]'),
('f3ead31d-ce9e-4854-b981-847252b4b3ee','泊姑熟口','王周','唐','唐诗','tang','','[]','杳杳金陵路，難禁欲斷魂。',48,'全唐诗/poet.tang.42000.json','["杳杳金陵路，難禁欲斷魂。", "雨晴山有態，風晚水無痕。", "遠色千檣岸，愁聲一笛村。", "如何遣懷抱，詩畢自開尊。"]'),
('80c53ed0-4fd7-4bad-b3b2-91e6ba802fb4','湖口縣','王周','唐','唐诗','tang','','[]','柴桑分邑載圖經，屈曲山光展畫屏。',32,'全唐诗/poet.tang.42000.json','["柴桑分邑載圖經，屈曲山光展畫屏。", "最是蘆洲東北望，人家殘照隔煙汀。"]'),
('4a6e6303-7dfe-422f-aa6b-4c7fc3e4f694','岳州衆湖阻風二首 一','王周','唐','唐诗','tang','','[]','衆湖湖口繫蘭船，睡起中餐又却眠。',32,'全唐诗/poet.tang.42000.json','["衆湖湖口繫蘭船，睡起中餐又却眠。", "風伯如何解迴怒，數宵檣倚碧蘆煙。"]'),
('f53b0daa-1785-4364-9cd4-0bd441beff63','岳州衆湖阻風二首 二','王周','唐','唐诗','tang','','[]','偶繫扁舟枕綠莎，旋移深處避驚波。',32,'全唐诗/poet.tang.42000.json','["偶繫扁舟枕綠莎，旋移深處避驚波。", "曉來閑共漁人話，此去巴陵路幾多。"]'),
('80121679-1d9f-4e8b-95ef-a5df953cf296','問春','王周','唐','唐诗','tang','','[]','遊絲垂幄雨依依，枝上紅香片片飛。',32,'全唐诗/poet.tang.42000.json','["遊絲垂幄雨依依，枝上紅香片片飛。", "把酒問春因底意，爲誰來後爲誰歸。"]'),
('dda42d82-acea-4e4f-bee2-f83b23b6975e','春荅','王周','唐','唐诗','tang','','[]','花枝千萬趁春開，三月瓓珊即自回。',32,'全唐诗/poet.tang.42000.json','["花枝千萬趁春開，三月瓓珊即自回。", "剩向東園種桃李，明年依舊爲君來。"]'),
('d01692ff-b859-416e-a3c7-cf7ba9dbdfeb','西塞山二首 一','王周','唐','唐诗','tang','','[]','西塞名山立翠屏，濃嵐橫入半江青。',32,'全唐诗/poet.tang.42000.json','["西塞名山立翠屏，濃嵐橫入半江青。", "千尋鐵鏁無由問，石壁空存道者形。"]'),
('7e58b4c8-7f40-4737-9eef-55eac0808d87','西塞山二首 二','王周','唐','唐诗','tang','','[]','匹婦頑然莫問因，匹夫何去望千春。',32,'全唐诗/poet.tang.42000.json','["匹婦頑然莫問因，匹夫何去望千春。", "翻思岵屺傳詩什，舉世曾無化石人。"]'),
('27c989a1-0e6e-41da-801e-12bf82274e69','使風','王周','唐','唐诗','tang','','[]','風起即千里，風回翻問津。',24,'全唐诗/poet.tang.42000.json','["風起即千里，風回翻問津。", "沈思宦遊者，何啻使風人。"]'),
('d427f29d-3355-4574-8a32-c5cd2e53bcf7','石首山','王周','唐','唐诗','tang','','["\u957f\u6c5f"]','首出崔嵬占上遊，迥存濃翠向荆州。',32,'全唐诗/poet.tang.42000.json','["首出崔嵬占上遊，迥存濃翠向荆州。", "空聞別有回山力，却見長江曲尺流。"]'),
('8ce50fcd-ef55-4507-abc8-08df406bbf21','金口步','王周','唐','唐诗','tang','','[]','兩山鬬咽喉，羣石矗牙齒。',24,'全唐诗/poet.tang.42000.json','["兩山鬬咽喉，羣石矗牙齒。", "行客無限怨，橫吞一江水。"]'),
('c784dee4-e753-4ad6-aaa0-4917781e0608','采桑女二首 一','王周','唐','唐诗','tang','','[]','渡水采桑歸，蠶老催上機。',24,'全唐诗/poet.tang.42000.json','["渡水采桑歸，蠶老催上機。", "扎扎得盈尺，輕素何人衣。"]'),
('ccdd125f-6b25-448e-89f8-c876fc6703e6','采桑女二首 二','王周','唐','唐诗','tang','','[]','採桑知蠶飢，投梭惜夜遲。',24,'全唐诗/poet.tang.42000.json','["採桑知蠶飢，投梭惜夜遲。", "誰誇羅綺叢，新畫學月眉。"]'),
('9a12caab-9bd4-4b27-9862-381df992761d','渡溪','王周','唐','唐诗','tang','','[]','渡溪溪水急，水濺羅衣濕。',24,'全唐诗/poet.tang.42000.json','["渡溪溪水急，水濺羅衣濕。", "日暮猶未歸，盈盈水邊立。"]'),
('bb2b70d6-9985-4b06-a850-5b51f2c98e1b','落葉','王周','唐','唐诗','tang','','[]','素律鑠欲脆，青女妒復稀。',24,'全唐诗/poet.tang.42000.json','["素律鑠欲脆，青女妒復稀。", "月冷天風吹，葉葉乾紅飛。"]'),
('6bfefbd7-5c69-4928-80a8-91c582aa7b11','宿疎陂驛','王周','唐','唐诗','tang','','[]','秋染棠梨葉半紅，荆州東望草平空。',32,'全唐诗/poet.tang.42000.json','["秋染棠梨葉半紅，荆州東望草平空。", "誰知孤宦天涯意，微雨蕭蕭古驛中。"]'),
('b552e4ac-7559-495b-af36-aa85f4be0013','再經秭歸二首 一','王周','唐','唐诗','tang','','[]','總角曾隨上峽船，尋思如夢可悽然。',32,'全唐诗/poet.tang.42000.json','["總角曾隨上峽船，尋思如夢可悽然。", "夜來孤館重來宿，枕底灘聲似舊年。"]'),
('da2a5d28-ff7a-4cc1-8822-2d51e6eaafb5','再經秭歸二首 二','王周','唐','唐诗','tang','','[]','秭歸城邑昔曾過，舊識無人奈老何。',32,'全唐诗/poet.tang.42000.json','["秭歸城邑昔曾過，舊識無人奈老何。", "獨有淒清難改處，月明聞唱竹枝歌。"]'),
('811552b4-5ca3-489e-8e5c-7ae7f0f3487b','霞','王周','唐','唐诗','tang','','[]','拂拂生殘暉，層層如裂緋。',24,'全唐诗/poet.tang.42000.json','["拂拂生殘暉，層層如裂緋。", "天風翦成片，疑作仙人衣。"]'),
('868f376b-2a60-4eac-8020-4ef885998e00','巫山公署壁有無名氏戲書二韻','王周','唐','唐诗','tang','','[]','南陵直上路盤盤，平地凌雲勢萬端。',32,'全唐诗/poet.tang.42000.json','["南陵直上路盤盤，平地凌雲勢萬端。", "堪笑巴民不厭足，更嫌山少畫山看。"]'),
('c4e115bf-547d-4ed4-a20d-97bd569a4507','道院','王周','唐','唐诗','tang','','[]','白日人稀到，簾垂道院深。',48,'全唐诗/poet.tang.42000.json','["白日人稀到，簾垂道院深。", "雨苔生古壁，雪雀聚寒林。", "忘慮憑三樂，消閑信五禽。", "誰知是官府，煙縷滿鑪沈。"]'),
('e7d4aca2-85f0-43af-addd-88372e695c7a','會噲岑山人','王周','唐','唐诗','tang','','[]','渝州江上忽相逢，說隱西山最上峰。',32,'全唐诗/poet.tang.42000.json','["渝州江上忽相逢，說隱西山最上峰。", "略坐移時又分別，片雲孤鶴一枝筇。"]'),
('92b8618c-a6fb-4a9e-86f3-5325206046b3','巴江','王周','唐','唐诗','tang','','[]','巴江江水色，一帶濃藍碧。',24,'全唐诗/poet.tang.42000.json','["巴江江水色，一帶濃藍碧。", "仙女瑟瑟衣，風梭晚來織。"]'),
('45d7f1a7-1852-4c68-880a-45c0db5c68ad','小園桃李始花偶以成詠','王周','唐','唐诗','tang','','[]','桃李栽成豔格新，數枝留得小園春。',32,'全唐诗/poet.tang.42000.json','["桃李栽成豔格新，數枝留得小園春。", "半紅半白無風雨，隨分夭容解笑人。"]'),
('f156b7cb-fdd1-4c46-97f5-b69ae429d901','公居','王周','唐','唐诗','tang','','[]','公居門館靜，旅寄萬州城。',48,'全唐诗/poet.tang.42000.json','["公居門館靜，旅寄萬州城。", "山共秋煙紫，霜幷夜月清。", "無愁干酒律，有句入詩評。", "何必須林下，方馳吏隱名。"]'),
('945f9cb4-87f4-47ea-a420-143c24be16b2','富池口','王周','唐','唐诗','tang','','[]','扁舟閑引望，望極更盤桓。',48,'全唐诗/poet.tang.42000.json','["扁舟閑引望，望極更盤桓。", "山密礙江曲，雨多饒地寒。", "短莎煙苒苒，驚浪雪漫漫。", "難寫愁何限，鄉關在一端。"]'),
('d09b6ee3-1732-42ad-a6ff-b743b7e5d324','夔州病中','王周','唐','唐诗','tang','','[]','隱几經旬疾未痊，孤燈孤驛若爲眠。',32,'全唐诗/poet.tang.42000.json','["隱几經旬疾未痊，孤燈孤驛若爲眠。", "郡樓昨夜西風急，一一更籌到枕前。"]'),
('c9ccc4d9-5b01-4c63-8176-865b9002617a','題廳壁','王周','唐','唐诗','tang','','[]','永日無他念，孤清吏隱心。',48,'全唐诗/poet.tang.42000.json','["永日無他念，孤清吏隱心。", "竹聲幷雪碎，溪色共煙深。", "數息閑凭几，緣情默寄琴。", "誰知同寂寞，相與結知音。"]'),
('04c489ed-8305-4fd7-b7f4-cd58853c41fa','過武寧縣','王周','唐','唐诗','tang','','[]','行過武寧縣，初晴物景和。',48,'全唐诗/poet.tang.42000.json','["行過武寧縣，初晴物景和。", "岸回驚水急，山淺見天多。", "細草濃藍潑，輕煙匹練拖。", "晚來何處宿，一笛起漁歌。"]'),
('9551e6ce-9f46-4162-8d67-602b5eec2e27','路次覆盆驛','王周','唐','唐诗','tang','','[]','曾上青泥蜀道難，架空成路入雲寒。',32,'全唐诗/poet.tang.42000.json','["曾上青泥蜀道難，架空成路入雲寒。", "如何却向巴東去，三十六盤天外盤。"]'),
('57cab9d3-0ccb-4f50-9d20-d18142571cae','藕池阻風寄同行撫牧裘駕','王周','唐','唐诗','tang','','[]','船檣相望荆江中，岸蘆汀樹煙濛濛。',32,'全唐诗/poet.tang.42000.json','["船檣相望荆江中，岸蘆汀樹煙濛濛。", "路聞隄缺水如箭，未知何日生南風。"]'),
('efe5901e-d44e-4622-a101-e05d9993ed72','無題二首 一','王周','唐','唐诗','tang','','[]','冰雪肌膚力不勝，落花飛絮遶風亭。',32,'全唐诗/poet.tang.42000.json','["冰雪肌膚力不勝，落花飛絮遶風亭。", "不知何事鞦韆下，蹙破愁眉兩點青。"]'),
('85fedb0b-a224-4ece-ba5b-7acbc7153e65','無題二首 二','王周','唐','唐诗','tang','','[]','梨花如雪已相迷，更被驚烏半夜啼。',32,'全唐诗/poet.tang.42000.json','["梨花如雪已相迷，更被驚烏半夜啼。", "簾捲玉樓人寂寂，一鉤新月未沈西。"]'),
('8d5159c8-0294-4685-85b2-2c09c0289b0a','泊巴東','王周','唐','唐诗','tang','','[]','偶泊巴東古縣前，宦情鄉思兩綿綿。',32,'全唐诗/poet.tang.42000.json','["偶泊巴東古縣前，宦情鄉思兩綿綿。", "不堪蠟炬燒殘淚，雨打船窗半夜天。"]'),
('e3a0eee6-4f26-4c13-bfab-33d55f7c837e','道中未開木杏花','王周','唐','唐诗','tang','','[]','粉英香萼一般般，無限行人立馬看。',32,'全唐诗/poet.tang.42000.json','["粉英香萼一般般，無限行人立馬看。", "村女浴蠶桑柘綠，枉將顏色忍春寒。"]'),
('1f4c9152-51b1-4351-bc6f-c4f975b17c1a','西山晚景','王周','唐','唐诗','tang','','[]','公局長清淡，池亭晚景中。',48,'全唐诗/poet.tang.42000.json','["公局長清淡，池亭晚景中。", "蔗竿閑倚碧，蓮朵靜淹紅。", "半引彎彎月，微生飋飋風。", "無思復無慮，此味幾人同。"]'),
('95ddac5f-5d57-441e-9f83-8d37a19a02d4','自和','王周','唐','唐诗','tang','','[]','一片殘陽景，朦朧淡月中。',48,'全唐诗/poet.tang.42000.json','["一片殘陽景，朦朧淡月中。", "蘭芽紆嫩紫，棃頰抹生紅。", "琴阮資清格，冠簪養素風。", "煙霄半知足，吏隱少相同。"]'),
('ffd8fd96-8fa5-4475-b157-06ae7d4966b6','齒落詞','王周','唐','唐诗','tang','','[]','己卯至庚辰，仲夏晦之暮。',144,'全唐诗/poet.tang.42000.json','["己卯至庚辰，仲夏晦之暮。", "吾齒右排上，一齒脫而去。", "呼吸缺吾防，咀嚼欠吾助。", "年籥惜不返，日馭走爲蠹。", "脣亡得無寒，舌在從何訴。", "輔車宜長依，髮膚可增懼。", "不須考前古，聊且爲近喻。", "有如雲中雨，雨散絕回顧。", "有如枝上葉，葉脫難再附。", "白髮非獨愁，紅顏豈私駐。", "何必鬱九回，何必牽百慮。", "開尊復開懷，引筆作長句。"]'),
('799ce138-8f5d-4bca-a8c1-288e9697e671','淘金磧','王周','唐','唐诗','tang','','[]','畫船晚過淘金磧，不見黃金惟見石。',32,'全唐诗/poet.tang.42000.json','["畫船晚過淘金磧，不見黃金惟見石。", "猶恐黃金價未高，見得錙銖幾多力。"]'),
('b9ba9138-357c-4a50-9204-83f39bd2c02c','施南路偶書','王周','唐','唐诗','tang','','[]','大石嶺南梅欲發，南陵陂上雪初飛。',32,'全唐诗/poet.tang.42000.json','["大石嶺南梅欲發，南陵陂上雪初飛。", "苦無酒解愁成陣，又附蘭橈向秭歸。"]'),
('d8da991e-92a4-4214-a98e-dbcf7d4df447','大石嶺驛梅花','王周','唐','唐诗','tang','','[]','仙中姑射接瑤姬，成陣清香擁路岐。',32,'全唐诗/poet.tang.42000.json','["仙中姑射接瑤姬，成陣清香擁路岐。", "半出驛牆誰畫得，雪英相倚兩三枝。"]'),
('70c3591f-3d13-4637-970f-53f0a355dd6b','贈怤師','王周','唐','唐诗','tang','','[]','水中有片月，照耀嬋娟姿。',108,'全唐诗/poet.tang.42000.json','["水中有片月，照耀嬋娟姿。", "庭前有孤栢，竦秀歲寒期。", "堅然物莫遷，寂焉心爲師。", "聲發響必荅，形存影即隨。", "雪花安結子，雪葉寧附枝。", "蘭死不改香，井寒豈生澌。", "晨鑪煙褭褭，病髮霜絲絲。", "丈室冰凜冽，一衲雲離披。", "顧此名利場，得不慙冠綏。"]'),
('dd4278d8-f0ec-45e5-89e8-accdbba225fa','遊仙都觀','王周','唐','唐诗','tang','','[]','冷杉枯栢路盤空，毛髮生寒略略風。',32,'全唐诗/poet.tang.42000.json','["冷杉枯栢路盤空，毛髮生寒略略風。", "兩漢真仙在何處，巡香行遶蘂珠宮。"]'),
('d7b08427-a4b6-48c9-9d30-18b5b18405ee','誌峽船具詩 梢','王周','唐','唐诗','tang','','[]','制之居首尾，俾之辨斜正。',108,'全唐诗/poet.tang.42000.json','["制之居首尾，俾之辨斜正。", "首動尾聿隨，斜取正爲定。", "有如提吏筆，有如執時柄。", "有如秉師律，有如宣命令。", "守彼方與直，得其剛且勁。", "既能濟險難，何畏涉遼敻。", "招招俾作主，汎汎實司命。", "風烏愧斟酌，畫鷁空輝映。", "古人存豐規，猗歟聊引證。"]'),
('c7c0a73c-17c9-4a0c-8315-d8e2c5830393','誌峽船具詩 艣','王周','唐','唐诗','tang','','[]','用之大曰艫，冠乎小者楫。',60,'全唐诗/poet.tang.42000.json','["用之大曰艫，冠乎小者楫。", "通津既能濟，巨浸即橫涉。", "身之使者頰，虎之拏者爪。", "魚之撥者鬣，弩之進者筴。", "此實爲相須，相須航一葉。"]'),
('e53f4491-47b8-4cb8-8ff5-31c85a0a6946','誌峽船具詩 戙','王周','唐','唐诗','tang','','[]','箭飛峽中水，鋸立峽中石。',132,'全唐诗/poet.tang.42000.json','["箭飛峽中水，鋸立峽中石。", "峽與水爲隘，水與石相擊。", "濆爲生險艱，聲發甚霹靂。", "三老航一葉，百丈空千尺。", "蒼黃徒爾爲，倏忽何可測。", "篙之小難制，戙之獨有力。", "猗嗟戙之爲，彬彬堅且直。", "有如用武人，森森矗戈戟。", "有如敢言士，落落吐胸臆。", "拯危居坦夷，濟險免兢惕。", "誌彼哲匠心，俾其來者識。"]'),
('176ca419-0dac-4f58-ba00-de6345b91e88','誌峽船具詩 百丈','王周','唐','唐诗','tang','','[]','少嘗侍先君，餘閑誦白氏。',168,'全唐诗/poet.tang.42000.json','["少嘗侍先君，餘閑誦白氏。", "始得入峽詩，深味作詩旨。", "云有萬仞山，云有千丈水。", "自念坎壈時，尤多兢慎理。", "山束峽如口，水漱石如齒。", "孤舟行其中，薄冰猶坦履。", "孱顏屹焉立，洶湧勃然起。", "百丈爲前牽，萬險即平砥。", "破之以篔簹，續之以麻枲。", "礪之堅以節，引之直如矢。", "杼軸連半空，長短隨兩涘。", "鐵鎖枉馳名，錦纜謾稱美。", "長繩豈能繫，朽索何足擬。", "苟非𦁤之爲，胡可力行此。"]'),
('fccb9aa6-0d69-44af-897d-97965138d613','早春西園','王周','唐','唐诗','tang','','[]','引步攜筇竹，西園小徑通。',48,'全唐诗/poet.tang.42000.json','["引步攜筇竹，西園小徑通。", "雪欹梅蔕綠，春入杏梢紅。", "靜意崖穿溜，孤愁笛破空。", "如何將此景，收拾向圖中。"]'),
('3a3fcccb-46f3-41f8-be2d-db176311f5a7','金盤草詩','王周','唐','唐诗','tang','','[]','今春從南陵，得草名金盤。',180,'全唐诗/poet.tang.42000.json','["今春從南陵，得草名金盤。", "金盤有仁性，生在林一端。", "根節歲一節，食之甘而酸。", "風俗競採掇，俾人防急難。", "巴中虵虺毒，解之如走丸。", "巨葉展六出，軟幹分長竿。", "搖搖綠玉活，褭褭香荷寒。", "世云暑酷月，鬱有神物看。", "天之產於此，意欲生民安。", "今之爲政者，何不反此觀。", "知彼苛且猛，慎勿虐而殘。", "一物苟失所，萬金惟可歎。", "莫並蒿與萊，豈羨芝及蘭。", "勤渠護根本，栽植當庭欄。", "寄言好生者，休說神仙丹。"]'),
('972d5f94-468b-428c-9a94-610f5c3777c5','和程刑部三首 公會亭','王周','唐','唐诗','tang','','[]','公事公言地，標名姓必臧。',48,'全唐诗/poet.tang.42000.json','["公事公言地，標名姓必臧。", "江山如得助，談笑若爲妨。", "均賦鄉原肅，詳刑郡邑康。", "官箴居座右，夙夜算難忘。"]'),
('b777d7c1-474f-4f60-bff2-4061159aa0c5','和程刑部三首 碧鮮亭','王周','唐','唐诗','tang','','[]','飋飋籠清籟，蕭蕭鏁翠陰。',48,'全唐诗/poet.tang.42000.json','["飋飋籠清籟，蕭蕭鏁翠陰。", "向高思盡節，從直美虛心。", "迥砌滋蒼蘚，幽窗伴素琴。", "公餘時引步，一徑靜中深。"]'),
('3acda17e-2d18-4c03-8e25-34c6ef7bcd7b','和程刑部三首 清漣閤','王周','唐','唐诗','tang','','[]','照影翻窗綺，層紋滉額波。',48,'全唐诗/poet.tang.42000.json','["照影翻窗綺，層紋滉額波。", "絲青迷岸柳，茸綠蘸汀莎。", "片雪翹飢鷺，孤香卷嫩荷。", "憑欄堪入畫，時聽竹枝歌。"]'),
('f12f0006-8935-43bc-9873-29cacf1d4c40','自喻','王周','唐','唐诗','tang','','[]','予念天之生，生本空疎器。',264,'全唐诗/poet.tang.42000.json','["予念天之生，生本空疎器。", "五歲稟慈訓，憤悱讀書志。", "七歲辨聲律，勤苦會詩賦。", "九歲執公卷，倜儻干名意。", "乞薦鄉老書，幸會春官試。", "折桂愧巍峩，依蓮何氣味。", "性拙絕不佞，才短無餘地。", "前年會知己，薦章實非據。", "寧見民說平，空荷君恩寄。", "瞿唐抵巴渝，往來名攬轡。", "孤舟一水中，艱險實可畏。", "羣操百丈牽，臨難無苟避。", "濆向江底發，水在石中沸。", "槌鼓稱打寬，繫紉呼下緯。", "善惡胡可分，死生何足諱。", "騎衡與垂堂，非不知前喻。", "臨淵與履冰，非不知深慮。", "我今縻搢紳，善地誰人致。", "城孤與社鼠，巧佞誰從庇。", "奴顏與婢膝，醜直誰從媚。", "妻兒敻限越，容顏幾憔悴。", "致身霄漢人，呝嚱盡賢智。"]'),
('c3e0edb2-364d-4305-ab53-e03cf18570dc','巫山廟','王周','唐','唐诗','tang','','[]','廟前溪水流潺潺，廟中修竹聲珊珊。',32,'全唐诗/poet.tang.42000.json','["廟前溪水流潺潺，廟中修竹聲珊珊。", "襄王一夢杳難問，晚晴天氣歸雲閑。"]'),
('45970138-c1e8-4810-815f-1bfae5bc8f7f','下瞿塘寄時同年','王周','唐','唐诗','tang','','[]','春寒天氣下瞿塘，大壤溪前柳線長。',32,'全唐诗/poet.tang.42000.json','["春寒天氣下瞿塘，大壤溪前柳線長。", "須信孤雲是孤宦，莫將鄉思附歸艎。"]'),
('19eac081-6e47-40d2-8349-7836f83ae843','和杜運使巴峽地暖節物與中土異黯然有感詩三首 一','王周','唐','唐诗','tang','','[]','隨柳參差破綠芽，此中依約欲飛花。',32,'全唐诗/poet.tang.42000.json','["隨柳參差破綠芽，此中依約欲飛花。", "春光是處傷離思，何況歸期未有涯。"]'),
('bcf3556a-26c9-42ae-a974-30001fdeb5b1','和杜運使巴峽地暖節物與中土異黯然有感詩三首 二','王周','唐','唐诗','tang','','[]','始看菊蘂開籬下，又見梅花寄嶺頭。',32,'全唐诗/poet.tang.42000.json','["始看菊蘂開籬下，又見梅花寄嶺頭。", "攬轡巴西官局冷，幾憑春酒沃鄉愁。"]'),
('afeaa38c-ca21-4596-b889-787a0a1c5e45','和杜運使巴峽地暖節物與中土異黯然有感詩三首 三','王周','唐','唐诗','tang','','[]','花品姚黃冠洛陽，巴中春早羨孤芳。',32,'全唐诗/poet.tang.42000.json','["花品姚黃冠洛陽，巴中春早羨孤芳。", "不知別有栽培力，流詠新詩與激昂。"]'),
('a205a516-bef3-4a90-9158-4a6380280ccf','施南太守以猨兒爲寄作詩答之','王周','唐','唐诗','tang','','[]','虞人初獲酉江西，長臂難將意馬齊。',32,'全唐诗/poet.tang.42000.json','["虞人初獲酉江西，長臂難將意馬齊。", "今日未啼頭已白，不堪深入白雲啼。"]'),
('5ed238c5-0d65-472b-8bdc-4eda7f3b588b','巫廟','王周','唐','唐诗','tang','','[]','巴水走若箭，峽山開如屏。',182,'全唐诗/poet.tang.42000.json','["巴水走若箭，峽山開如屏。", "洶湧匹練白，𡷾崒濃藍青。", "崖空蓄雲雨，灘惡驚雷霆。", "神仙宅幽邃，廟貌橫杳冥。", "隱約可一夢，縹緲餘千齡。", "名利有所役，舟楫無暫停。", "悉宰垂[肸]蠁，祠禱希安寧。", "鵶鵶爾何物，飛飛來廟庭。", "紛紛颺寥泬，遠近隨虛舲。", "鐵石礪觜爪，金碧輝光翎。", "翔集託陰險，鵮啄貪羶腥。", "日既恃威福，歲久爲精靈。", "依草與附木，誣詭殊不經。", "城狐與社鼠，瑣細何足聽。", "況乎人假人，心闊吞滄溟。"]'),
('20ffcf8c-a46f-48be-bdb5-31f4a2e66a45','貴遊','劉兼','唐','唐诗','tang','','[]','繡衣公子宴池塘，淑景融融萬卉芳。',64,'全唐诗/poet.tang.42000.json','["繡衣公子宴池塘，淑景融融萬卉芳。", "珠翠照天春未老，管弦臨水日初長。", "風飄柳線金成穗，雨洗梨花玉有香。", "醉後不能離綺席，擬憑青帝繫斜陽。"]'),
('89a5aa76-391b-4cd6-b95d-465cf9570e73','夢歸故園 一','劉兼','唐','唐诗','tang','','[]','桐葉飛霜落井欄，菱花藏雪助衰顏。',64,'全唐诗/poet.tang.42000.json','["桐葉飛霜落井欄，菱花藏雪助衰顏。", "夜窗颯颯搖寒竹，秋枕迢迢夢故山。", "臨水釣舟橫荻岸，隔溪禪侶啓柴關。", "覺來依舊三更月，離緒鄉心起萬端。"]'),
('ad36f629-19a6-409f-86e3-769bf641b698','夢歸故園 二','劉兼','唐','唐诗','tang','','[]','舊館秋寒夜夢長，水簾疎影入迴塘。',64,'全唐诗/poet.tang.42000.json','["舊館秋寒夜夢長，水簾疎影入迴塘。", "宦情率爾拖魚艇，客恨依然在燕梁。", "白鷺獨飄山面雪，紅蕖全謝鏡心香。", "起來不語無人會，醉倚東軒半夕陽。"]'),
('cd2d5341-21a9-4a95-a4c2-9a9d8b14842b','蜀都春晚感懷','劉兼','唐','唐诗','tang','','[]','蜀都春色漸離披，夢斷雲空事莫追。',64,'全唐诗/poet.tang.42000.json','["蜀都春色漸離披，夢斷雲空事莫追。", "宮闕一城荒作草，王孫猶自醉如泥。", "誰家玉笛吹殘照，柳市金絲拂舊堤。", "可惜錦江無錦濯，海棠花下杜鵑啼。"]'),
('62426e88-a7e8-4862-b816-f26d6b7505c3','對雨','劉兼','唐','唐诗','tang','','[]','幽庭凝碧亦漣漪，簷霤聲繁聒夢歸。',64,'全唐诗/poet.tang.42000.json','["幽庭凝碧亦漣漪，簷霤聲繁聒夢歸。", "半岫金烏纔委照，一川石燕又交飛。", "濯枝霢霂榴花吐，吹渚飄颻暑氣微。", "因憶故園閑釣處，蒼苔斑駁滿漁磯。"]'),
('6382c01f-4a54-434f-a784-51228010162c','春霽','劉兼','唐','唐诗','tang','','[]','春霽江山似畫圖，醉垂鞭袂出康衢。',64,'全唐诗/poet.tang.42000.json','["春霽江山似畫圖，醉垂鞭袂出康衢。", "猖狂亂打貔貅鼓，懶慢遲修鴛鷺書。", "老色漸來欺鬢髮，閑晴將欲傲簪裾。", "苔錢遍地知多少，買得花枝不落無。"]'),
('755ee7db-5806-45b1-a48a-3fa1e39657e7','秋夕書懷 一','劉兼','唐','唐诗','tang','','[]','荒僻淹留歲已深，解龜無計恨難任。',64,'全唐诗/poet.tang.42000.json','["荒僻淹留歲已深，解龜無計恨難任。", "守方半會蠻夷語，賀廈全忘燕雀心。", "夜靜倚樓悲月笛，秋寒欹枕泣霜砧。", "宦情總逐愁腸斷，一筯鱸魚直萬金。"]'),
('429b2294-e37e-4414-bec8-7ec536cba78a','秋夕書懷 二','劉兼','唐','唐诗','tang','','[]','直氣從來不入時，掩關慵更釣磻溪。',64,'全唐诗/poet.tang.42000.json','["直氣從來不入時，掩關慵更釣磻溪。", "斯文未喪宣尼歎，吾道將窮阮籍悲。", "輕粉覆霜凝夜砌，亂金鋪菊織秋籬。", "南陽臥久無人問，薄命非才有可疑。"]'),
('c92574db-dd5b-45b2-a504-3fac65e0d6cb','春霄','劉兼','唐','唐诗','tang','','[]','春雲春日共朦朧，滿院梨花半夜風。',64,'全唐诗/poet.tang.42000.json','["春雲春日共朦朧，滿院梨花半夜風。", "宿酒未醒珠箔捲，豔歌初闋玉樓空。", "五湖范蠡才堪重，六印蘇秦道不同。", "再取素琴聊假寐，南柯靈夢莫相通。"]'),
('c553c8d1-3f42-41e4-8216-76df46dc4dff','秋夕書懷呈戎州郎中 一','劉兼','唐','唐诗','tang','','[]','素律初迴枕簟涼，松風飄泊入華堂。',64,'全唐诗/poet.tang.42000.json','["素律初迴枕簟涼，松風飄泊入華堂。", "譚雞寂默紗窗靜，夢蝶蕭條玉漏長。", "歸去水雲多阻隔，別來情緒足悲傷。", "霜砧月笛休相引，只有離襟淚兩行。"]'),
('70220e10-577b-431d-a51e-c928b1a88b08','秋夕書懷呈戎州郎中 二','劉兼','唐','唐诗','tang','','[]','風送秋荷滿鼻香，竹聲敲玉近虛廊。',64,'全唐诗/poet.tang.42000.json','["風送秋荷滿鼻香，竹聲敲玉近虛廊。", "夢迴故國情方黯，月過疎簾夜正涼。", "菱鏡也知移豔態，錦書其奈隔年光。", "鸞膠處處難尋覓，斷盡相思寸寸腸。"]'),
('d1f63af2-2b60-4ca1-bbb5-9c0d65cf44df','晚樓寓懷','劉兼','唐','唐诗','tang','','[]','薄暮疎林宿鳥還，倚樓垂袂復憑欄。',64,'全唐诗/poet.tang.42000.json','["薄暮疎林宿鳥還，倚樓垂袂復憑欄。", "月沈江底珠輪淨，雲鎖峰頭玉葉寒。", "劉毅暫貧雖壯志，馮唐將老自低顏。", "無言獨對秋風立，擬把朝簪換釣竿。"]'),
('01963000-36cb-4f71-ac7d-3575177a05bf','征婦怨','劉兼','唐','唐诗','tang','','[]','金閨寂寞罷妝臺，玉筯闌干界粉腮。',64,'全唐诗/poet.tang.42000.json','["金閨寂寞罷妝臺，玉筯闌干界粉腮。", "花落掩關春欲暮，月圓欹枕夢初迴。", "鸞膠豈續愁腸斷，龍劒難揮別緒開。", "曾寄錦書無限意，塞鴻何事不歸來。"]'),
('77fc7fc0-1bee-44f7-8e26-7d1fe5f8b7a3','對鏡','劉兼','唐','唐诗','tang','','[]','青鏡重磨照白鬚，白鬚撚閑意何如。',64,'全唐诗/poet.tang.42000.json','["青鏡重磨照白鬚，白鬚撚閑意何如。", "故園迢遰千山外，荒郡淹留四載餘。", "風送竹聲侵枕簟，月移花影過庭除。", "秋霜滿領難消釋，莫讀離騷失意書。"]'),
('0767304f-1005-41ca-9d41-5595c932082a','春燕','劉兼','唐','唐诗','tang','','[]','多時窗外語呢喃，只要佳人捲繡簾。',64,'全唐诗/poet.tang.42000.json','["多時窗外語呢喃，只要佳人捲繡簾。", "大廈已成須慶賀，高門頻入莫憎嫌。", "花間舞蝶和香趁，江畔春泥帶雨銜。", "栖息數年情已厚，營巢爭肯傍他簷。"]'),
('afbe626e-344a-4905-b911-cbfa5155a4b7','春晚寓懷','劉兼','唐','唐诗','tang','','[]','一承兌澤蒞方州，八度春光照郡樓。',64,'全唐诗/poet.tang.42000.json','["一承兌澤蒞方州，八度春光照郡樓。", "好景幾將官吏醉，名山時領管弦遊。", "空花任爾頻侵眼，老雪從他漸滿頭。", "歸去杜陵池閣在，只能歡笑不能愁。"]'),
('8acdfdd7-03f4-49a5-99d5-cda2e34ea30e','中春宴遊','劉兼','唐','唐诗','tang','','[]','二月風光似洞天，紅英翠萼簇芳筵。',64,'全唐诗/poet.tang.42000.json','["二月風光似洞天，紅英翠萼簇芳筵。", "楚王雲雨迷巫峽，江令文章媚蜀箋。", "歌黛入顰春袖斂，舞衣新繡曉霞鮮。", "酒闌香袂初分散，笑指漁翁釣暮煙。"]'),
('c4d93918-3bf9-44ab-adfe-3a27ef6cf590','春晚閑望','劉兼','唐','唐诗','tang','','[]','東風滿地是梨花，只把琴心殢酒家。',64,'全唐诗/poet.tang.42000.json','["東風滿地是梨花，只把琴心殢酒家。", "立處晚樓橫短笛，望中春草接平沙。", "雁行斷續晴天遠，燕翼參差翠幕斜。", "歸計未成頭欲白，釣舟煙浪思無涯。"]'),
('368889f8-4a3d-46c4-8338-b98a706f5135','秋夕書事','劉兼','唐','唐诗','tang','','[]','搖落江天萬木空，雁行斜戛塞垣風。',64,'全唐诗/poet.tang.42000.json','["搖落江天萬木空，雁行斜戛塞垣風。", "征閨擣月離愁遠，舊館眠雲旅夢通。", "郢客豈能陪下里，臯禽爭肯戀樊籠。", "此心曠蕩誰相會，盡在南華十卷中。"]'),
('25d4c636-a730-4f2c-84f2-447f883472f2','蓮塘霽望','劉兼','唐','唐诗','tang','','[]','新秋菡萏發紅英，向晚風飄滿郡馨。',64,'全唐诗/poet.tang.42000.json','["新秋菡萏發紅英，向晚風飄滿郡馨。", "萬疊水紋羅乍展，一雙鸂鶒繡初成。", "採蓮女散吳歌闋，拾翠人歸楚雨晴。", "遠岸牧童吹短笛，蓼花深處信牛行。"]'),
('cb6f0957-d7a5-41c0-8c49-78c4f4bc5a9a','送從弟舍人入蜀','劉兼','唐','唐诗','tang','','[]','嘉陵江畔餞行車，離袂難分十里餘。',64,'全唐诗/poet.tang.42000.json','["嘉陵江畔餞行車，離袂難分十里餘。", "慷慨莫誇心似鐵，留連不覺淚成珠。", "風光川谷梅將發，音信雲天雁未疎。", "立馬舉鞭無限意，會稀別遠擬何如。"]'),
('b5806765-f2d8-4d0f-9018-d0fbcb4365c4','新迴車院筵上作','劉兼','唐','唐诗','tang','','[]','迴車院子未迴車，三載疲民詠袴襦。',64,'全唐诗/poet.tang.42000.json','["迴車院子未迴車，三載疲民詠袴襦。", "借寇已承英主詔，乞骸須上老臣書。", "黃金蜀柳籠朱戶，碧玉湘筠映綺疏。", "因問滿筵詩酒客，錦江何處有鱸魚。"]'),
('5e6129cb-80f6-41dc-bc66-a502da4836d3','寄長安鄭員外','劉兼','唐','唐诗','tang','','[]','屈指良交十四人，隙駒風燭漸爲塵。',64,'全唐诗/poet.tang.42000.json','["屈指良交十四人，隙駒風燭漸爲塵。", "當初花下三秦客，只有天涯二老身。", "乘醉幾同遊北內，尋芳多共謁東隣。", "此時阻隔關山遠，月滿江樓淚滿巾。"]'),
('0047d363-0c3d-4fab-93d6-d6ba5b620520','咸陽懷古','劉兼','唐','唐诗','tang','','[]','高秋咸鎬起霜風，秦漢荒陵樹葉紅。',64,'全唐诗/poet.tang.42000.json','["高秋咸鎬起霜風，秦漢荒陵樹葉紅。", "七國鬬雞方賈勇，中原逐鹿更爭雄。", "南山漠漠雲常在，渭水悠悠事旋空。", "立馬舉鞭遙望處，阿房遺址夕陽東。"]'),
('9f280384-5f44-4bf9-b190-feb0f531d13a','春怨','劉兼','唐','唐诗','tang','','[]','繡林紅岸落花鈿，故去新來感自然。',64,'全唐诗/poet.tang.42000.json','["繡林紅岸落花鈿，故去新來感自然。", "絕塞杪春悲漢月，長林深夜泣緗弦。", "錦書雁斷應難寄，菱鏡鸞孤貌可憐。", "獨倚畫屏人不會，夢魂纔別戍樓邊。"]'),
('c4af037f-38fb-4694-9c7a-4d5fccf92373','登樓寓望','劉兼','唐','唐诗','tang','','[]','憑高多是偶汍瀾，紅葉何堪照病顏。',64,'全唐诗/poet.tang.42000.json','["憑高多是偶汍瀾，紅葉何堪照病顏。", "萬疊雲山供遠恨，一軒風物送秋寒。", "背琴鶴客歸松徑，橫笛牛童臥蓼灘。", "獨倚郡樓無限意，夕陽西去水東還。"]'),
('515d8d6a-f7e2-48de-8d13-7830c6293d08','江岸獨步','劉兼','唐','唐诗','tang','','[]','醉卓寒筇傍水行，漁翁不會獨吟情。',64,'全唐诗/poet.tang.42000.json','["醉卓寒筇傍水行，漁翁不會獨吟情。", "龜能顧印誰相重，鶴偶乘軒自可輕。", "簪組百年終長物，文章千古亦虛名。", "是非得喪皆閑事，休向南柯與夢爭。"]'),
('3ab46fa7-c66d-4e23-84d1-741f41f0249b','江樓望鄉寄內','劉兼','唐','唐诗','tang','','[]','獨上江樓望故鄉，淚襟霜笛共淒涼。',64,'全唐诗/poet.tang.42000.json','["獨上江樓望故鄉，淚襟霜笛共淒涼。", "雲生隴首秋雖早，月在天心夜已長。", "魂夢只能隨蛺蝶，煙波無計學鴛鴦。", "蜀箋都有三千幅，總寫離情寄孟光。"]'),
('9d233c37-a81d-4d35-ad20-f2e9bb389f55','命妓不至','劉兼','唐','唐诗','tang','','[]','琴中難挑孰憐才，獨對良宵酒數杯。',64,'全唐诗/poet.tang.42000.json','["琴中難挑孰憐才，獨對良宵酒數杯。", "蘇子黑貂將已盡，宋弘青鳥又空回。", "月穿淨牖霜成隙，風捲殘花錦作堆。", "欹枕夢魂何處去，醉和春色入天台。"]'),
('61dd57c4-9c30-4bdc-b52e-0c492483fc17','宣賜錦袍設上贈諸郡客','劉兼','唐','唐诗','tang','','[]','十月芙蓉花滿枝，天庭驛騎賜寒衣。',64,'全唐诗/poet.tang.42000.json','["十月芙蓉花滿枝，天庭驛騎賜寒衣。", "將同玉蝶侵肌冷，也遣金鵬遍體飛。", "夜臥始知多忝竊，晝行方覺轉光輝。", "深冬若得朝丹闕，太華峰前衣錦歸。"]'),
('010044dc-55d1-4a60-97bf-18ed5cb30b4c','晨雞','劉兼','唐','唐诗','tang','','[]','朱冠金距綵毛身，昧爽高聲已報晨。',64,'全唐诗/poet.tang.42000.json','["朱冠金距綵毛身，昧爽高聲已報晨。", "作瑞莫慚先貢楚，擅塲須信獨推秦。", "淮南也伴升仙犬，函谷曾容借曉人。", "此日卑棲隨飲啄，宰君驅我亦相馴。"]'),
('c28cd125-b380-4c40-90f2-a493f9c2fcd0','芳春','劉兼','唐','唐诗','tang','','[]','微雨微風隔晝簾，金爐檀炷冷慵添。',64,'全唐诗/poet.tang.42000.json','["微雨微風隔晝簾，金爐檀炷冷慵添。", "桃花滿地春牢落，柳絮成堆雪棄嫌。", "寶瑟不能邀卓氏，綵毫何必夢江淹。", "宦情歸興休相撓，隼斾漁舟總未厭。"]'),
('298c5bbf-a1ca-428c-a16c-63bdb0ce55e2','春遊 一','劉兼','唐','唐诗','tang','','[]','柳成金穗草如茵，載酒尋花共賞春。',32,'全唐诗/poet.tang.42000.json','["柳成金穗草如茵，載酒尋花共賞春。", "先入醉鄉君莫問，十年風景在三秦。"]'),
('b70702ea-7ddc-4528-831e-db9557ab2a19','春遊 二','劉兼','唐','唐诗','tang','','[]','搖搖離緒不能持，滿郡花開酒熟時。',64,'全唐诗/poet.tang.42000.json','["搖搖離緒不能持，滿郡花開酒熟時。", "羞聽黃鶯求善友，強隨綠柳展愁眉。", "隔雲故國山千疊，傍水芳林錦萬枝。", "聖主未容歸北闕，且將勤儉撫南夷。"]'),
('24fad807-9684-49b6-a9ce-27286797769a','重陽感懷 一','劉兼','唐','唐诗','tang','','[]','重陽不忍上高樓，寒菊年年照暮秋。',64,'全唐诗/poet.tang.42000.json','["重陽不忍上高樓，寒菊年年照暮秋。", "萬疊故山雲總隔，兩行鄉淚血和流。", "黃茅莽莽連邊郡，紅葉紛紛落釣舟。", "歸計未成年漸老，茱萸羞戴雪霜頭。"]'),
('b40e68fd-ecb8-40e4-8c1e-540d08eae0a3','重陽感懷 二','劉兼','唐','唐诗','tang','','[]','載花乘酒上高山，四望秋空八極寬。',64,'全唐诗/poet.tang.42000.json','["載花乘酒上高山，四望秋空八極寬。", "蜀國江山存不得，劉家豚犬取何難。", "張儀舊壁蒼苔厚，葛亮荒祠古木寒。", "獨對斜陽更惆悵，錦江東注似波瀾。"]'),
('85ed1d97-7497-4ffd-a8f4-c4c49a7b8e2b','宴遊池館','劉兼','唐','唐诗','tang','','[]','綺筵金碧照芳菲，酒滿瑤巵水滿池。',64,'全唐诗/poet.tang.42000.json','["綺筵金碧照芳菲，酒滿瑤巵水滿池。", "去歲南岐離郡日，今春東蜀看花時。", "儉蓮發臉當籌著，緒柳生腰按柘枝。", "座客半酣言笑狎，孔融懷抱正怡怡。"]'),
('e67f0948-dbd2-449f-82b8-39dcab768551','寄高書記','劉兼','唐','唐诗','tang','','[]','齊朝慶裔祖敖曹，麟角無雙鳳九毛。',64,'全唐诗/poet.tang.42000.json','["齊朝慶裔祖敖曹，麟角無雙鳳九毛。", "聲價五侯爭辟命，文章一代振風騷。", "醉琴自寄陶家意，夢枕誰聽益郡刀。", "補衮應星曾奏舉，北山南海孰爲高。"]'),
('8885d398-bbd9-4de2-b527-33ea4345382a','再見從弟舍人','劉兼','唐','唐诗','tang','','[]','屈指依稀十五年，鸞臺秘閣位相懸。',64,'全唐诗/poet.tang.42000.json','["屈指依稀十五年，鸞臺秘閣位相懸。", "分飛淮甸雁行斷，重見江樓蟾影圓。", "滯跡未偕朝北闕，高才方命入西川。", "願君通理須還早，拜慶慈親几杖前。"]'),
('f1e80b3f-36ee-4843-b3e6-fe0e6f01a704','春晝醉眠','劉兼','唐','唐诗','tang','','[]','朱欄芳草綠纖纖，欹枕高堂捲晝簾。',64,'全唐诗/poet.tang.42000.json','["朱欄芳草綠纖纖，欹枕高堂捲晝簾。", "處處落花春寂寂，時時中酒病懨懨。", "塞鴻信斷雖堪訝，梁燕詞多且莫嫌。", "自有卷書銷永日，霜華未用鬢邊添。"]'),
('5d191843-cb7d-4d85-af7f-a0f55e19915e','中夏晝臥','劉兼','唐','唐诗','tang','','[]','寂寂無聊九夏中，傍簷依壁待清風。',32,'全唐诗/poet.tang.42000.json','["寂寂無聊九夏中，傍簷依壁待清風。", "壯圖奇策無人問，不及南陽一臥龍。"]'),
('35155334-7e02-4412-8907-5015a699b8af','春夕寓興','劉兼','唐','唐诗','tang','','[]','忘憂何必在庭萱，是事悠悠竟可寬。',64,'全唐诗/poet.tang.42000.json','["忘憂何必在庭萱，是事悠悠竟可寬。", "酒病未能辭錦里，春狂又擬入桃源。", "風吹楊柳絲千縷，月照梨花雪萬團。", "閑泥金徽度芳夕，幽泉石上自潺湲。"]'),
('0913f0e1-00e7-451b-8ef1-896f463d4237','春夜','劉兼','唐','唐诗','tang','','[]','薄薄春雲籠皓月，杏花滿地堆香雪。',32,'全唐诗/poet.tang.42000.json','["薄薄春雲籠皓月，杏花滿地堆香雪。", "醉垂羅袂倚朱欄，小數玉仙歌未闋。"]'),
('be1e0b44-8cc6-47b3-8357-b05d07cd912c','訪飲妓不遇招酒徒不至','劉兼','唐','唐诗','tang','','[]','小橋流水接平沙，何處行雲不在家。',64,'全唐诗/poet.tang.42000.json','["小橋流水接平沙，何處行雲不在家。", "畢卓未來輕竹葉，劉晨重到殢桃花。", "琴樽冷落春將盡，幃幌蕭條日又斜。", "回首却尋芳草路，金鞍拂柳思無涯。"]'),
('bc01ec28-7e26-4067-9733-c4de83956f9a','春宴河亭','劉兼','唐','唐诗','tang','','[]','柳擺輕絲拂嫩黃，檻前流水滿池塘。',64,'全唐诗/poet.tang.42000.json','["柳擺輕絲拂嫩黃，檻前流水滿池塘。", "一筵金翠臨芳岸，四面煙花出粉牆。", "舞袖逐風翻繡浪，歌塵隨燕下雕梁。", "蠻箋象管休凝思，且放春心入醉鄉。"]'),
('ab792d4d-0cf0-46c5-8a44-df20d5649242','蜀都道中','劉兼','唐','唐诗','tang','','[]','劒關雲棧亂崢嶸，得喪何由險與平。',64,'全唐诗/poet.tang.42000.json','["劒關雲棧亂崢嶸，得喪何由險與平。", "千載龜城終失守，一堆鬼錄漫留名。", "季年必不延昏主，薄賞那堪激懦兵。", "李特後來多二世，納降歸擬盡公卿。"]'),
('cda7e435-20d4-409f-9916-f4286a28d1cc','萬葛樹','劉兼','唐','唐诗','tang','','[]','葉如羽蓋豈堪論，百步清陰鎖綠雲。',64,'全唐诗/poet.tang.42000.json','["葉如羽蓋豈堪論，百步清陰鎖綠雲。", "善政已聞思召伯，英風偏稱號將軍。", "靜鋪講席麟經潤，高拂□枝兔影分。", "更有歲寒霜雪操，莫將樗櫟擬相羣。"]'),
('31e8a61c-63ad-4cdc-bd85-ec728a232b22','春夕遣懷','劉兼','唐','唐诗','tang','','[]','窮通分定莫淒涼，且放歡情入醉鄉。',64,'全唐诗/poet.tang.42000.json','["窮通分定莫淒涼，且放歡情入醉鄉。", "范蠡扁舟終去相，馮唐半世只爲郎。", "風飄玉笛梅初落，酒汎金樽月未央。", "休把虛名撓懷抱，九原丘隴盡侯王。"]'),
('64b78742-4d1c-447d-9816-d05eac921a2c','西齋','劉兼','唐','唐诗','tang','','[]','西齋新竹兩三莖，也有風敲碎玉聲。',32,'全唐诗/poet.tang.42000.json','["西齋新竹兩三莖，也有風敲碎玉聲。", "莫恨移來欄檻遠，譬如元本此間生。"]'),
('5df7a1a7-b5f6-4e68-917f-45d51ae6b368','新蟬','劉兼','唐','唐诗','tang','','[]','齊女屏幃失舊容，侍中冠冕有芳蹤。',64,'全唐诗/poet.tang.42000.json','["齊女屏幃失舊容，侍中冠冕有芳蹤。", "翅翻晚鬢尋香露，聲引秋絲逐遠風。", "旅館聽時髭欲白，戍樓聞處葉多紅。", "只知送恨添愁事，誰見凌霄羽蛻功。"]'),
('04272af5-beb9-40ec-83e6-821eea50bb7e','寄滑州文秀大師','劉兼','唐','唐诗','tang','','[]','分飛屈指十三年，菡萏峰前別社蓮。',64,'全唐诗/poet.tang.42000.json','["分飛屈指十三年，菡萏峰前別社蓮。", "薄宦偶然來左蜀，孤雲何事在南燕。", "一封瑤簡音初達，兩處金沙色共圓。", "珍重湯休惠佳句，郡齋吟久不成眠。"]'),
('50a97c7b-96bc-44c3-b080-e18c455e35d3','中春登樓 一','劉兼','唐','唐诗','tang','','[]','金杯不以滌愁腸，江郡芳時憶故鄉。',64,'全唐诗/poet.tang.42000.json','["金杯不以滌愁腸，江郡芳時憶故鄉。", "兩岸煙花春富貴，一樓風月夜淒涼。", "王章莫耻牛衣淚，潘岳休驚鶴鬢霜。", "歸去蓮花歸未得，白雲深處有茅堂。"]'),
('cb2d8f1c-82e9-4923-9661-4a628ad5aac5','中春登樓 二','劉兼','唐','唐诗','tang','','[]','古今通塞莫咨嗟，謾把霜髯敵歲華。',64,'全唐诗/poet.tang.42000.json','["古今通塞莫咨嗟，謾把霜髯敵歲華。", "失手已慙蛇有足，用心休爲鼠無牙。", "九天雲淨方憐月，一夜風高便厭花。", "獨倚郡樓人不會，釣舟春浪接平沙。"]'),
('33d5f4a2-cc60-46c5-9ad4-af2070cf25b7','自遣','劉兼','唐','唐诗','tang','','[]','未上亨衢獨醉吟，賦成無處博黃金。',64,'全唐诗/poet.tang.42000.json','["未上亨衢獨醉吟，賦成無處博黃金。", "家人莫問張儀舌，國士須知豫讓心。", "照乘始堪沽善價，陽春爭忍混凡音。", "鵾鵬鱗翼途程在，九萬風雲海浪深。"]'),
('b785ca86-72a6-455b-b8f5-2d9dcfedf411','偶有下殤因而自遣','劉兼','唐','唐诗','tang','','[]','彭壽殤齡共兩空，幻泡緣影夢魂中。',64,'全唐诗/poet.tang.42000.json','["彭壽殤齡共兩空，幻泡緣影夢魂中。", "缺圓宿會長如月，飄忽浮生疾似風。", "修短百年先後定，賢愚千古是非同。", "南柯太守知人意，休問陶陶塞上翁。"]'),
('36b057ee-e776-4a4d-9f5f-9123f67dc8e8','倦學','劉兼','唐','唐诗','tang','','[]','樂廣亡來冰鏡稀，宓妃嫫母混妍媸。',64,'全唐诗/poet.tang.42000.json','["樂廣亡來冰鏡稀，宓妃嫫母混妍媸。", "且於霧裏藏玄豹，休向窗中問碧雞。", "百氏典墳空自苦，一堆螢雪竟誰知。", "門前春色芳如晝，好掩書齋任所之。"]'),
('2e5b2367-1ade-4758-a224-6d54b1342d30','去年今日','劉兼','唐','唐诗','tang','','[]','去年今日到榮州，五騎紅塵入郡樓。',64,'全唐诗/poet.tang.42000.json','["去年今日到榮州，五騎紅塵入郡樓。", "貔虎只知迎太守，蠻夷不信是儒流。", "姦豪已息時將泰，疲瘵全蘇歲又周。", "聖主若容辭重祿，便歸煙水狎羣鷗。"]'),
('2e4ba77c-a082-4525-af10-67108892ff89','晝寢','劉兼','唐','唐诗','tang','','[]','花落青苔錦數重，書淫不覺避春慵。',66,'全唐诗/poet.tang.42000.json','["花落青苔錦數重，書淫不覺避春慵。", "[恣]情枕上飛莊蝶，任爾雲間騁陸龍。", "玉液未能消氣魄，牙籤方可滌昏蒙。", "起來已被詩魔引，窗外寒敲翠竹風。"]'),
('c1eb9ccb-d9a5-4302-bb38-0cfd417aa945','郡齋寓興','劉兼','唐','唐诗','tang','','[]','依約樊川似旭川，郡齋風物盡蕭然。',64,'全唐诗/poet.tang.42000.json','["依約樊川似旭川，郡齋風物盡蕭然。", "秋庭碧蘚鋪雲錦，晚閣紅蕖簇水仙。", "醉筆語狂揮粉壁，歌梁塵亂拂花鈿。", "情懷放蕩無羈束，地角天涯亦信緣。"]'),
('79b9a822-7bf9-4d12-9754-255d5f0207bb','郡樓閑望書懷','劉兼','唐','唐诗','tang','','[]','郡城樓閣繞江濱，風物清秋入望頻。',64,'全唐诗/poet.tang.42000.json','["郡城樓閣繞江濱，風物清秋入望頻。", "銅鼓祭龍雲塞廟，蘆花飄市雪黏人。", "蓮披淨沼羣香散，鷺點寒煙玉片新。", "歸去杜陵池館在，且將朝服拂埃塵。"]'),
('7d6f2c0a-7d4d-4f45-b072-f8c800fb50cd','玉燭花','劉兼','唐','唐诗','tang','','[]','嫋嫋香英三四枝，亭亭紅豔照階墀。',64,'全唐诗/poet.tang.42000.json','["嫋嫋香英三四枝，亭亭紅豔照階墀。", "正當晚檻初開處，却似春闈就試時。", "少女不吹方熠爚，東君偏惜未離披。", "夜深斜倚朱欄外，擬把鄰光借與誰。"]'),
('450bba5d-674c-4954-88fe-e72cdb16922a','從弟舍人惠茶','劉兼','唐','唐诗','tang','','[]','曾求芳茗貢蕪詞，果沐頒霑味甚奇。',64,'全唐诗/poet.tang.42000.json','["曾求芳茗貢蕪詞，果沐頒霑味甚奇。", "龜背起紋輕炙處，雲頭翻液乍烹時。", "老丞倦悶偏宜矣，舊客過從別有之。", "珍重宗親相寄惠，水亭山閣自攜持。"]'),
('6cc081df-cbdb-4166-8a1c-1ba8ec2960d8','再看光福寺牡丹','劉兼','唐','唐诗','tang','','[]','去年曾看牡丹花，蛺蝶迎人傍彩霞。',64,'全唐诗/poet.tang.42000.json','["去年曾看牡丹花，蛺蝶迎人傍彩霞。", "今日再遊光福寺，春風吹我入仙家。", "當筵芬馥歌唇動，倚檻嬌羞醉眼斜。", "來歲未朝金闕去，依前和露載歸衙。"]'),
('607932b6-49ce-400a-8eab-29c22551a9af','海棠花','劉兼','唐','唐诗','tang','','[]','淡淡微紅色不深，依依偏得似春心。',64,'全唐诗/poet.tang.42000.json','["淡淡微紅色不深，依依偏得似春心。", "煙輕虢國顰歌黛，露重長門斂淚衿。", "低傍繡簾人易折，密藏香蘂蝶難尋。", "良宵更有多情處，月下芬芳伴醉吟。"]'),
('c5f18a35-a520-4e27-9a8a-bbb50590b6ad','新竹','劉兼','唐','唐诗','tang','','[]','近窗臥砌兩三叢，佐靜添幽別有功。',64,'全唐诗/poet.tang.42000.json','["近窗臥砌兩三叢，佐靜添幽別有功。", "影鏤碎金初透月，聲敲寒玉乍搖風。", "無憑費叟煙波碧，莫信湘妃淚點紅。", "自是子猷偏愛爾，虛心高節雪霜中。"]'),
('aa6377a0-bfc4-4271-bbf5-4d27cd90f5b7','木芙蓉','劉兼','唐','唐诗','tang','','[]','素靈失律詐風流，強把芳菲半載偷。',64,'全唐诗/poet.tang.42000.json','["素靈失律詐風流，強把芳菲半載偷。", "是葉葳蕤霜照夜，此花爛熳火燒秋。", "謝蓮色淡爭堪種，陶菊香穠亦合羞。", "誰道金風能肅物，因何厚薄不相侔。"]'),
('2abd0a39-8b8c-434a-a3e5-0a04b9b90fad','送二郎君歸長安','劉兼','唐','唐诗','tang','','[]','我兒辭去淚雙流，蜀郡秦川兩處愁。',64,'全唐诗/poet.tang.42000.json','["我兒辭去淚雙流，蜀郡秦川兩處愁。", "紅葉滿山歸故國，黃茅徧地住他州。", "荷衣曉挂慙官吏，菱鏡秋窺訝鬢髹。", "好向雲泉營舊隱，莫教莊叟畏犧牛。"]'),
('82fa6585-5e71-4eb2-a24f-4c77605e751c','送文英大師','劉兼','唐','唐诗','tang','','[]','屈指平陽別社蓮，蟾光一百度曾圓。',64,'全唐诗/poet.tang.42000.json','["屈指平陽別社蓮，蟾光一百度曾圓。", "孤雲自在知何處，薄宦參差亦信緣。", "山郡披風方穆若，花時分袂更淒然。", "搖鞭相送嘉陵岸，回首羣峰隔翠煙。"]'),
('8b6bf724-41ad-4811-950d-30c1fce368cd','酬勾評事','劉兼','唐','唐诗','tang','','[]','閑庭欹枕正悲秋，忽覺新編浣遠愁。',64,'全唐诗/poet.tang.42000.json','["閑庭欹枕正悲秋，忽覺新編浣遠愁。", "才薄只愁安雁戶，年高空憶復漁舟。", "鷺翹皓雪臨汀岸，蓮嫋紅香匝郡樓。", "對景却慙無藻思，南金荆玉卒難酬。"]'),
('c3488e53-0d1f-471a-89e6-c485fb5b06bb','初至郡界','劉兼','唐','唐诗','tang','','[]','嘉陵江畔接榮川，兩畔旌旗下瀨船。',64,'全唐诗/poet.tang.42000.json','["嘉陵江畔接榮川，兩畔旌旗下瀨船。", "郡印已分炎瘴地，朝衣猶惹御爐煙。", "蓮塘小飲香隨艇，月榭高吟水壓天。", "錦字莫嫌歸路遠，華夷一統太平年。"]'),
('195043de-c9e6-4c7b-98db-f367cc71b237','到郡後有寄','劉兼','唐','唐诗','tang','','[]','蜀路新修盡坦平，交親深幸再逢迎。',64,'全唐诗/poet.tang.42000.json','["蜀路新修盡坦平，交親深幸再逢迎。", "正當返袂思鄉國，却似歸家見弟兄。", "霑澤只慙堯綍重，泝流還喜范舟輕。", "欲將感戀裁書旨，多少漁箋寫得成。"]'),
('5f4ed997-c2b4-4ca8-8841-2ec44c9c870c','長春節','劉兼','唐','唐诗','tang','','[]','聖朝佳節遇長春，跪捧金爐祝又焚。',64,'全唐诗/poet.tang.42000.json','["聖朝佳節遇長春，跪捧金爐祝又焚。", "寶藏發來天地秀，兵戈銷後帝皇尊。", "太平基址千年永，混一車書萬古存。", "更有馨香滿芳檻，和風遲日在蘭蓀。"]'),
('77b23db4-167c-4cb4-a207-75f606b754e4','登郡樓書事','劉兼','唐','唐诗','tang','','[]','偶奉綸書蒞旭川，郡樓嘉致盡依然。',64,'全唐诗/poet.tang.42000.json','["偶奉綸書蒞旭川，郡樓嘉致盡依然。", "松欹鳥道雲藏寺，月滿漁舟水浸天。", "望帝古祠花簇簇，錦城歸路草芊芊。", "有時倚檻垂雙袂，故國風光似眼前。"]'),
('9148b4d9-2717-4123-b6b4-2244559a6220','旭川祁宰思家而卒因述意呈秦川知己','劉兼','唐','唐诗','tang','','[]','歲稔民康絕訟論，政成公暇自由身。',64,'全唐诗/poet.tang.42000.json','["歲稔民康絕訟論，政成公暇自由身。", "朝看五馬閑如社，夜擁雙姬煖似春。", "家計不憂憑冢子，官資無愧是朝臣。", "豈同齷齪祁員外，至死悲涼一婦人。"]'),
('f586c2fe-fee8-421e-bd73-71b94d555f54','登郡樓書懷 一','劉兼','唐','唐诗','tang','','[]','煙雨樓臺漸晦冥，錦江澄碧浪花平。',64,'全唐诗/poet.tang.42000.json','["煙雨樓臺漸晦冥，錦江澄碧浪花平。", "卞和未雪荆山耻，莊舃空傷越國情。", "天際寂寥無雁下，雲端依約有僧行。", "登高欲繼離騷詠，魂斷愁深寫不成。"]'),
('9f9783f6-7082-4c36-872f-0f04daa43a25','登郡樓書懷 二','劉兼','唐','唐诗','tang','','[]','邊郡荒涼悲且歌，故園迢遰隔煙波。',64,'全唐诗/poet.tang.42000.json','["邊郡荒涼悲且歌，故園迢遰隔煙波。", "琴聲背俗終如是，劍氣衝星又若何。", "朝客漸通書信少，釣舟頻引夢魂多。", "北山更有移文者，白首無塵歸去麽。"]'),
('90b11099-8cd4-46c7-b791-75e77b51bb9a','登郡樓書懷 三','劉兼','唐','唐诗','tang','','[]','莫嗔阮氏哭途窮，萬代深沈恨亦同。',64,'全唐诗/poet.tang.42000.json','["莫嗔阮氏哭途窮，萬代深沈恨亦同。", "瑞玉豈知將抵鵲，鉛刀何事却屠龍。", "九夷欲適嗟吾道，五柳終歸效古風。", "獨倚郡樓無限意，滿江煙雨正冥濛。"]'),
('5a913591-73bd-4bae-8ba1-24112dbedfa7','偶聞官吏舉請輒有一篇寄從弟舍人','劉兼','唐','唐诗','tang','','[]','官吏潛陳借寇詞，宦情鄉夢兩相違。',64,'全唐诗/poet.tang.42000.json','["官吏潛陳借寇詞，宦情鄉夢兩相違。", "青城錦水無心住，紫閣蓮峯有意歸。", "張翰鱸魚因醉憶，孟光書信近春稀。", "黃茅瘴色看看起，貪者猶疑別是機。"]'),
('0066f9f7-a694-452c-abb3-25c34dd96bb7','誡是非','劉兼','唐','唐诗','tang','','[]','巧舌如簧總莫聽，是非多自愛憎生。',66,'全唐诗/poet.tang.42000.json','["巧舌如簧總莫聽，是非多自愛憎生。", "三人告母雖投[杼]，百犬聞風只吠聲。", "辨玉且寬和氏罪，誣金須認不疑情。", "因思疇昔遊談者，六國交馳亦受烹。"]'),
('99cd20e9-4d06-496a-9afb-e1b1955d00c8','簡豎儒','劉兼','唐','唐诗','tang','','[]','蹄涔豈信有滄浪，螢火何堪竝太陽。',64,'全唐诗/poet.tang.42000.json','["蹄涔豈信有滄浪，螢火何堪竝太陽。", "淵奧未曾探禹穴，矜誇便擬越丘牆。", "小巫神氣終須怯，下里音聲必不長。", "近日冰壺多晦昧，虎皮羊質也觀光。"]'),
('645611be-6595-45d9-a52c-3f89abffd65d','貽諸學童','劉兼','唐','唐诗','tang','','[]','橫經叉手步還趨，積善方知慶有餘。',64,'全唐诗/poet.tang.42000.json','["橫經叉手步還趨，積善方知慶有餘。", "五箇小雛離學院，一行新雁入貧居。", "攘羊告罪言何直，舐犢牽情理豈虛。", "勸汝立身須苦志，月中丹桂自扶疎。"]'),
('5fdb9ab5-3dd3-4427-88cf-3f254d2ca8e1','吳 黃金車','孫元晏','唐','唐诗','tang','','[]','分擘山河即漸開，許昌基業已傾頹。',32,'全唐诗/poet.tang.42000.json','["分擘山河即漸開，許昌基業已傾頹。", "黃金車與斑斕耳，早個須知入讖來。"]'),
('20faa02b-b327-4fbe-8a40-8826c4592888','吳 赤壁','孫元晏','唐','唐诗','tang','','[]','會獵書來舉國驚，祗應周魯不教迎。',32,'全唐诗/poet.tang.42000.json','["會獵書來舉國驚，祗應周魯不教迎。", "曹公一戰奔波後，赤壁功傳萬古名。"]'),
('6cd6af9a-5019-46d5-ac95-67ff64fcc05e','吳 魯肅指囷','孫元晏','唐','唐诗','tang','','[]','破產移家事亦難，佐吳從此霸江山。',32,'全唐诗/poet.tang.42000.json','["破產移家事亦難，佐吳從此霸江山。", "爭教不立功勳得，指出千囷如等閑。"]'),
('1c18b40f-01b3-45d4-ac00-6a95655c0d42','吳 甘寧斫營','孫元晏','唐','唐诗','tang','','[]','夜深偷入魏軍營，滿寨驚忙火似星。',32,'全唐诗/poet.tang.42000.json','["夜深偷入魏軍營，滿寨驚忙火似星。", "百口寶刀千匹絹，也應消得與甘寧。"]'),
('6d61e081-87e4-434a-bce7-77a9743d5471','吳 徐盛','孫元晏','唐','唐诗','tang','','[]','欲把江山鼎足分，邢真銜冊到江南。',32,'全唐诗/poet.tang.42000.json','["欲把江山鼎足分，邢真銜冊到江南。", "當時將相誰堪重，徐盛將軍最不甘。"]'),
('d6b0e36d-a65b-4419-8094-86cd3337bbdf','吳 魯肅','孫元晏','唐','唐诗','tang','','[]','斫案興言斷衆疑，鼎分從此定雄雌。',32,'全唐诗/poet.tang.42000.json','["斫案興言斷衆疑，鼎分從此定雄雌。", "若無子敬心相似，爭得烏林破魏師。"]'),
('2d75fd07-e843-44d4-a08c-8c55fa8bda80','吳 武昌','孫元晏','唐','唐诗','tang','','[]','西塞山高截九垓，讖謠終日自相催。',32,'全唐诗/poet.tang.42000.json','["西塞山高截九垓，讖謠終日自相催。", "武昌魚美應難戀，曆數須歸建業來。"]'),
('2872e675-29c0-451d-a341-5bad5c6a6cb8','吳 顧雍','孫元晏','唐','唐诗','tang','','[]','贊國經綸更有誰，蔡公相歎亦相師。',32,'全唐诗/poet.tang.42000.json','["贊國經綸更有誰，蔡公相歎亦相師。", "貴爲丞相封侯了，歸後家人總不知。"]'),
('6cfeb1e4-a376-4129-af9b-23f77f91bd65','吳 呂蒙','孫元晏','唐','唐诗','tang','','[]','幼小家貧實可哀，願征行去志難回。',32,'全唐诗/poet.tang.42000.json','["幼小家貧實可哀，願征行去志難回。", "不探虎穴求身達，爭得人間富貴來。"]'),
('1c52db75-b70c-44fe-98fd-0dad3b2f6b91','吳 介象','孫元晏','唐','唐诗','tang','','[]','好道君王遇亦難，變通靈異幾多般。',32,'全唐诗/poet.tang.42000.json','["好道君王遇亦難，變通靈異幾多般。", "介先生有神仙術，釣得鱸魚在玉盤。"]'),
('b986c272-8844-43ec-982b-63bf65c39bd9','吳 濡須塢','孫元晏','唐','唐诗','tang','','[]','風揭洪濤響若雷，枕波爲壘險相隈。',32,'全唐诗/poet.tang.42000.json','["風揭洪濤響若雷，枕波爲壘險相隈。", "莫言有個濡須塢，幾度曹公失志回。"]'),
('cf15431d-1ee4-44ea-b9a3-a1de1e6914d6','吳 周泰','孫元晏','唐','唐诗','tang','','[]','名與諸公又不同，金瘡痕在滿身中。',32,'全唐诗/poet.tang.42000.json','["名與諸公又不同，金瘡痕在滿身中。", "不將御蓋宣恩澤，誰信將軍別有功。"]'),
('a59f205d-3f8f-4ac7-abbf-dd42a07a81b6','吳 張紘','孫元晏','唐','唐诗','tang','','[]','東部張公與衆殊，共施經畧贊全吳。',32,'全唐诗/poet.tang.42000.json','["東部張公與衆殊，共施經畧贊全吳。", "陳琳漫自稱雄伯，神氣應須怯大巫。"]'),
('8708cf61-0147-437d-b6f5-8d0f29383a48','吳 太史慈','孫元晏','唐','唐诗','tang','','[]','聖德招賢遠近知，曹公心計却成欺。',32,'全唐诗/poet.tang.42000.json','["聖德招賢遠近知，曹公心計却成欺。", "陳韓昔日嘗投楚，豈是當歸召得伊。"]'),
('34d95b04-ebc2-42c1-9cca-6f248da6c6ef','吳 孫堅后','孫元晏','唐','唐诗','tang','','[]','委存張公翊聖材，幾將賢德贊文臺。',32,'全唐诗/poet.tang.42000.json','["委存張公翊聖材，幾將賢德贊文臺。", "爭教不霸江山得，日月徵曾入夢來。"]'),
('fb3ec3b1-494e-49df-b1c1-1ccdbca02e2b','吳 陸統','孫元晏','唐','唐诗','tang','','[]','將軍身歿有兒孤，虎子爲名教讀書。',32,'全唐诗/poet.tang.42000.json','["將軍身歿有兒孤，虎子爲名教讀書。", "更向宮中教騎馬，感君恩重合何如。"]'),
('465ca3c9-d399-4f30-9dc3-7e16ec734442','吳 青蓋','孫元晏','唐','唐诗','tang','','[]','曆數將終勢已摧，不修君德更堪哀。',32,'全唐诗/poet.tang.42000.json','["曆數將終勢已摧，不修君德更堪哀。", "被他青蓋言相誤，元是須教入晉來。"]'),
('c5d1e6f6-743c-47f3-b2d5-8a7bcf9b35ae','晉 七寶鞭','孫元晏','唐','唐诗','tang','','[]','天命須知豈偶然，亂臣徒欲用兵權。',32,'全唐诗/poet.tang.42000.json','["天命須知豈偶然，亂臣徒欲用兵權。", "聖謨廟畧還應別，渾不消他七寶鞭。"]'),
('b93f39d8-e91b-4b15-b60d-2c10623550db','晉 庾悅鵝炙','孫元晏','唐','唐诗','tang','','[]','春暖江南景氣新，子鵝炙美就中珍。',32,'全唐诗/poet.tang.42000.json','["春暖江南景氣新，子鵝炙美就中珍。", "庾家廚盛劉公困，渾弗相貽也惱人。"]'),
('c4c82a64-7a44-4301-9a5c-77eff57f30d7','晉 謝玄','孫元晏','唐','唐诗','tang','','[]','百萬兵來逼合肥，謝玄爲將統雄師。',32,'全唐诗/poet.tang.42000.json','["百萬兵來逼合肥，謝玄爲將統雄師。", "旌旗首尾千餘里，渾不消他一局棊。"]'),
('93488d4b-299c-4788-9452-49103cd43b9d','晉 謝混','孫元晏','唐','唐诗','tang','','[]','尚主當初偶未成，此時誰合更關情。',32,'全唐诗/poet.tang.42000.json','["尚主當初偶未成，此時誰合更關情。", "可憐謝混風華在，千古翻傳禁臠名。"]'),
('595ff87e-6190-4cc0-8639-1e6fb7c952bf','晉 陸玩','孫元晏','唐','唐诗','tang','','[]','陸公高論亦由衷，謙讓還慙未有功。',32,'全唐诗/poet.tang.42000.json','["陸公高論亦由衷，謙讓還慙未有功。", "天下忠良人欲盡，始應交我作三公。"]'),
('4baa4b24-99d2-4e8c-81d4-4f6d9f7bc36e','晉 王坦之','孫元晏','唐','唐诗','tang','','[]','晉祚安危只此行，坦之何必苦憂驚。',32,'全唐诗/poet.tang.42000.json','["晉祚安危只此行，坦之何必苦憂驚。", "謝公合定寰區在，爭遣當時事得成。"]'),
('99fa083d-1708-4e68-b6c0-8bdf9b2bbbe8','晉 蒲葵扇','孫元晏','唐','唐诗','tang','','[]','拋捨東山歲月遙，幾施經畧挫雄豪。',32,'全唐诗/poet.tang.42000.json','["拋捨東山歲月遙，幾施經畧挫雄豪。", "若非名德喧寰宇，爭得蒲葵價數高。"]'),
('17a93474-ff61-4362-912c-760138929e9f','晉 王郎','孫元晏','唐','唐诗','tang','','[]','太尉門庭亦甚高，王郎名重禮相饒。',32,'全唐诗/poet.tang.42000.json','["太尉門庭亦甚高，王郎名重禮相饒。", "自家妻父猶如此，誰更逢君得折腰。"]'),
('00b0d5a0-bf63-4f5a-9f6c-718ccc5d3a26','晉 劉毅','孫元晏','唐','唐诗','tang','','[]','遶牀堪壯喝盧聲，似鐵容儀衆盡驚。',32,'全唐诗/poet.tang.42000.json','["遶牀堪壯喝盧聲，似鐵容儀衆盡驚。", "二十七人同舉義，幾人全得舊功名。"]'),
('94bef8b1-78b9-432b-a5d2-2987d529ba48','晉 王恭','孫元晏','唐','唐诗','tang','','[]','春風濯濯柳容儀，鶴氅神情舉世推。',32,'全唐诗/poet.tang.42000.json','["春風濯濯柳容儀，鶴氅神情舉世推。", "可惜教君仗旄鉞，枉將心地託牢之。"]'),
('f4e311a3-726f-49ba-a4bc-3c05d82abf51','晉 謝公賭墅','孫元晏','唐','唐诗','tang','','[]','發遣將軍欲去時，畧無情撓只貪棊。',32,'全唐诗/poet.tang.42000.json','["發遣將軍欲去時，畧無情撓只貪棊。", "自從乞與羊曇後，賭墅功成更有誰。"]'),
('936fd16d-0ba4-48af-9b33-fd5ec6ace67c','晉 苻堅投箠','孫元晏','唐','唐诗','tang','','[]','投箠填江語未終，謝安乘此立殊功。',32,'全唐诗/poet.tang.42000.json','["投箠填江語未終，謝安乘此立殊功。", "三台星爛乾坤在，且與張華死不同。"]'),
('ba437da2-5f6b-4a44-8a59-3f832fd7db79','晉 衛玠','孫元晏','唐','唐诗','tang','','[]','叔寶羊車海內稀，山家女壻好風姿。',32,'全唐诗/poet.tang.42000.json','["叔寶羊車海內稀，山家女壻好風姿。", "江東士女無端甚，看殺玉人渾不知。"]'),
('608997b6-76fb-4654-bbd9-cd7ff23996d8','晉 郭璞脫襦','孫元晏','唐','唐诗','tang','','[]','吟坐因思郭景純，每言窮達似通神。',32,'全唐诗/poet.tang.42000.json','["吟坐因思郭景純，每言窮達似通神。", "到頭分命難移改，解脫清襦與別人。"]'),
('175098fa-eb4c-4ba6-907e-39534452efa3','晉 庾樓','孫元晏','唐','唐诗','tang','','[]','江州樓上月明中，從事同登眺遠空。',32,'全唐诗/poet.tang.42000.json','["江州樓上月明中，從事同登眺遠空。", "玉樹忽薶千載後，有誰重此繼清風。"]'),
('949348c9-b9a8-4f5d-a5e1-6f960941cc4c','晉 新亭','孫元晏','唐','唐诗','tang','','[]','容易乘虛逼帝畿，滿江艛艣與旌旗。',32,'全唐诗/poet.tang.42000.json','["容易乘虛逼帝畿，滿江艛艣與旌旗。", "盧循若解新亭上，勝負還應未可知。"]'),
('e973d8bb-6146-4668-8a2d-2bfa94711428','宋 大峴','孫元晏','唐','唐诗','tang','','[]','大峴纔過喜可知，指空言已副心期。',32,'全唐诗/poet.tang.42000.json','["大峴纔過喜可知，指空言已副心期。", "公孫計策嗟無用，天與南朝作霸基。"]'),
('8635ff72-f931-4752-b843-614a9a5a0961','宋 放宮人','孫元晏','唐','唐诗','tang','','[]','納諫廷臣免犯顏，自然恩可霸江山。',32,'全唐诗/poet.tang.42000.json','["納諫廷臣免犯顏，自然恩可霸江山。", "姚興侍女方承寵，放出宮闈若等閑。"]'),
('16eedfc4-88d7-40e8-b09e-ba8fe5aef124','宋 借南苑','孫元晏','唐','唐诗','tang','','[]','人主詞應不偶然，幾人曾說笑掀天。',32,'全唐诗/poet.tang.42000.json','["人主詞應不偶然，幾人曾說笑掀天。", "不知南苑今何在，借與張公三百年。"]'),
('e359f4e5-6d0b-4650-83cc-6e996b912643','宋 謝澹雲霞友','孫元晏','唐','唐诗','tang','','[]','仗氣凌人豈可親，只將范泰是知聞。',32,'全唐诗/poet.tang.42000.json','["仗氣凌人豈可親，只將范泰是知聞。", "緣何喚作雲霞友，却恐雲霞未似君。"]'),
('5fb1b7fe-2804-435a-a8f4-245aed0fc99f','宋 烏衣巷','孫元晏','唐','唐诗','tang','','[]','古迹荒基好歎嗟，滿川吟景只煙霞。',32,'全唐诗/poet.tang.42000.json','["古迹荒基好歎嗟，滿川吟景只煙霞。", "烏衣巷在何人住，回首令人憶謝家。"]'),
('c6c92013-bdc0-4fa4-9eb7-4c12cefe963a','宋 袁粲','孫元晏','唐','唐诗','tang','','[]','負才尚氣滿朝知，高臥閑吟見客稀。',32,'全唐诗/poet.tang.42000.json','["負才尚氣滿朝知，高臥閑吟見客稀。", "獨步何人識袁尹，白楊郊外醉方歸。"]'),
('4feb86fc-d5e8-490e-96ff-ce4828fd7b49','宋 劉伯龍','孫元晏','唐','唐诗','tang','','[]','位重何如不厭貧，伯龍孤子只修身。',32,'全唐诗/poet.tang.42000.json','["位重何如不厭貧，伯龍孤子只修身。", "固知生計還須有，窮鬼臨時也笑人。"]'),
('bddf29a9-dd23-4223-95c5-602387e140c7','宋 王方平','孫元晏','唐','唐诗','tang','','[]','拂衣耕釣已多時，江上山前樂可知。',32,'全唐诗/poet.tang.42000.json','["拂衣耕釣已多時，江上山前樂可知。", "著却貂裘將採藥，任他人喚作漁師。"]'),
('097a9ac1-20c5-4322-9ac9-0ac9ffea0889','宋 黃羅襦','孫元晏','唐','唐诗','tang','','[]','戚屬羣臣盡見猜，預憂身後又堪哀。',32,'全唐诗/poet.tang.42000.json','["戚屬羣臣盡見猜，預憂身後又堪哀。", "到頭委付何曾是，虛把羅襦與彥回。"]'),
('2194c81d-2200-414a-80b1-8e45650102b0','宋 謝朏','孫元晏','唐','唐诗','tang','','[]','謝家諸子盡蘭香，各震芳名滿帝鄉。',32,'全唐诗/poet.tang.42000.json','["謝家諸子盡蘭香，各震芳名滿帝鄉。", "惟有千金更堪重，只將高臥向齊王。"]'),
('806e578d-367d-4609-bbc3-ca96a46c57d1','宋 羊玄保','孫元晏','唐','唐诗','tang','','[]','運命將來各有期，好官才闕即思之。',32,'全唐诗/poet.tang.42000.json','["運命將來各有期，好官才闕即思之。", "就中堪愛羊玄保，偏受君王分外知。"]'),
('eea51910-22c4-44ab-871a-a7ac83f764e9','齊 謝朏','孫元晏','唐','唐诗','tang','','[]','解璽傳呼詔侍中，却來高臥豈疏慵。',32,'全唐诗/poet.tang.42000.json','["解璽傳呼詔侍中，却來高臥豈疏慵。", "此時忠節還希有，堪羨君王特地容。"]'),
('3cf4b849-79d3-4f39-a383-eea07abb3aae','齊 小兒執燭','孫元晏','唐','唐诗','tang','','[]','謝公情量已難量，忠宋心誠豈暫忘。',32,'全唐诗/poet.tang.42000.json','["謝公情量已難量，忠宋心誠豈暫忘。", "執燭小兒渾放去，略無言語與君王。"]'),
('661c4823-2114-4bc1-9970-d1d4daa8bc51','齊 王僧祐','孫元晏','唐','唐诗','tang','','[]','肯與公卿作等倫，澹然名德只推君。',32,'全唐诗/poet.tang.42000.json','["肯與公卿作等倫，澹然名德只推君。", "任他車騎來相訪，簫鼓盈庭似不聞。"]'),
('c2fe4e3f-f6ab-4df8-a6c6-8a4aad4b03b5','齊 王僧虔','孫元晏','唐','唐诗','tang','','[]','位高名重不堪疑，懇讓儀同帝亦知。',32,'全唐诗/poet.tang.42000.json','["位高名重不堪疑，懇讓儀同帝亦知。", "不學常流爭進取，却憂門有二台司。"]'),
('ecba34f9-c6e8-45e3-bee2-723a4f711bb4','齊 明帝裹蒸','孫元晏','唐','唐诗','tang','','[]','至尊尊貴異人間，御膳天廚豈等閑。',32,'全唐诗/poet.tang.42000.json','["至尊尊貴異人間，御膳天廚豈等閑。", "惜得裹蒸無用處，不如安霸取江山。"]'),
('abf444a2-990d-43d2-aee5-de67df71d49a','齊 鬱林王','孫元晏','唐','唐诗','tang','','[]','強哀強慘亦從伊，歸到私庭喜可知。',32,'全唐诗/poet.tang.42000.json','["強哀強慘亦從伊，歸到私庭喜可知。", "喜字漫書三十六，到頭能得幾多時。"]'),
('21f8e75b-407c-4d67-9d8d-bc303517bf4c','齊 何氏小山','孫元晏','唐','唐诗','tang','','[]','顯達何曾肯繫心，築居郊外好園林。',32,'全唐诗/poet.tang.42000.json','["顯達何曾肯繫心，築居郊外好園林。", "賺他謝朏出山去，贏得高名直至今。"]'),
('a1e8545d-87e4-454d-a632-ec0988107271','齊 王倫之','孫元晏','唐','唐诗','tang','','[]','豫章太守重詞林，圖畫陳蕃與華歆。',32,'全唐诗/poet.tang.42000.json','["豫章太守重詞林，圖畫陳蕃與華歆。", "更奠子將幷孺子，爲君千載作知音。"]'),
('17b3a1a0-1f9f-419d-a7a8-f5ca86b7e936','齊 潘妃','孫元晏','唐','唐诗','tang','','[]','曾步金蓮寵絕倫，豈甘今日委埃塵。',32,'全唐诗/poet.tang.42000.json','["曾步金蓮寵絕倫，豈甘今日委埃塵。", "玉兒還有懷恩處，不肯將身嫁小臣。"]'),
('085adf86-1ddf-4c7b-a094-c605472201da','齊 王亮','孫元晏','唐','唐诗','tang','','[]','後見梁王未免哀，奈何無計拯傾頹。',32,'全唐诗/poet.tang.42000.json','["後見梁王未免哀，奈何無計拯傾頹。", "若教彼相顛扶得，爭遣明公到此來。"]'),
('842fba13-93e6-45bd-90b8-549319543770','梁 分宮女','孫元晏','唐','唐诗','tang','','[]','滌蕩齊宮法令新，分張宮女二千人。',32,'全唐诗/poet.tang.42000.json','["滌蕩齊宮法令新，分張宮女二千人。", "可憐無限如花貌，重見世間桃李春。"]'),
('e9c3113b-d02d-47fb-a208-6e3160b8aaa8','梁 馬仙埤','孫元晏','唐','唐诗','tang','','[]','齊朝太守不甘降，忠節當時動四方。',32,'全唐诗/poet.tang.42000.json','["齊朝太守不甘降，忠節當時動四方。", "義士要教天下見，且留君住待袁昂。"]'),
('6b9f8aa2-813e-46dd-8b1a-15ed7e121367','梁 勍敵','孫元晏','唐','唐诗','tang','','[]','傳聞天子重儒才，特爲皇華綺宴開。',32,'全唐诗/poet.tang.42000.json','["傳聞天子重儒才，特爲皇華綺宴開。", "今日方驚遇勍敵，此人元自北朝來。"]'),
('b6f38bc8-a6d3-4b3a-b183-eca22a7a886f','梁 蔡撙','孫元晏','唐','唐诗','tang','','[]','紫茄白莧以爲珍，守任清真轉更貧。',32,'全唐诗/poet.tang.42000.json','["紫茄白莧以爲珍，守任清真轉更貧。", "不飲吳興郡中水，古今能有幾多人。"]'),
('d26cbaab-ccf0-45bd-b0ef-3e90d4e31d78','梁 楚祠','孫元晏','唐','唐诗','tang','','[]','曾與蕭侯醉玉桮，此時神影盡傾頹。',32,'全唐诗/poet.tang.42000.json','["曾與蕭侯醉玉桮，此時神影盡傾頹。", "莫云千古無靈聖，也向西川助敵來。"]'),
('02c01ff4-e324-4d1d-906e-a5668ec96029','梁 謝朏小輿','孫元晏','唐','唐诗','tang','','[]','小輿升殿掌鈞台，不免無憀却憶回。',32,'全唐诗/poet.tang.42000.json','["小輿升殿掌鈞台，不免無憀却憶回。", "應恨被他何胤誤，悔先容易出山來。"]'),
('d97d355f-0c96-41c6-910d-37899aaf63e0','梁 八關齋','孫元晏','唐','唐诗','tang','','[]','依憑金地甚虔誠，忍溺空王爲聖明。',32,'全唐诗/poet.tang.42000.json','["依憑金地甚虔誠，忍溺空王爲聖明。", "內殿設齋申禱祝，豈無功德及臺城。"]'),
('d42dd1ac-fc7d-4487-8f36-e0a7e597321b','梁 庾信','孫元晏','唐','唐诗','tang','','[]','苦心詞賦向誰談，淪落周朝志豈甘。',32,'全唐诗/poet.tang.42000.json','["苦心詞賦向誰談，淪落周朝志豈甘。", "可惜多才庾開府，一生惆悵憶江南。"]'),
('f722c666-e64d-4a02-babf-0571a029977e','陳 王僧辨','孫元晏','唐','唐诗','tang','','[]','彼此英雄各有名，石頭高臥擬爭衡。',32,'全唐诗/poet.tang.42000.json','["彼此英雄各有名，石頭高臥擬爭衡。", "當時堪笑王僧辨，待欲將心託聖明。"]'),
('9be1afb4-54ca-4adf-bc04-758a4e5ec6ff','陳 武帝蚌盤','孫元晏','唐','唐诗','tang','','[]','金翠絲黃略不舒，蚌盤清宴意何如。',32,'全唐诗/poet.tang.42000.json','["金翠絲黃略不舒，蚌盤清宴意何如。", "豈知三閣繁華日，解爲君王妙破除。"]'),
('7b05353a-6a61-4908-8b0a-9e19b9d08cfa','陳 虞居士','孫元晏','唐','唐诗','tang','','[]','苦諫將軍總不知，幾隨煙焰作塵飛。',32,'全唐诗/poet.tang.42000.json','["苦諫將軍總不知，幾隨煙焰作塵飛。", "東山居士何人識，惟有君王却許歸。"]'),
('0d86caf5-fc10-4ebc-8d7a-f3688857c71d','陳 姚察','孫元晏','唐','唐诗','tang','','[]','曾佐徐陵向北遊，剖陳疑事動名流。',32,'全唐诗/poet.tang.42000.json','["曾佐徐陵向北遊，剖陳疑事動名流。", "却歸掌選清何甚，一匹花綀不肯收。"]'),
('f8433b5d-4e0d-419f-be28-25b39fede0c9','陳 宣帝傷將卒','孫元晏','唐','唐诗','tang','','[]','前後兵師戰勝回，百餘城壘盡歸來。',32,'全唐诗/poet.tang.42000.json','["前後兵師戰勝回，百餘城壘盡歸來。", "當時將卒應知感，況得君王爲舉哀。"]'),
('28ce92a9-063a-4091-91a8-42b92556e10d','陳 臨春閣','孫元晏','唐','唐诗','tang','','[]','臨春高閣上侵雲，風起香飄數里聞。',32,'全唐诗/poet.tang.42000.json','["臨春高閣上侵雲，風起香飄數里聞。", "自是君王正沈醉，豈知消息報隋軍。"]'),
('891e5f83-460a-4824-8eff-40709539ffbd','陳 [結]綺閣','孫元晏','唐','唐诗','tang','','[]','結綺高宜眺海涯，上凌丹漢拂雲霞。',32,'全唐诗/poet.tang.42000.json','["結綺高宜眺海涯，上凌丹漢拂雲霞。", "一千朱翠同居此，爭奈恩多屬麗華。"]'),
('1d56783b-2d55-4497-9306-f9008d148523','陳 望僊閣','孫元晏','唐','唐诗','tang','','[]','多少沈檀結築成，望仙爲號倚青冥。',32,'全唐诗/poet.tang.42000.json','["多少沈檀結築成，望仙爲號倚青冥。", "不知孔氏何形狀，醉得君主不解醒。"]'),
('1d3b34d0-32ce-4f87-a1b5-95585c5b1317','陳 三閣','孫元晏','唐','唐诗','tang','','[]','三閣相通綺宴開，數千朱翠遶周回。',32,'全唐诗/poet.tang.42000.json','["三閣相通綺宴開，數千朱翠遶周回。", "只知斷送君王醉，不道韓擒已到來。"]'),
('d8cd45dc-274f-4b7f-ba31-2f8932e6c9c1','陳 狎客','孫元晏','唐','唐诗','tang','','[]','八宮妃盡賦篇章，風揭歌聲錦繡香。',32,'全唐诗/poet.tang.42000.json','["八宮妃盡賦篇章，風揭歌聲錦繡香。", "選得十人爲狎客，有誰能解諫君王。"]'),
('50152499-6d45-4892-b857-6d1f1830cf14','陳 淮水','孫元晏','唐','唐诗','tang','','[]','文物衣冠盡入秦，六朝繁盛忽埃塵。',32,'全唐诗/poet.tang.42000.json','["文物衣冠盡入秦，六朝繁盛忽埃塵。", "自從淮水乾枯後，不見王家更有人。"]'),
('df67c3cd-47fc-4b31-bca5-bf321e745d99','陳 江令宅','孫元晏','唐','唐诗','tang','','[]','不向南朝立諫名，舊居基在事分明。',32,'全唐诗/poet.tang.42000.json','["不向南朝立諫名，舊居基在事分明。", "令人惆悵江中令，只作篇章過一生。"]'),
('f392e396-6adc-4339-9132-dabc6787532d','陳 後庭舞','孫元晏','唐','唐诗','tang','','[]','嬿婉回風態若飛，麗華翹袖玉爲姿。',32,'全唐诗/poet.tang.42000.json','["嬿婉回風態若飛，麗華翹袖玉爲姿。", "後庭一曲從教舞，舞破江山君未知。"]'),
('6eab8c6e-fcf9-45cf-9750-471fc2dbf153','班倢伃','嚴識玄','唐','唐诗','tang','','[]','賤妾如桃李，君王若歲時。',48,'全唐诗/poet.tang.42000.json','["賤妾如桃李，君王若歲時。", "秋風一已勁，搖落不勝悲。", "寂寂蒼苔滿，沈沈綠草滋。", "繁華非此日，指輦競何辭。"]'),
('fc0723bf-29c7-4277-b1d9-3c12f2f7594a','賦得御製句朔野陣雲飛','何象','唐','唐诗','tang','','[]','塞日穿痕斷，邊鴻背影飛。',24,'全唐诗/poet.tang.42000.json','["塞日穿痕斷，邊鴻背影飛。", "縹緲浮黃屋，陰沈護御衣。"]'),
('7b7b8b92-a509-4fb1-9b50-bca62b4ec925','宿金河戍','張震','唐','唐诗','tang','','[]','朝發鐵麟驛，夕宿金河戍。',48,'全唐诗/poet.tang.42000.json','["朝發鐵麟驛，夕宿金河戍。", "奔波急王程，一日千里路。", "但見容鬢改，不知歲華暮。", "悠悠沙漠行，王事彌多故。"]'),
('b0c7c934-5567-451d-8e47-1e736eb6fac0','補新宮 一','丘光庭','唐','唐诗','tang','','[]','奐奐新宮，禮樂其融。',40,'全唐诗/poet.tang.42000.json','["奐奐新宮，禮樂其融。", "爾德惟賢，爾□維忠。", "爲忠以公，斯筵是同。", "人之醉我，與我延賓。"]'),
('4b06c7fd-46b6-44f6-bed0-9de353df57b7','補新宮 二','丘光庭','唐','唐诗','tang','','[]','奐奐新宮，既奐而輪。',40,'全唐诗/poet.tang.42000.json','["奐奐新宮，既奐而輪。", "其固如山，其儼如雲。", "其寢斯安，□□□分。", "我既考落，以燕羣臣。"]'),
('4d42007c-124c-4aa1-94ef-d228140bb294','補新宮 三','丘光庭','唐','唐诗','tang','','[]','奐奐新宮，既祭既延。',40,'全唐诗/poet.tang.42000.json','["奐奐新宮，既祭既延。", "我□□鏞，于以醉賢。", "有禮無愆，我有斯宮。", "斯宮以安，康後萬年。"]'),
('4ddba38c-4ffa-487d-89bf-468826b264de','補茅鴟 一','丘光庭','唐','唐诗','tang','','[]','茅鴟茅鴟，無集我岡。',40,'全唐诗/poet.tang.42000.json','["茅鴟茅鴟，無集我岡。", "汝食汝飽，莫我爲祥。", "願彈去汝，來彼鳳凰。", "來彼鳳凰，其儀有章。"]'),
('9de3b6a3-cdf9-43ed-903a-1a098af5c426','補茅鴟 二','丘光庭','唐','唐诗','tang','','[]','茅鴟茅鴟，無啄我雀。',40,'全唐诗/poet.tang.42000.json','["茅鴟茅鴟，無啄我雀。", "汝食汝飽，莫我肯略。", "願彈去汝，來彼瑞鵲。", "來彼瑞鵲，其音可樂。"]'),
('79874942-d8cc-4d1f-9dd0-d30241d1e20d','補茅鴟 三','丘光庭','唐','唐诗','tang','','[]','茅鴟茅鴟，無搏鷅鶹。',40,'全唐诗/poet.tang.42000.json','["茅鴟茅鴟，無搏鷅鶹。", "汝食汝飽，莫我爲休。", "願彈去汝，來彼鳲鳩。", "來彼鳲鳩，食子其周。"]'),
('f5177fc1-3b2d-41b4-befb-c10d8b94ce8f','補茅鴟 四','丘光庭','唐','唐诗','tang','','[]','茅鴟茅鴟，無㗲我陵。',40,'全唐诗/poet.tang.42000.json','["茅鴟茅鴟，無㗲我陵。", "汝食汝飽，莫我好聲。", "願彈去汝，來彼蒼鷹。", "來彼蒼鷹，祭鳥是徵。"]'),
('1c8c0395-f63b-49cf-b055-2b10ea8afb78','瑕瑜不相掩','武翊黃','唐','唐诗','tang','','[]','抱璞應難辨，妍媸每自融。',72,'全唐诗/poet.tang.42000.json','["抱璞應難辨，妍媸每自融。", "貞姿偏特達，微玷遇磨礱。", "涇渭流終異，瑕瑜自不同。", "半曾光透石，未掩氣如虹。", "縝密誠爲智，包藏豈謂忠。", "停看分美惡，今得值良工。"]'),
('ccffe9d4-a66c-41ea-b04c-f4b374c83a94','袁江口懷王司勳王吏部','李祜','唐','唐诗','tang','','[]','京華不啻三千里，客淚如今一萬雙。',32,'全唐诗/poet.tang.42000.json','["京華不啻三千里，客淚如今一萬雙。", "若箇最爲相憶處，青楓黃竹入袁江。"]'),
('bafddc67-dc33-441c-8839-8d81601a9b87','贈進士李守微','韓嶼','唐','唐诗','tang','','[]','一定童顏老歲華，貧寒游歷貴人家。',64,'全唐诗/poet.tang.42000.json','["一定童顏老歲華，貧寒游歷貴人家。", "煉成正氣功應大，養得元神道不差。", "舃曳鶴毛乾毾𣬬，杖攜筇節瘦槎牙。", "如何蓬閬不歸去，落盡蟠桃幾度花。"]'),
('02d6505c-901e-4e90-a5da-78a864f9d4f2','馬上有見','李茂復','唐','唐诗','tang','','[]','行盡疎林見小橋，綠楊深處有紅蕉。',32,'全唐诗/poet.tang.42000.json','["行盡疎林見小橋，綠楊深處有紅蕉。", "無端眼界無分別，安置心頭不肯銷。"]'),
('04d056a9-ca1e-45ff-af60-7a865eb9cffa','自歎','李茂復','唐','唐诗','tang','','[]','落日西山近一竿，世間恩愛極難𢬵。',32,'全唐诗/poet.tang.42000.json','["落日西山近一竿，世間恩愛極難𢬵。", "近來不作顛狂事，免被冤家惡眼看。"]'),
('2f09b13c-f19d-45c5-af6e-cf099e8be705','贈吳圓','李曜','唐','唐诗','tang','','[]','經年理郡少歡娛，爲習干戈間飲徒。',32,'全唐诗/poet.tang.42000.json','["經年理郡少歡娛，爲習干戈間飲徒。", "今日臨行盡交割，分明收取媚川珠。"]'),
('ae4156ff-c06a-446e-803b-131e304e1440','答李曜','吳圓','唐','唐诗','tang','','[]','曳履優容日日歡，須言達德倍汍瀾。',32,'全唐诗/poet.tang.42000.json','["曳履優容日日歡，須言達德倍汍瀾。", "韶光今已輸先手，領得蠙珠掌上看。"]'),
('ccf25078-3cae-4ad7-9100-5a8512db0b7a','和訾家洲宴游','陸弘休','唐','唐诗','tang','','[]','新春蘂綻訾家洲，信是南方最勝游。',64,'全唐诗/poet.tang.42000.json','["新春蘂綻訾家洲，信是南方最勝游。", "酒滿百分殊不怕，人添一歲更堪愁。", "鶯聲暗逐歌聲豔，花態還隨舞態羞。", "莫惜今朝同酩酊，任他龜鶴與蜉蝣。"]'),
('13039106-f805-483a-b073-7e04517c87bf','題賈島墓','安錡','唐','唐诗','tang','','[]','倚恃才難繼，昂藏貌不恭。',48,'全唐诗/poet.tang.42000.json','["倚恃才難繼，昂藏貌不恭。", "騎驢衝大尹，奪卷忤宣宗。", "馳譽超先輩，居官下我儂。", "司倉舊曹署，一見一心忡。"]'),
('41d3aec4-a237-4e5b-97d2-43957c68c4a2','贈別營妓卿卿','油蔚','唐','唐诗','tang','','[]','憐君無那是多情，枕上相看直到明。',64,'全唐诗/poet.tang.42000.json','["憐君無那是多情，枕上相看直到明。", "日照綠窗人去住，鴉啼紅粉淚縱橫。", "愁腸只向金閨斷，白髮應從玉塞生。", "爲報花時少惆悵，此生終不負卿卿。"]'),
('3c530a5c-4785-44dd-8702-a7c2bb644f10','巢燕','胡玢','唐','唐诗','tang','','[]','燕來巢我簷，我屋非高大。',48,'全唐诗/poet.tang.42000.json','["燕來巢我簷，我屋非高大。", "所貴兒童善，保爾無殃禍。", "莫巢孀婦家，孀婦怨孤坐。", "妬爾長雙飛，打爾危巢破。"]'),
('dd8476a2-6337-4d8b-a879-260811639ee2','廬山桑落洲','胡玢','唐','唐诗','tang','','["\u5e90\u5c71"]','莫問桑田事，但看桑落洲。',48,'全唐诗/poet.tang.42000.json','["莫問桑田事，但看桑落洲。", "數家新住處，昔日大江流。", "古岸崩欲盡，平沙長未休。", "想應百年後，人世更悠悠。"]'),
('dde4c549-84a9-4238-a1d4-db974bb54e6d','石楠樹','胡玢','唐','唐诗','tang','','[]','本自清江石上生，移栽此處稱閑情。',64,'全唐诗/poet.tang.42000.json','["本自清江石上生，移栽此處稱閑情。", "青雲士盡識珍木，白屋人多喚俗名。", "重布綠陰滋蘚色，深藏好鳥引雛聲。", "余今一日千迴看，每度看來眼益明。"]'),
('c4c54bcd-4108-4ca9-9b33-b9c796b3dc8a','句','胡玢','唐','唐诗','tang','','[]','輪中別有物，光外更無空。',12,'全唐诗/poet.tang.42000.json','["輪中別有物，光外更無空。"]'),
('d63d1035-09c2-473d-b8e0-c43e976f601a','酒胡子','盧注','唐','唐诗','tang','','[]','同心相遇思同歡，擎出酒胡當玉盤。',180,'全唐诗/poet.tang.42000.json','["同心相遇思同歡，擎出酒胡當玉盤。", "盤中臲卼不自定，四座清賓注意看。", "可亦不在心，否亦不在面，徇客隨時自圓轉。", "酒胡五藏屬他人，十分亦是無情勸。", "爾不耕，亦不飢。", "爾不蠶，亦有衣。", "有眼不能分黼黻，有口不能明是非。", "鼻何尖，眼何碧，儀形本非天地力。", "雕鐫匠意苦多端，翠帽朱衫巧妝飾。", "長安斗酒十千酤，劉伶平生爲酒徒。", "劉伶虛向酒中死，不得酒池中拍浮。", "酒胡一滴不入眼，空令酒胡名酒胡。"]'),
('47f5de23-d195-4308-8f41-b338c254a927','西施','盧注','唐','唐诗','tang','','[]','惆悵興亡繫綺羅，世人猶自選青娥。',32,'全唐诗/poet.tang.42000.json','["惆悵興亡繫綺羅，世人猶自選青娥。", "越王解破夫差國，一箇西施已是多。"]'),
('c5944a00-b312-43f8-94ce-f59c3b2ec15c','題西施浣紗石','胡幽貞','唐','唐诗','tang','','[]','一朝入紫宮，萬古遺芳塵。',24,'全唐诗/poet.tang.42000.json','["一朝入紫宮，萬古遺芳塵。", "至今溪邊花，不敢嬌青春。"]'),
('4b35033b-44a4-4886-98c0-32a4ec016706','歸四明','胡幽貞','唐','唐诗','tang','','[]','海色連四明，仙舟去容易。',24,'全唐诗/poet.tang.42000.json','["海色連四明，仙舟去容易。", "天籍豈輙問，不是卑朝士。"]'),
('7f9a3f44-57d4-4214-9c17-56325d206675','送人游邵州','狄煥','唐','唐诗','tang','','[]','春江正渺渺，送別兩依依。',48,'全唐诗/poet.tang.42000.json','["春江正渺渺，送別兩依依。", "煙裏棹將遠，渡頭人未歸。", "漁家侵疊浪，島樹挂殘暉。", "況入湖湘路，那堪花亂飛。"]'),
('8f2d4534-c99a-4639-8b0b-c02d34b56b4c','題柳','狄煥','唐','唐诗','tang','','[]','天南與天北，此處影婆娑。',48,'全唐诗/poet.tang.42000.json','["天南與天北，此處影婆娑。", "翠色折不盡，離情生更多。", "雨餘籠灞岸，煙暝夾隋河。", "自有佳名在，秦松繼得麽。"]'),
('31fce595-d7f2-44dc-821f-f692a1a27d16','詠南嶽徑松','狄煥','唐','唐诗','tang','','["\u8861\u5c71"]','一陣雨聲歸嶽嶠，兩條寒色下瀟湘。',32,'全唐诗/poet.tang.42000.json','["一陣雨聲歸嶽嶠，兩條寒色下瀟湘。", "客吟晚景停孤櫂，僧踏清陰徹上方。"]'),
('ed2249ab-f00c-4a51-8add-257c5e794e72','句','狄煥','唐','唐诗','tang','','[]','數點當秋霽，不知何處峰？更無聲接續，空有影相隨。',24,'全唐诗/poet.tang.42000.json','["數點當秋霽，不知何處峰？更無聲接續，空有影相隨。"]'),
('9d74df0b-604b-45dc-802c-841be59f0112','潯陽觀水','韓溉','唐','唐诗','tang','','[]','朝宗漢水接陽臺，唅呀填坑吼作雷。',64,'全唐诗/poet.tang.42000.json','["朝宗漢水接陽臺，唅呀填坑吼作雷。", "莫見九江平穩去，還從三峽嶮巇來。", "南經夢澤寬浮日，西出岷山劣泛杯。", "直至滄溟涵貯盡，沈深不動浸昭回。"]'),
('14b55283-69b8-480c-8008-a762da10d4cc','水','韓溉','唐','唐诗','tang','','[]','方圓不定性空求，東注滄溟早晚休。',64,'全唐诗/poet.tang.42000.json','["方圓不定性空求，東注滄溟早晚休。", "高截碧塘長耿耿，遠飛青嶂更悠悠。", "瀟湘月浸千年色，夢澤煙含萬古愁。", "別有嶺頭嗚咽處，爲君分作斷腸流。"]'),
('ffb6bc82-a940-47dc-bb6a-8ad208454518','松','韓溉','唐','唐诗','tang','','[]','倚空高檻冷無塵，往事閑徵夢欲分。',64,'全唐诗/poet.tang.42000.json','["倚空高檻冷無塵，往事閑徵夢欲分。", "翠色本宜霜後見，寒聲偏向月中聞。", "啼猿想帶蒼山雨，歸鶴應和紫府雲。", "莫向東園競桃李，春光還是不容君。"]'),
('a114e227-28f2-4877-b744-12cdb34cb7e6','柳','韓溉','唐','唐诗','tang','','[]','雪盡青門弄影微，暖風遲日早鶯歸。',64,'全唐诗/poet.tang.42000.json','["雪盡青門弄影微，暖風遲日早鶯歸。", "如憑細葉留春色，須把長條繫落暉。", "彭澤有情還鬱鬱，隋堤無主自依依。", "世間惹恨偏饒此，可是行人折贈稀。"]'),
('c457dc82-d65a-4575-af65-1a6ea5e72862','竹','韓溉','唐','唐诗','tang','','[]','樹色連雲萬葉開，王孫不厭滿庭栽。',64,'全唐诗/poet.tang.42000.json','["樹色連雲萬葉開，王孫不厭滿庭栽。", "凌霜盡節無人見，終日虛心待鳳來。", "誰許風流添興詠，自憐瀟灑出塵埃。", "朱門處處多閑地，正好移陰覆翠苔。"]'),
('f59dbad4-f4cd-47e4-a839-9d9597d5ab7a','鵲','韓溉','唐','唐诗','tang','','[]','纔見離巢羽翼開，盡能輕颺出塵埃。',64,'全唐诗/poet.tang.42000.json','["纔見離巢羽翼開，盡能輕颺出塵埃。", "人間樹好紛紛占，天上橋成草草回。", "幾度送風臨玉戶，一時傳喜到妝臺。", "若教顏色如霜雪，應與清平作瑞來。"]'),
('4678e71d-2920-4548-a8ea-1cb759c445d3','燈','韓溉','唐','唐诗','tang','','[]','分影由來恨不同，綠窗孤館兩何窮。',64,'全唐诗/poet.tang.42000.json','["分影由來恨不同，綠窗孤館兩何窮。", "熒煌短焰長疑暗，零落殘花旋委空。", "幾處隔簾愁夜雨，誰家當戶怯秋風。", "莫言明滅無多重，曾比人生一世中。"]'),
('710f1b9a-9b92-44a9-90f9-4d0e238fcd2b','句','韓溉','唐','唐诗','tang','','[]','門掩落花人別後，窗含殘月酒醒時。',16,'全唐诗/poet.tang.42000.json','["門掩落花人別後，窗含殘月酒醒時。"]'),
('b41e25f5-5a57-497f-a3a2-84bdfb9331f5','春怨','金昌緒','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6000\u4eba", "\u4e94\u8a00\u7edd\u53e5", "\u95fa\u6028"]','打起黃鶯兒，莫教枝上啼。',24,'全唐诗/poet.tang.42000.json','["打起黃鶯兒，莫教枝上啼。", "啼時驚妾夢，不得到遼西。"]'),
('18d34867-5ad9-4787-8ebd-8fd03e6a0cc1','放猨','曾麻幾','唐','唐诗','tang','','[]','孤猨鎖檻歲年深，放出城南百丈林。',32,'全唐诗/poet.tang.42000.json','["孤猨鎖檻歲年深，放出城南百丈林。", "綠水任從聯臂飲，青山不用斷腸吟。"]'),
('3189af41-4de5-42ed-99ce-aa99ab2de0fa','觀兄弟同夜成婚','鄭軌','唐','唐诗','tang','','[]','棠棣開雙萼，夭桃照兩花。',48,'全唐诗/poet.tang.42000.json','["棠棣開雙萼，夭桃照兩花。", "分庭含佩響，隔扇偶妝華。", "迎風俱似雪，映綺共如霞。", "今宵二神女，幷在一仙家。"]'),
('f947de8c-92fe-4321-b627-721ffd429241','夏彈琴','劉戩','唐','唐诗','tang','','[]','碧山本岑寂，素琴何清幽。',84,'全唐诗/poet.tang.42000.json','["碧山本岑寂，素琴何清幽。", "彈爲風入松，崖谷颯已秋。", "庭鶴舞白雪，泉魚躍洪流。", "予欲娛世人，明月難暗投。", "感歎未終曲，淚下不可收。", "嗚呼鍾子期，零落歸荒丘。", "死而若有知，魂兮從我游。"]'),
('e86e8bf4-f3a8-414e-94fc-007f80e4354e','過函谷關','楊齊哲','唐','唐诗','tang','','[]','地險崤函北，途經分陝東。',36,'全唐诗/poet.tang.42000.json','["地險崤函北，途經分陝東。", "逶迤衆山盡，荒涼古塞空。", "河光流曉日，樹影散朝風。"]'),
('40b3c2f6-393c-4968-9b1e-c3d592592d9a','傷死奴','劉夷道','唐','唐诗','tang','','[]','丹籍生涯淺，黃泉歸路深。',24,'全唐诗/poet.tang.42000.json','["丹籍生涯淺，黃泉歸路深。", "不及江陵樹，千秋長作林。"]'),
('2cabf81a-c85e-4b1a-ab19-572d4d719d3f','侍宴賦得起坐彈鳴琴二首 一','楊希道','唐','唐诗','tang','','[]','北林鵲夜飛，南軒月初進。',48,'全唐诗/poet.tang.42000.json','["北林鵲夜飛，南軒月初進。", "調弦發清徵，蕩心怯褊恡。", "變作離鴻聲，還入思歸引。", "長歎未終極，秋風飄素鬢。"]'),
('b9801b4c-510e-45b1-ba22-ebf5090704e3','侍宴賦得起坐彈鳴琴二首 二','楊希道','唐','唐诗','tang','','[]','絲傳園客意，曲奏楚妃情。',24,'全唐诗/poet.tang.42000.json','["絲傳園客意，曲奏楚妃情。", "罕有知音者，空勞流水聲。"]'),
('6b84794e-f7ac-43fe-9356-82bb680bfb7c','詠琴','楊希道','唐','唐诗','tang','','[]','久擅龍門質，孤竦嶧陽名。',38,'全唐诗/poet.tang.42000.json','["久擅龍門質，孤竦嶧陽名。", "齊[娥]初發弄，趙女正調聲。", "嘉客勿遽反，繁弦曲未成。"]'),
('c5bc841e-5d20-49d2-a91b-61222eb792fb','詠笙','楊希道','唐','唐诗','tang','','[]','短長插鳳翼，洪細摹鸞音。',36,'全唐诗/poet.tang.42000.json','["短長插鳳翼，洪細摹鸞音。", "能令楚妃歎，復使荆王吟。", "切切孤竹管，來應雲和琴。"]'),
('55300d72-52fa-43d6-8a05-fac0c6e4bf40','詠舞','楊希道','唐','唐诗','tang','','[]','二八如同雪，三春類早花。',24,'全唐诗/poet.tang.42000.json','["二八如同雪，三春類早花。", "分行向燭轉，一種逐風斜。"]'),
('2d09a638-dd14-44ac-ac17-ed416422bdca','詠妓','王勣','唐','唐诗','tang','','[]','妖姬飾靚妝，窈窕出蘭房。',48,'全唐诗/poet.tang.42000.json','["妖姬飾靚妝，窈窕出蘭房。", "日照當軒影，風吹滿路香。", "早時歌扇薄，今日舞衫長。", "不應令曲誤，持此試周郎。"]'),
('bb34b393-79b9-4ebe-9760-86e6f6be66d1','益州城西張超亭觀妓','王勣','唐','唐诗','tang','','[]','落日明歌席，行雲逐舞人。',48,'全唐诗/poet.tang.42000.json','["落日明歌席，行雲逐舞人。", "江前飛暮雨，梁上下輕塵。", "冶服看疑畫，妝臺望似春。", "高車勿遽返，長袖欲相親。"]'),
('d91474a0-27fa-4e20-b243-10acb4190cc7','辛司法宅觀妓','王勣','唐','唐诗','tang','','[]','南國佳人至，北堂羅薦開。',48,'全唐诗/poet.tang.42000.json','["南國佳人至，北堂羅薦開。", "長裙隨鳳管，促柱送鸞杯。", "雲光身後落，雪態掌中回。", "到愁金谷晚，不怪玉山頹。"]'),
('ef029348-a389-4705-8903-d17de5734933','秋池一枝蓮','郭恭','唐','唐诗','tang','','[]','秋至皆零落，凌波獨吐紅。',24,'全唐诗/poet.tang.42000.json','["秋至皆零落，凌波獨吐紅。", "托根方得所，未肯即隨風。"]'),
('9236e030-9820-49e0-b5be-aef19dcaf9b3','婕妤怨','張烜','唐','唐诗','tang','','[]','賤妾裁紈扇，初搖明月姿。',48,'全唐诗/poet.tang.42000.json','["賤妾裁紈扇，初搖明月姿。", "君王看舞席，坐起秋風時。", "玉樹清御路，金陳翳垂絲。", "昭陽無分理，愁寂任前期。"]'),
('76519323-4e3f-4442-b757-dce23dc21c5d','長門怨','張修之','唐','唐诗','tang','','[]','長門落景盡，洞房秋月明。',48,'全唐诗/poet.tang.42000.json','["長門落景盡，洞房秋月明。", "玉階草露積，金屋網塵生。", "妾妒今應改，君恩昔未平。", "寄語臨邛客，何時作賦成。"]'),
('d1b0278c-d198-48e5-954b-fbc27eb7b526','王昭君','梁獻','唐','唐诗','tang','','[]','圖畫失天真，容華坐誤人。',48,'全唐诗/poet.tang.42000.json','["圖畫失天真，容華坐誤人。", "君恩不可再，妾命在和親。", "淚點關山月，衣銷邊塞塵。", "一聞陽鳥至，思絕漢宮春。"]'),
('605e8805-d2fa-41ff-a7e9-7140c78ef7ac','芳樹','符子珪','唐','唐诗','tang','','[]','芳樹宜三月，曈曈豔綺年。',48,'全唐诗/poet.tang.42000.json','["芳樹宜三月，曈曈豔綺年。", "香交珠箔氣，陰占綠庭煙。", "小葉風吹長，繁花露濯鮮。", "遂令穠李兒，折取簪花鈿。"]'),
('54c32e1f-8b27-41d9-a0b5-e5f2582f9dba','觀妓','李何','唐','唐诗','tang','','[]','向晚小乘遊，朝來新上頭。',24,'全唐诗/poet.tang.42000.json','["向晚小乘遊，朝來新上頭。", "從來許長袖，未有客難留。"]'),
('062e81ae-95dc-4d3e-b9f9-ea23451c82c5','邯鄲俠少年','鄭鏦','唐','唐诗','tang','','[]','夜渡濁河津，衣中劒滿身。',48,'全唐诗/poet.tang.42000.json','["夜渡濁河津，衣中劒滿身。", "兵符劫晉鄙，匕首刺秦人。", "執事非無膽，高堂念有親。", "昨緣秦苦趙，來往大梁頻。"]'),
('9fe17dde-0803-4a16-b0af-30048872d60a','玉階怨','鄭鏦','唐','唐诗','tang','','[]','昔日同飛燕，今朝似伯勞。',48,'全唐诗/poet.tang.42000.json','["昔日同飛燕，今朝似伯勞。", "情深爭擲果，寵罷怨殘桃。", "別殿春心斷，長門夜樹高。", "雖能不自悔，誰見舊衣褒。"]'),
('2bf75b4d-b436-4606-be25-38d14287b43f','婕妤怨','鄭鏦','唐','唐诗','tang','','[]','南國承歡日，東方候曉時。',48,'全唐诗/poet.tang.42000.json','["南國承歡日，東方候曉時。", "那能妒褒姒，祗愛笑唐兒。", "寶葉隨雲髻，珠絲鍛履綦。", "不知飛燕意，何事苦相疑。"]'),
('c85a7438-8498-42aa-a9f3-f0f89c1887b4','入塞曲','鄭鏦','唐','唐诗','tang','','[]','留滯邊庭久，歸思歲月賒。',48,'全唐诗/poet.tang.42000.json','["留滯邊庭久，歸思歲月賒。", "黃雲同入塞，白首獨還家。", "宛馬隨秦草，胡人問漢花。", "還傷李都尉，獨自沒黃沙。"]'),
('55655ff6-aef0-4f87-b017-157afe23cee6','賞殘花','紇干著','唐','唐诗','tang','','[]','零落多依草，芳香散著人。',24,'全唐诗/poet.tang.42000.json','["零落多依草，芳香散著人。", "低簷一枝在，猶占滿堂春。"]'),
('569ed0de-4674-4941-bd23-c1a0634d26b8','古仙詞','紇干著','唐','唐诗','tang','','[]','珠幡絳節曉霞中，漢武清齋待少翁。',32,'全唐诗/poet.tang.42000.json','["珠幡絳節曉霞中，漢武清齋待少翁。", "不向人間戀春色，桃花自滿紫陽宮。"]'),
('5ac2ecfc-6d6e-4a3c-a503-d23fac7c0ae2','感春詞','紇干著','唐','唐诗','tang','','[]','未得鳴珂謁漢宮，江頭寂寞向春風。',32,'全唐诗/poet.tang.42000.json','["未得鳴珂謁漢宮，江頭寂寞向春風。", "悲歌一曲心應醉，萬葉千花淚眼中。"]'),
('5c47ef80-a127-446d-8ecb-31eaabcd34d0','灞上','紇干著','唐','唐诗','tang','','[]','鳴鞭晚日禁城東，渭水晴煙灞岸風。',32,'全唐诗/poet.tang.42000.json','["鳴鞭晚日禁城東，渭水晴煙灞岸風。", "都傍柳陰回首望，春天樓閣五雲中。"]'),
('8004b06b-41b5-43aa-ba43-ce8e418407fe','凌雲寺','李習','唐','唐诗','tang','','[]','古寺臨江間碧波，石梯深入白雲窠。',32,'全唐诗/poet.tang.42000.json','["古寺臨江間碧波，石梯深入白雲窠。", "僧禪寂寂無人跡，滿地落花春又過。"]'),
('18575368-2853-4fc0-b1ee-8f98e9e0e42a','鳳棲怨','顏舒','唐','唐诗','tang','','[]','佳人名莫愁，珠箔上花鉤。',48,'全唐诗/poet.tang.42000.json','["佳人名莫愁，珠箔上花鉤。", "清鏡鴛鴦匣，新妝翡翠樓。", "擣衣明月夜，吹管白雲秋。", "惟恨金吾子，年年向隴頭。"]'),
('d5475f18-667a-4f89-a97a-35b1a4550ac8','春女怨','朱絳','唐','唐诗','tang','','[]','獨坐紗窗刺繡遲，紫荆花下囀黃鸝。',32,'全唐诗/poet.tang.42000.json','["獨坐紗窗刺繡遲，紫荆花下囀黃鸝。", "欲知無限傷春意，盡在停針不語時。"]'),
('d78cbde2-edf3-4166-9aa7-4e1115b9cccc','失題','徐璧','唐','唐诗','tang','','[]','雙燕今朝至，何時發海濱？窺簷向人語，如道故鄉春。',24,'全唐诗/poet.tang.42000.json','["雙燕今朝至，何時發海濱？窺簷向人語，如道故鄉春。"]'),
('2a414387-9a5a-4e97-9d7e-fd0d73ee5bcd','催妝','徐安期','唐','唐诗','tang','','[]','傳聞燭下調紅粉，明鏡臺前別作春。',32,'全唐诗/poet.tang.42000.json','["傳聞燭下調紅粉，明鏡臺前別作春。", "不須面上渾妝却，留著雙眉待畫人。"]'),
('58da5236-5f49-43b6-a97f-393c061eab53','隔壁聞奏伎','裴延','唐','唐诗','tang','','[]','徒聞管弦切，不見舞腰回。',24,'全唐诗/poet.tang.42000.json','["徒聞管弦切，不見舞腰回。", "賴有歌梁合，塵飛一半來。"]'),
('2773dc92-2757-46df-8715-8ba1565f79a6','詠翦花','裴延','唐','唐诗','tang','','[]','花寒未聚蝶，色豔已驚人。',24,'全唐诗/poet.tang.42000.json','["花寒未聚蝶，色豔已驚人。", "懸知陌上柳，應妒手中春。"]'),
('c78be780-b2a1-4de6-b512-a72a355d536b','歎美人照鏡','陳述','唐','唐诗','tang','','[]','插花枝共動，含笑靨俱生。',36,'全唐诗/poet.tang.42000.json','["插花枝共動，含笑靨俱生。", "衫分兩處色，釧響一邊聲。", "就中還妒影，恐奪可憐名。"]'),
('fa43bc94-52d6-4a76-90cd-dd34f0cf5b1f','開緘怨','朱琳','唐','唐诗','tang','','[]','夫婿邊庭久，幽閨恨幾重。',48,'全唐诗/poet.tang.42000.json','["夫婿邊庭久，幽閨恨幾重。", "玉琴知別日，金鏡識愁容。", "懶寄雲中服，慵開海上封。", "年年得衣慣，且試莫裁縫。"]'),
('ae5a4c42-cfac-4077-9ce9-cf56025e183d','雜言','謝陶','唐','唐诗','tang','','[]','天不與人言，禍福能自至。',48,'全唐诗/poet.tang.42000.json','["天不與人言，禍福能自至。", "水火雖活人，暫不得即死。", "蹈之焚斯須，憑之溺容易。", "水火與禍福，豈有先言耳。"]'),
('91ded700-11dd-40e4-b093-bee065c7ed9c','書事','何贊','唐','唐诗','tang','','[]','果決生涯向路中，西投知己話從容。',64,'全唐诗/poet.tang.42000.json','["果決生涯向路中，西投知己話從容。", "雲遮劍閣三千里，水隔瞿塘十二峰。", "闊步文翁坊裏月，閑尋杜老宅邊松。", "到頭須卜林泉隱，自愧無能繼臥龍。"]'),
('a1dce452-b83c-40fc-9e05-815c7eafbbd0','鴈塔','解彥融','唐','唐诗','tang','','[]','崢嶸澈倒景，刻峭俯無地。',120,'全唐诗/poet.tang.42000.json','["崢嶸澈倒景，刻峭俯無地。", "勇進攀有緣，即嶮恐迷墜。", "窅然喪五蘊，蠢爾懷萬類。", "實際罔他尋，波羅必可致。", "南山繚上苑，祇樹連巖翠。", "北斗臨帝城，扶宮切太清。", "餐和裨日用，味道懿天明。", "綠野冷風浹，紫微佳氣晶。", "馴禽演法要，忍草藉經行。", "本願從茲適，方知物世輕。"]'),
('524ecb86-26b8-44db-9100-a7a8d2a9bcbe','昭君怨','董初','唐','唐诗','tang','','[]','新年猶尚小，那堪遠聘秦。',48,'全唐诗/poet.tang.42000.json','["新年猶尚小，那堪遠聘秦。", "裾衫沾馬汗，眉黛染胡塵。", "舉眼無相識，路逢皆異人。", "唯有梅將李，猶帶故鄉春。"]'),
('9826a309-8ef9-42b0-8903-d5cda7453f57','南山','賀朝清','唐','唐诗','tang','','[]','湖北雨初晴，湖南山盡見。',48,'全唐诗/poet.tang.42000.json','["湖北雨初晴，湖南山盡見。", "嵒嵒石帆影，如得海風便。", "仙穴茅山峰，彩雲時一見。", "邀君共探此，異籙殘幾卷。"]'),
('1fb7a86a-2c1d-410e-9a1f-20c14a758b90','賦得遊人久不歸','賀朝清','唐','唐诗','tang','','[]','鄉關眇天末，引領悵懷歸。',48,'全唐诗/poet.tang.42000.json','["鄉關眇天末，引領悵懷歸。", "羈旅久淫滯，物色屢芳菲。", "稍覺私意盡，行看鬔鬢稀。", "如何千里外，佇立霑裳衣。"]'),
('4ec437fe-6347-4989-b53e-1065d2b25cd6','白紵辭 一','楊衡','唐','唐诗','tang','','[]','玉纓翠珮雜輕羅，香汗微漬朱顏酡，爲君起唱白紵歌。',72,'全唐诗/poet.tang.42000.json','["玉纓翠珮雜輕羅，香汗微漬朱顏酡，爲君起唱白紵歌。", "清聲褭雲思繁多，凝笳哀琴時相和。", "金壺半傾芳夜促，梁塵霏霏暗紅燭。", "令君安坐聽終曲，墜葉飄花難再復。"]'),
('8f0b9071-c9b9-487c-bf97-fc4d89de649a','白紵辭 二','楊衡','唐','唐诗','tang','','[]','躡珠履，步瓊筵。',56,'全唐诗/poet.tang.42000.json','["躡珠履，步瓊筵。", "輕身起舞紅燭前，芳姿豔態妖且妍。", "迴眸轉袖暗催弦，涼風蕭蕭漏水急。", "月華泛溢紅蓮濕，牽裙攬帶翻成泣。"]'),
('288df8f2-e0e3-4ccb-8a75-e0d2e317ea7a','還渭南感舊二首 一','唐暄','唐','唐诗','tang','','[]','寢室悲長簟，妝樓泣鏡臺。',36,'全唐诗/poet.tang.42000.json','["寢室悲長簟，妝樓泣鏡臺。", "獨悲桃李節，不共一時開。", "魂兮若有感，髣髴夢中來。"]'),
('f8c01b8b-02df-44bd-b331-e48fbe26d807','還渭南感舊二首 二','唐暄','唐','唐诗','tang','','[]','常時華室靜，笑語度更籌。',48,'全唐诗/poet.tang.42000.json','["常時華室靜，笑語度更籌。", "恍惚人事改，冥漠委荒丘。", "陽原歎薤露，陰壑悼藏舟。", "清夜妝臺月，空想畫眉愁。"]'),
('3cd6c4a3-10f0-4cb4-9d6f-8b69778997cb','贈亡妻張氏','唐暄','唐','唐诗','tang','','[]','嶧陽桐半死，延津劒一沈。',24,'全唐诗/poet.tang.42000.json','["嶧陽桐半死，延津劒一沈。", "如何宿昔內，空負百年心。"]'),
('0500c6f9-6432-4bd8-910e-052d1ab7884b','題司空山觀','李韶','唐','唐诗','tang','','[]','梁代真人上紫微，水盤山脚五雲飛。',32,'全唐诗/poet.tang.42000.json','["梁代真人上紫微，水盤山脚五雲飛。", "松杉老盡無消息，猶得千年一度歸。"]'),
('7e6c9e13-cd8e-49c5-b353-3ff2260a9ace','戲題盱眙壁','韋鵬翼','唐','唐诗','tang','','[]','豈肯閑尋竹徑行，却嫌絲管好蛙聲。',32,'全唐诗/poet.tang.42000.json','["豈肯閑尋竹徑行，却嫌絲管好蛙聲。", "自從煮鶴燒琴後，背却青山臥月明。"]'),
('40ba8774-1f69-4ad2-80eb-31f7255d3242','題楊少卿書後','安鴻漸','唐','唐诗','tang','','[]','端溪石硯宣城管，王屋松煙紫兔毫。',32,'全唐诗/poet.tang.42000.json','["端溪石硯宣城管，王屋松煙紫兔毫。", "更得孤卿老書札，人間無此五般高。"]'),
('84834cee-75e6-406e-a652-c7d08a2d093d','自紫陽觀至華陽洞宿侯尊師草堂簡同遊','李延陵','唐','唐诗','tang','','[]','石林媚煙景，句曲盤江甸。',144,'全唐诗/poet.tang.42000.json','["石林媚煙景，句曲盤江甸。", "南向佳氣濃，峰峰遙隱見。", "漸臨華陽口，微路入葱蒨。", "七曜懸洞宮，五雲抱山殿。", "銀函意誰發，金液徒堪薦。", "千載桃花春，秦人深不見。", "東溪喜相遇，貞白如會面。", "青鳥來去閑，紅霞朝夕變。", "一從化真骨，萬里乘飛電。", "蘿月延步虛，松花醉閑宴。", "幽人即長往，茂宰應交戰。", "明發歸琴堂，知君嬾爲縣。"]'),
('9a54f389-251e-4085-8cbd-66c288c60d73','題鍾雅青紗枕','秦尚運','唐','唐诗','tang','','[]','陰香裝豔入青紗，還與欹眠好事家。',32,'全唐诗/poet.tang.42000.json','["陰香裝豔入青紗，還與欹眠好事家。", "夢裏却成山色雨，沈山不敢鬬青華。"]'),
('339f4fcf-62ee-4505-b608-b75a44161be9','題搔口','張仲謀','唐','唐诗','tang','','[]','嘗聞燒尾便拏空，只過天門更一重。',32,'全唐诗/poet.tang.42000.json','["嘗聞燒尾便拏空，只過天門更一重。", "大禹未生門未鑿，可能天下總無龍。"]'),
('1b29f012-6843-41d0-a61f-f6daa3d57995','山寺見楊少卿書壁因題其尾','馮少吉','唐','唐诗','tang','','[]','少卿真跡滿僧居，祗恐鍾王也不如。',32,'全唐诗/poet.tang.42000.json','["少卿真跡滿僧居，祗恐鍾王也不如。", "爲報遠公須愛惜，此書書後更無書。"]'),
('6ac4e8c5-8608-40a8-9315-c5296dbbfa79','經杜甫舊宅','殷陶','唐','唐诗','tang','','[]','浣花溪裏花多處，爲憶先生在蜀時。',64,'全唐诗/poet.tang.42000.json','["浣花溪裏花多處，爲憶先生在蜀時。", "萬古只應留舊宅，千金無復換新詩。", "沙棚水檻鷗飛盡，樹壓村橋馬過時。", "山月不知人事變，夜來江上與誰期。"]'),
('e2ab266d-3eaa-4c37-939a-8f2ea02adf57','行縣至浮查寺','羅炯','唐','唐诗','tang','','[]','二十年前此布衣，鹿鳴西上虎符歸。',64,'全唐诗/poet.tang.42000.json','["二十年前此布衣，鹿鳴西上虎符歸。", "行時賓從光前事，到處松杉長舊圍。", "野老競遮官道拜，沙鷗遙避隼旟飛。", "春風一宿琉璃地，自有泉聲愜素機。"]'),
('a2308f16-aec3-4bd5-9bcd-24e9ebcd80e4','敕和元相公家園即事寄王相公','韓雄','唐','唐诗','tang','','[]','共列中台貴，能齊物外心。',48,'全唐诗/poet.tang.42000.json','["共列中台貴，能齊物外心。", "迴車青閣晚，解帶碧芳深。", "夜水隨畦入，晴花度竹尋。", "題詩更相應，一字重千金。"]'),
('c48d44c3-feb5-40c8-a856-05f5c027547a','仲秋太常寺觀公輅車拜陵','苗仲方','唐','唐诗','tang','','[]','南宮初開律，金風已戒涼。',72,'全唐诗/poet.tang.42000.json','["南宮初開律，金風已戒涼。", "拜陵將展敬，車輅儼成行。", "士庶觀祠禮，公卿習舊章。", "郊原佳氣引，園寢瑞煙長。", "鹵簿辭丹闕，威儀列太常。", "聖心何所寄，惟德在無忘。"]'),
('c9dc403a-a474-4498-a7b8-af589e2163fd','尋易尊師不遇','陳嶰','唐','唐诗','tang','','[]','爛熳紅霞光照衣，苔封白石路微微。',32,'全唐诗/poet.tang.42000.json','["爛熳紅霞光照衣，苔封白石路微微。", "華陽洞裏何人在，落盡松花不見歸。"]'),
('9fb78251-4368-4537-ad9b-973d8f676fb6','早過棃嶺喜雪書情呈崔判官','張起','唐','唐诗','tang','','[]','度嶺逢朝雪，行看馬跡深。',48,'全唐诗/poet.tang.42000.json','["度嶺逢朝雪，行看馬跡深。", "輕標南國瑞，寒慰北人心。", "皎潔停丹嶂，飄颻映綠林。", "共君歌樂土，無作白頭吟。"]'),
('fa3e609e-e7fb-4dc9-84f2-fdfbbf8faf9b','春情','張起','唐','唐诗','tang','','[]','畫閣餘寒在，新年舊燕歸。',24,'全唐诗/poet.tang.42000.json','["畫閣餘寒在，新年舊燕歸。", "梅花猶帶雪，未得試春衣。"]'),
('2275179c-519b-44ea-b7fd-6b9c85b7cb14','贈竇蔡二記室入蜀','陳政','唐','唐诗','tang','','[]','崑山積良寶，大廈構衆材。',144,'全唐诗/poet.tang.42000.json','["崑山積良寶，大廈構衆材。", "馬卿委官去，鄒子背淮來。", "風流信多美，朝夕豫平臺。", "逸翮獨不羣，清才復遒上。", "六輔昔推名，二江今振響。", "英華雖外發，磨琢終內朗。", "四海奮羽儀，清風久播馳。", "沈鬱林難廁，青山翻易阻。", "迴首望煙霞，誰知慕儔侶。", "飄然不繫舟，爲情自可求。", "若奉西園夜，浩想北園愁。", "無因逐萍藻，從爾泛清流。"]'),
('06159912-0e2d-44da-bd3f-90e42153c795','採菊','李建業','唐','唐诗','tang','','[]','簇簇竟相鮮，一枝開幾番。',52,'全唐诗/poet.tang.42000.json','["簇簇竟相鮮，一枝開幾番。", "味甘資麴{艹/糪}，香好勝蘭蓀。", "古道風搖遠，荒籬露壓繁。", "盈筐時採得，服餌近知門。"]'),
('43a0813e-d591-41d7-957f-e04ad2db810f','水精環','羅維','唐','唐诗','tang','','[]','王室符長慶，環中得水精。',72,'全唐诗/poet.tang.42000.json','["王室符長慶，環中得水精。", "任圓循不極，見素質仍貞。", "信是天然瑞，非因樸斲成。", "無瑕勝玉美，至潔過冰清。", "未肯齊珉價，寧同雜佩聲。", "能銜任黃雀，亦欲應時明。"]'),
('db641eb5-3dd5-44ae-9688-c0eb005da71a','看牡丹','殷益','唐','唐诗','tang','','[]','擁毳對芳叢，由來趣不同。',48,'全唐诗/poet.tang.42000.json','["擁毳對芳叢，由來趣不同。", "髮從今日白，花是去年紅。", "豔色隨朝露，馨香逐晚風。", "何須待零落，然後始知空。"]'),
('95358367-9762-480e-8cf6-f0cd0cad1dee','賦得垣衣','李得','唐','唐诗','tang','','[]','漠漠復霏霏，爲君垣上衣。',48,'全唐诗/poet.tang.42000.json','["漠漠復霏霏，爲君垣上衣。", "昭陽輦下草，應笑此生非。", "掩藹青春去，蒼茫白露稀。", "猶勝萍逐水，流浪不相依。"]'),
('0d245633-9131-4afa-b96e-a23b0d9189cf','冬晚對雪憶胡處士','王邵','唐','唐诗','tang','','["\u601d\u5ff5", "\u5199\u96ea", "\u51ac\u5929", "\u96ea"]','寒更傳唱晚，清鏡覽衰顏。',48,'全唐诗/poet.tang.42000.json','["寒更傳唱晚，清鏡覽衰顏。", "隔牖風驚竹，開簾雪滿山。", "灑空深巷靜，積素廣庭閑。", "借問袁安舍，翛然尚閉關。"]'),
('e326e353-777c-4656-8752-c14f3cf1309d','池上','曹脩古','唐','唐诗','tang','','[]','荷葉罩芙蓉，圓青映嫩紅。',24,'全唐诗/poet.tang.42000.json','["荷葉罩芙蓉，圓青映嫩紅。", "佳人南陌上，翠蓋立春風。"]'),
('1c323f45-2326-462c-9b22-88e6a8e34b61','對趙穎歌','朱子真','唐','唐诗','tang','','[]','人間幾日變桑田，誰識神仙洞裏天。',32,'全唐诗/poet.tang.42000.json','["人間幾日變桑田，誰識神仙洞裏天。", "短促雖知有殊異，且須歡醉在生前。"]'),
('6078f45d-2a0b-4386-b2e1-99188da142cc','賦百舌鳥','嚴郭','唐','唐诗','tang','','[]','此禽輕巧少同倫，我聽長疑舌滿身。',64,'全唐诗/poet.tang.42000.json','["此禽輕巧少同倫，我聽長疑舌滿身。", "星未沒河先報曉，柳猶粘雪便迎春。", "頻嫌海燕巢難定，却訝林鶯語不真。", "莫倚清風更多事，玉樓還有晏眠人。"]'),
('8c490656-abbe-416a-89f8-9453bf58e72d','孤雁','張子明','唐','唐诗','tang','','[]','隻影翩翩下碧湘，傍池鴛鷺宿銀塘。',64,'全唐诗/poet.tang.42000.json','["隻影翩翩下碧湘，傍池鴛鷺宿銀塘。", "雖逢夜雨迷深浦，終向晴天著舊行。", "憶伴幾回思片月，蛻翎多爲繫繁霜。", "江南塞北俱關念，兩地飛歸是故鄉。"]'),
('0d8e8202-f326-4d56-8427-6ce20a3cc684','水殿拋毬曲二首 一','李謹言','唐','唐诗','tang','','[]','侍宴黃昏曉未休，玉階夜色月如流。',32,'全唐诗/poet.tang.42000.json','["侍宴黃昏曉未休，玉階夜色月如流。", "朝來自覺承恩最，笑倩傍人認繡毬。"]'),
('1674f002-ec41-4719-ba47-875daf4afdf8','水殿拋毬曲二首 二','李謹言','唐','唐诗','tang','','[]','堪恨隋家幾帝王，舞裀揉盡繡鴛鴦。',32,'全唐诗/poet.tang.42000.json','["堪恨隋家幾帝王，舞裀揉盡繡鴛鴦。", "如今重到拋毬處，不是金鑪舊日香。"]'),
('30d10358-8e8d-4f3a-aa04-72242e7f6c4d','銅雀妓','吳燭','唐','唐诗','tang','','[]','秋色西陵滿綠蕪，繁弦急管強歡娛。',32,'全唐诗/poet.tang.42000.json','["秋色西陵滿綠蕪，繁弦急管強歡娛。", "長舒羅袖不成舞，却向風前承淚珠。"]'),
('40804199-70c1-4391-8b58-2ff400bf2d7d','戲示諸妓','張保嗣','唐','唐诗','tang','','[]','綠羅裙上標三棒，紅粉腮邊淚兩行。',32,'全唐诗/poet.tang.42000.json','["綠羅裙上標三棒，紅粉腮邊淚兩行。", "抄手向前咨大使，這回不敢惱兒郎。"]'),
('1d31107b-993b-4d35-b4b2-f570994b8690','末秋到家','潘圖','唐','唐诗','tang','','[]','歸來無所利，骨肉亦不喜。',24,'全唐诗/poet.tang.42000.json','["歸來無所利，骨肉亦不喜。", "黃犬却有情，當門臥搖尾。"]'),
('30f6eca8-526e-4d8c-8d12-8c34f6ffe803','送人往宣城','潘佐','唐','唐诗','tang','','[]','江畔送行人，千山生暮氛。',24,'全唐诗/poet.tang.42000.json','["江畔送行人，千山生暮氛。", "謝安團扇上，爲畫敬亭雲。"]'),
('3f138b05-2a7a-4904-bfce-fd2c558281e0','洛陽河亭奉酬留守郡公追送','李逸','唐','唐诗','tang','','[]','離亭餞落暉，臘酒減征衣。',48,'全唐诗/poet.tang.42000.json','["離亭餞落暉，臘酒減征衣。", "歲晚煙霞重，川寒雲樹微。", "戎裝千里至，舊路十年歸。", "還似汀洲雁，相逢又背飛。"]'),
('a54ed041-c06e-4209-b179-7917fc94e1f2','送道士曾昭瑩','沈麟','唐','唐诗','tang','','[]','南北東西事，人間會也無。',48,'全唐诗/poet.tang.42000.json','["南北東西事，人間會也無。", "昔曾棲玉笥，今也返玄都。", "雪片隨天闊，泉聲落石孤。", "丹霄人有約，去採石菖蒲。"]'),
('e7299df6-2342-4321-b836-2faebbda8eb5','贈別徐侃','安鳳','唐','唐诗','tang','','[]','一自離鄉國，十年在咸秦。',60,'全唐诗/poet.tang.42000.json','["一自離鄉國，十年在咸秦。", "泣盡卞和血，不逢一故人。", "今日舊友別，羞此漂泊身。", "離情吟詩處，麻衣掩淚頻。", "淚別各分袂，且及來年春。"]'),
('5978fe7b-d679-48bb-a306-16e01c80318a','顧城','李倫','唐','唐诗','tang','','[]','世久荒墟在，白雲幾代耕。',48,'全唐诗/poet.tang.42000.json','["世久荒墟在，白雲幾代耕。", "市廛新草綠，里社故煙輕。", "不謹罹天討，來蘇豈忿兵。", "誰云殷鑒遠，今古在人程。"]'),
('39979cce-c52f-4d12-b62d-bcea5d634811','金錢花','盧子發','唐','唐诗','tang','','[]','輪廓休誇四字書，紅窠寫出對庭除。',32,'全唐诗/poet.tang.42000.json','["輪廓休誇四字書，紅窠寫出對庭除。", "時時買得佳人笑，本色金錢却不如。"]'),
('f6868df3-5680-4cab-a889-b7141187f995','故白巖禪師院','王夢周','唐','唐诗','tang','','[]','能師還世名還在，空閉禪堂滿院苔。',32,'全唐诗/poet.tang.42000.json','["能師還世名還在，空閉禪堂滿院苔。", "花樹不隨人寂寞，數株猶自出牆來。"]'),
('80ff687f-e183-4075-9376-872591fd7a31','題九天使者廟','孫咸','唐','唐诗','tang','','[]','獨入玄宮禮至真，焚香不爲賤貧身。',64,'全唐诗/poet.tang.42000.json','["獨入玄宮禮至真，焚香不爲賤貧身。", "秦淮兩岸沙埋骨，湓浦千家血染塵。", "廬阜煙霞誰是主，虎溪風月屬何人。", "九江太守勤王事，好放天兵渡要津。"]'),
('8aaf0c9b-fecf-4183-a50f-b12ce5a46b5f','房公舊竹亭聞琴','李澣','唐','唐诗','tang','','[]','石室寒飆警，孫枝雅器裁。',24,'全唐诗/poet.tang.42000.json','["石室寒飆警，孫枝雅器裁。", "坐來山水操，弦斷弔塵埃。"]'),
('6152ec54-7878-43c5-817b-00f27f4a6598','清溪館作','錢戭','唐','唐诗','tang','','[]','指途清溪裏，左右唯深林。',48,'全唐诗/poet.tang.42000.json','["指途清溪裏，左右唯深林。", "雲蔽望鄉處，雨愁爲客心。", "遇人多物役，聽鳥時幽音。", "何必滄浪水，庶茲浣塵襟。"]'),
('dbe9f655-b81e-4af2-a281-f400670cc02c','晚春宴','韋道遜','唐','唐诗','tang','','[]','日斜賓館晚，春輕麥候初。',48,'全唐诗/poet.tang.42000.json','["日斜賓館晚，春輕麥候初。", "簾暄巢幕燕，池躍戲蓮魚。", "石聲隨流響，桐影傍巖疎。", "誰能千里外，獨寄八行書。"]'),
('cd504159-7ef5-40f8-a723-947b7b40fb2d','長沙六快詩','王揆','唐','唐诗','tang','','[]','湖外風物奇，長沙信難續。',156,'全唐诗/poet.tang.42000.json','["湖外風物奇，長沙信難續。", "衡峰排古青，湘水湛寒綠。", "舟檝通大江，車輪會平陸。", "昔賢官是邦，仁澤流豐沃。", "今賢官是邦，刳啗人脂肉。", "懷昔甘棠花，傷今猛虎毒。", "然此一郡內，所樂人纔六。", "漕與二憲僚，守連兩通屬。", "高堂日暮會，深夜繼以燭。", "幃幕皆綺紈，器皿盡金玉。", "歌喉若珠纍，舞腰如素束。", "千態與萬狀，六人歡不足。", "因成快活詩，薦之堯舜目。"]'),
('a9f20d8a-8c7b-4a45-b3d1-fd60e1503be2','廣州王園寺伏日即事寄北中親友','王言史','唐','唐诗','tang','','[]','南越逢初伏，東林度一朝。',120,'全唐诗/poet.tang.43000.json','["南越逢初伏，東林度一朝。", "曲池煎畏景，高閣絕微飆。", "竹簟移先灑，蒲葵破復搖。", "地偏毛瘴近，山毒火威饒。", "裛汗絺如濯，親牀枕並燒。", "墮枝傷翠羽，萎葉惜紅蕉。", "且困流金熾，難成獨酌謠。", "望霖窺潤礎，思吹候纖條。", "旅恨生烏滸，鄉心繫浴橋。", "誰憐在炎客，一夕壯容銷。"]'),
('d8146e42-2d5a-4ccc-b11c-f5613ae37f60','春日','宋雍','唐','唐诗','tang','','[]','輕花細葉滿林端，昨夜春風曉色寒。',32,'全唐诗/poet.tang.43000.json','["輕花細葉滿林端，昨夜春風曉色寒。", "黃鳥不堪愁裏聽，綠楊宜向雨中看。"]'),
('df743a74-b342-4642-9bcb-3efccd54202d','失題','宋雍','唐','唐诗','tang','','[]','斜雨飛絲織晚風，疎簾半捲野亭空。',32,'全唐诗/poet.tang.43000.json','["斜雨飛絲織晚風，疎簾半捲野亭空。", "荷花開盡秋光晚，零落殘紅綠沼中。"]'),
('7d2b0970-93d5-4f0c-bdeb-6cbd94f546f2','古意','戴休珽','唐','唐诗','tang','','[]','窮秋朔風起，滄海愁陰漲。',96,'全唐诗/poet.tang.43000.json','["窮秋朔風起，滄海愁陰漲。", "虜騎掠河南，漢兵屯灞上。", "羽書驚沙漠，刁斗喧亭障。", "關塞何蒼茫，遙烽遞相望。", "弱齡負奇節，俠客多招訪。", "投筆棄繻生，提戈逐飛將。", "拔劒照霜白，怒髮衝冠壯。", "會立萬里功，視君封侯相。"]'),
('ccf41249-0d03-4746-a375-f3ba7ee82f60','勗曹生','盧鉟','唐','唐诗','tang','','[]','桑扈交飛百舌忙，祖亭聞樂倍思鄉。',64,'全唐诗/poet.tang.43000.json','["桑扈交飛百舌忙，祖亭聞樂倍思鄉。", "尊前有恨慚卑宦，席上無憀愛豔妝。", "莫爲狂花迷眼界，須求真理定心王。", "遊蜂採掇何時已，祗恐多言議短長。"]'),
('4b07aeac-f930-4400-a3d7-7deabcaa3e7a','琴歌','趙摶','唐','唐诗','tang','','[]','綠琴製自桐孫枝，十年窗下無人知。',256,'全唐诗/poet.tang.43000.json','["綠琴製自桐孫枝，十年窗下無人知。", "清聲不與衆樂雜，所以屈受塵埃欺。", "七弦脆斷蟲絲朽，辨別不曾逢好手。", "琴聲若似琵琶聲，賣與時人應已久。", "玉徽冷落無光彩，堪恨鍾期不相待。", "鳳囀吟幽鶴舞時，撚弄錚摐聲亦在。", "向曾守貧貧不徹，賤價與人人不別。", "前迴忍淚却收來，泣向秋風兩條血。", "乃知凡俗難可名，輕者却重重者輕。", "真龍不聖土龍聖，鳳皇啞舌鴟梟鳴。", "何殊此琴哀怨苦，寂寞沈埋在幽戶。", "萬重山水不肯聽，俗耳樂聞人打鼓。", "知君立身待分義，驅喝風雷在平地。", "一生從事不因人，健步窣雲皆自致。", "不辭重拂弦上塵，市廛不買多讒人。", "莫辭憔悴與買取，爲君一曲號青春。"]'),
('3d7184e0-8b1d-4b69-907c-48183d821421','廢長行','趙摶','唐','唐诗','tang','','[]','紫牙鏤合方如斗，二十四星銜月口。',144,'全唐诗/poet.tang.43000.json','["紫牙鏤合方如斗，二十四星銜月口。", "貴人迷此華筵中，運木手交如陣鬬。", "不算勞神運枯木，且廢爲官恤惸獨。", "門前有吏嚇孤窮，欲訴門深抱冤哭。", "耳厭人催坐衙早，纔聞此戲身先到。", "理人似愛長行心，天下安平多草草。", "何當化局爲明鏡，挂在高堂辨邪正。", "何當化子作筆鋒，常在手中行法令。", "莫令終日迷如此，不治生民負天子。"]'),
('2c6601d0-9053-4397-a4bd-1e4a4b5b85ef','玉女詞','張安石','唐','唐诗','tang','','[]','綺薦銀屏空積塵，柳眉桃臉暗銷春。',32,'全唐诗/poet.tang.43000.json','["綺薦銀屏空積塵，柳眉桃臉暗銷春。", "不須更學陽臺女，爲雨爲雲趁惱人。"]'),
('dd4423fe-73f6-40aa-8ac7-3649bfafbeeb','苦別','張安石','唐','唐诗','tang','','[]','向前不信別離苦，而今自到別離處。',32,'全唐诗/poet.tang.43000.json','["向前不信別離苦，而今自到別離處。", "兩行粉淚紅闌干，一朵芙蕖帶殘露。"]'),
('833d7c10-b5e7-45e4-a53e-80ab372f3f28','石城','蔣吉','唐','唐诗','tang','','[]','繫纜石城下，恣吟懷暫開。',24,'全唐诗/poet.tang.43000.json','["繫纜石城下，恣吟懷暫開。", "江人橈艇子，將謂莫愁來。"]'),
('380183a0-f8cb-4af7-b10e-1020bf3aff0d','漢東道中','蔣吉','唐','唐诗','tang','','[]','九十九岡遙，天寒雪未消。',24,'全唐诗/poet.tang.43000.json','["九十九岡遙，天寒雪未消。", "羸童牽瘦馬，不敢過危橋。"]'),
('291ee704-2de1-46da-8cb1-f10e0ce76806','高溪有懷','蔣吉','唐','唐诗','tang','','[]','駐馬高溪側，旅人千里情。',24,'全唐诗/poet.tang.43000.json','["駐馬高溪側，旅人千里情。", "雁山山下水，還作此泉聲。"]'),
('478f129b-206f-4716-9eff-57a13e2303fc','寄進士賈希','蔣吉','唐','唐诗','tang','','[]','恨苦淚不落，耿然東北心。',24,'全唐诗/poet.tang.43000.json','["恨苦淚不落，耿然東北心。", "空囊與瘦馬，羈紲意應深。"]'),
('aaf76ba3-d84f-4d36-a605-43cb7d38ef8c','出塞','蔣吉','唐','唐诗','tang','','[]','瘦馬羸童行背秦，暮鴉撩亂入殘雲。',32,'全唐诗/poet.tang.43000.json','["瘦馬羸童行背秦，暮鴉撩亂入殘雲。", "北風吹起寒營角，直至榆關人盡聞。"]'),
('1b21949d-9d1a-40e7-9059-f929452d824f','旅泊','蔣吉','唐','唐诗','tang','','[]','霜月正高鸚鵡洲，美人清唱發紅樓。',32,'全唐诗/poet.tang.43000.json','["霜月正高鸚鵡洲，美人清唱發紅樓。", "鄉心暗逐秋江水，直到吳山脚下流。"]'),
('1adbbffb-98b2-40f5-bfcd-750aeb36e03b','次青雲驛','蔣吉','唐','唐诗','tang','','[]','馬轉櫟林山鳥飛，商溪流水背殘暉。',32,'全唐诗/poet.tang.43000.json','["馬轉櫟林山鳥飛，商溪流水背殘暉。", "行人幾在青雲路，底事風塵猶滿衣。"]'),
('ddd1f0b9-4bf3-4493-ac14-8dea55f51125','大庾驛有懷','蔣吉','唐','唐诗','tang','','[]','一囊書重百餘斤，郵吏寧知去計貧。',32,'全唐诗/poet.tang.43000.json','["一囊書重百餘斤，郵吏寧知去計貧。", "莫訝偏吟望鄉句，明朝便見嶺南人。"]'),
('1afcdfd1-60bb-4ac5-995a-c3aa2e9a4fb3','題商山修路僧院','蔣吉','唐','唐诗','tang','','[]','此地修行山幾枯，草堂生計只缾盂。',32,'全唐诗/poet.tang.43000.json','["此地修行山幾枯，草堂生計只缾盂。", "支郎既解除艱險，試看人心平得無。"]'),
('d4a889da-4afe-4e6e-9986-c306c4e1d1a2','題長安僧院','蔣吉','唐','唐诗','tang','','[]','出門爭走九衢塵，總是浮生不了身。',32,'全唐诗/poet.tang.43000.json','["出門爭走九衢塵，總是浮生不了身。", "惟有水田衣下客，大家忙處作閑人。"]'),
('81b5e3ea-b813-4432-96d7-5b994d1f8b30','次商於感舊寄盧中丞','蔣吉','唐','唐诗','tang','','[]','昔年簪組隘丘門，今日旌幢一院存。',32,'全唐诗/poet.tang.43000.json','["昔年簪組隘丘門，今日旌幢一院存。", "何事商於淚如雨，小儒偏受陸家恩。"]'),
('8aa23bb2-fb7c-47dc-a33e-edc077ad85ac','樵翁','蔣吉','唐','唐诗','tang','','[]','獨入深山信脚行，慣當貙虎不曾驚。',32,'全唐诗/poet.tang.43000.json','["獨入深山信脚行，慣當貙虎不曾驚。", "路傍花發無心看，惟見枯枝刮眼明。"]'),
('633bc9bc-aa49-408a-8ef6-c4e406aa8ee9','四老廟','蔣吉','唐','唐诗','tang','','[]','無端捨釣學干名，不得溪山養性情。',32,'全唐诗/poet.tang.43000.json','["無端捨釣學干名，不得溪山養性情。", "自省此身非達者，今朝羞拜四先生。"]'),
('cbb549dc-31b0-42d9-8de3-be362e441c24','昭君冢','蔣吉','唐','唐诗','tang','','[]','曾爲漢帝眼中人，今作狂胡陌上塵。',32,'全唐诗/poet.tang.43000.json','["曾爲漢帝眼中人，今作狂胡陌上塵。", "身死不知多少載，冢花猶帶洛陽春。"]'),
('1cf1ba9e-bbd1-4a60-a8bd-76dbf1e22228','聞歌竹枝','蔣吉','唐','唐诗','tang','','[]','巡隄聽唱竹枝詞，正是月高風靜時。',32,'全唐诗/poet.tang.43000.json','["巡隄聽唱竹枝詞，正是月高風靜時。", "獨向東南人不會，弟兄俱在楚江湄。"]'),
('fc9aad69-b497-4a6f-a97f-a039c841b027','重門曲','周濆','唐','唐诗','tang','','[]','憔悴容華怯對春，寂寥宮殿鎖閑門。',32,'全唐诗/poet.tang.43000.json','["憔悴容華怯對春，寂寥宮殿鎖閑門。", "此身却羨宮中樹，不失芳時雨露恩。"]'),
('ea6a50b3-b02a-4b58-a98b-a6704de4e393','山下水','周濆','唐','唐诗','tang','','[]','背雲衝石出深山，淺碧泠泠一帶寒。',32,'全唐诗/poet.tang.43000.json','["背雲衝石出深山，淺碧泠泠一帶寒。", "不獨有聲流出此，會歸滄海助波瀾。"]'),
('1e7b5d31-6e9c-4e59-b2da-c14e61c27fb0','逢鄰女','周濆','唐','唐诗','tang','','[]','日高鄰女笑相逢，慢束羅裙半露胸。',32,'全唐诗/poet.tang.43000.json','["日高鄰女笑相逢，慢束羅裙半露胸。", "莫向秋池照綠水，參差羞殺白芙蓉。"]'),
('97c1f609-4fa5-4b40-a981-9bf5a28fda04','廢宅','周濆','唐','唐诗','tang','','[]','牢落畫堂空鎖塵，荒涼庭樹暗消春。',32,'全唐诗/poet.tang.43000.json','["牢落畫堂空鎖塵，荒涼庭樹暗消春。", "豪家莫笑此中事，曾見此中人笑人。"]'),
('0e852d14-b9f0-4927-aabf-fbdfd5fe927c','奉和登會昌山應制','趙起','唐','唐诗','tang','','[]','睿想入希夷，真游到具茨。',48,'全唐诗/poet.tang.43000.json','["睿想入希夷，真游到具茨。", "玉鸞登嶂遠，雲輅出花遲。", "泉壑凝神處，陽和布澤時。", "六龍多順動，四海正雍熙。"]'),
('b8bc15ae-fde4-4f10-be54-1e5bb51fcf48','冬日與羣公泛舟焦山 一','王瓚','唐','唐诗','tang','','[]','江外水不凍，今年寒復遲。',96,'全唐诗/poet.tang.43000.json','["江外水不凍，今年寒復遲。", "衆芳且未歇，近臘仍裌衣。", "載酒適我情，興來趣漸微。", "方舟大川上，環酌對落暉。", "兩片青石稜，波際無因依。", "三山安可到，欲到風引歸。", "滄溟壯觀多，心目豁暫時。", "況得窮日夕，乘槎何所之。"]'),
('4f91c2a3-fa44-439f-85fe-efbfc11f1ecb','冬日與羣公泛舟焦山 二','王瓚','唐','唐诗','tang','','[]','縱步不知遠，夕陽猶未回。',24,'全唐诗/poet.tang.43000.json','["縱步不知遠，夕陽猶未回。", "好花隨處發，流水趂人來。"]'),
('3e01c32e-bf5c-4021-9199-6ed20c0067ba','度揭鴻嶺','慕容韋','唐','唐诗','tang','','[]','閩越曾爲塞，將軍舊置營。',24,'全唐诗/poet.tang.43000.json','["閩越曾爲塞，將軍舊置營。", "我歌空感慨，西北望神京。"]'),
('050b4047-5141-4db7-b833-b248311b3835','湘江','黃文','唐','唐诗','tang','','[]','瀟湘江頭三月春，柳條弄日搖黃金。',64,'全唐诗/poet.tang.43000.json','["瀟湘江頭三月春，柳條弄日搖黃金。", "鷓鴣一聲在何許，黃陵廟前煙靄深。", "丹青欲畫無好手，穩提玉勒沈吟久。", "馬蹄不爲行客留，心挂長林屢回首。"]'),
('c98865db-762f-4349-a0d6-e5ca98f89a3f','題龍陽縣青草湖','唐溫如','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','西風吹老洞庭波，一夜湘君白髮多。',32,'全唐诗/poet.tang.43000.json','["西風吹老洞庭波，一夜湘君白髮多。", "醉後不知天在水，滿船清夢壓星河。"]'),
('75e715ed-9d82-4a58-ade6-b788aba2abcb','訾家洲','歐陽賓','唐','唐诗','tang','','[]','舊業分明桂水頭，人歸業盡水東流。',32,'全唐诗/poet.tang.43000.json','["舊業分明桂水頭，人歸業盡水東流。", "春風日暮江頭立，不及漁人有釣舟。"]'),
('1e139d0b-02e2-4f95-bb55-bfcadc917690','題吉州龍溪','何敬','唐','唐诗','tang','','[]','龍溪之山秀而峙，龍溪之水清無底。',64,'全唐诗/poet.tang.43000.json','["龍溪之山秀而峙，龍溪之水清無底。", "狂風激烈翻春濤，薄霧冥濛溢清泚。", "奔流百折銀河通，落花滾滾浮霞紅。", "四時佳境不可窮，彷彿直與桃源通。"]'),
('03c7e05b-0eee-4e44-badf-ac6d2ee11f0f','過睦州青溪渡','楊彝','唐','唐诗','tang','','[]','天闊銜江雨，冥冥上客衣。',48,'全唐诗/poet.tang.43000.json','["天闊銜江雨，冥冥上客衣。", "潭清魚可數，沙晚鴈爭飛。", "川谷留雲氣，鵜鶘傍釣磯。", "瓢零江海客，欹側一帆歸。"]'),
('12f8b1da-1e9b-4284-b46f-17c85d56c973','闔閭城懷古','裴瑤','唐','唐诗','tang','','[]','五湖春水接遙天，國破君亡不記年。',32,'全唐诗/poet.tang.43000.json','["五湖春水接遙天，國破君亡不記年。", "惟有妖娥曾舞處，古臺寂寞起愁煙。"]'),
('8d99e05a-4f8b-43a5-bb47-2616466e0f7a','葦谷','鄭玉','唐','唐诗','tang','','[]','水會三川漾碧波，雕陰人唱採花歌。',32,'全唐诗/poet.tang.43000.json','["水會三川漾碧波，雕陰人唱採花歌。", "舊時白翟今荒壤，葦谷淒淒風雨多。"]'),
('5dead6b4-9462-4e8c-9e70-cd1801b9eab8','登岳陽樓','麻溫其','唐','唐诗','tang','','["\u5cb3\u9633\u697c"]','湖邊景物屬秋天，樓上風光似去年。',64,'全唐诗/poet.tang.43000.json','["湖邊景物屬秋天，樓上風光似去年。", "仙侶緱生留福地，湘娥帝子寄哀弦。", "雲門自統軒臺外，木葉偏飛楚客前。", "極目江山何處是，一帆萬里信歸船。"]'),
('9c1a26d1-67b6-4517-aec7-c230ccbd1ffa','經望湖驛','韋鎰','唐','唐诗','tang','','[]','大漠無屯雲，孤峰出亂柳。',120,'全唐诗/poet.tang.43000.json','["大漠無屯雲，孤峰出亂柳。", "前驅白登道，顧失飛狐口。", "遙憶代王城，俯臨恆山後。", "纍纍多古墓，寂寞爲墟久。", "豈不固金湯，終聞擊銅斗。", "交懽初仗信，接讌翻貽咎。", "埋寶賊夫人，磨笄傷彼婦。", "功成行且薄，義立名不朽。", "莫慎纖微端，其何社稷守。", "身歿國遂亡，此立人君醜。"]'),
('1fab37a8-b460-4592-acf6-bc0eefd81cc9','杪秋洞庭懷王道士','謝太虛','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','漂泊日復日，洞庭今更秋。',96,'全唐诗/poet.tang.43000.json','["漂泊日復日，洞庭今更秋。", "青桃亦何意，此夜催人愁。", "惆悵客中月，裴回江上樓。", "心知楚天遠，目送滄波流。", "謝客久已滅，微言無處求。", "空餘白雲在，客興隨孤舟。", "千里杳難盡，一身常獨游。", "故園復何許，江漢徒遲留。"]'),
('5e35a9f8-f951-4d7c-8f99-b967ce7a2df4','君山祠','周岳秀','唐','唐诗','tang','','[]','萬頃湖波浸碧天，旌封香火幾千年。',64,'全唐诗/poet.tang.43000.json','["萬頃湖波浸碧天，旌封香火幾千年。", "風濤澎湃魚龍舞，棟宇崢嶸燕雀遷。", "遠岫光中濃淡樹，斜陽影裏往來船。", "江河願借吹噓便，應有神功在目前。"]'),
('332bfe21-dd40-4029-8434-51ea87f16771','新樂府','馬逢','唐','唐诗','tang','','[]','溫谷春生至，宸遊近甸榮。',48,'全唐诗/poet.tang.43000.json','["溫谷春生至，宸遊近甸榮。", "雲隨天上轉，風入御筵輕。", "翠蓋浮佳氣，朱樓依太清。", "朝臣冠劒退，宮女管弦迎。"]'),
('38acf987-857b-457e-8324-a538baf0473c','部落曲','馬逢','唐','唐诗','tang','','[]','蕃軍傍塞遊，代馬噴風秋。',48,'全唐诗/poet.tang.43000.json','["蕃軍傍塞遊，代馬噴風秋。", "老將垂金甲，閼支著錦裘。", "琱戈蒙豹尾，紅斾插狼頭。", "日暮天山下，鳴笳漢使愁。"]'),
('8d552771-d4db-41a9-9314-98c83f89bde9','從軍','馬逢','唐','唐诗','tang','','[]','漢馬千蹄合一羣，單于鼓角隔山聞。',32,'全唐诗/poet.tang.43000.json','["漢馬千蹄合一羣，單于鼓角隔山聞。", "沙塠風起紅樓下，飛上胡天作陣雲。"]'),
('216b73fe-f9f6-444b-a570-f7f37f0421e2','宮詞二首 一','馬逢','唐','唐诗','tang','','[]','金吾持戟護軒簷，天樂傳教萬姓瞻。',32,'全唐诗/poet.tang.43000.json','["金吾持戟護軒簷，天樂傳教萬姓瞻。", "樓上美人相倚看，紅妝透出水晶簾。"]'),
('2c2b3f90-f45a-40f8-a872-d5e8c1d962ae','宮詞二首 二','馬逢','唐','唐诗','tang','','[]','玉樓天半起笙歌，風送宮人笑語和。',32,'全唐诗/poet.tang.43000.json','["玉樓天半起笙歌，風送宮人笑語和。", "月影殿開聞曉漏，水晶簾捲近秋河。"]'),
('8e4fd288-3692-4d5a-bbc6-e9ed86584c1b','長門失寵','蕭意','唐','唐诗','tang','','[]','自從別鑾殿，長門幾度春。',24,'全唐诗/poet.tang.43000.json','["自從別鑾殿，長門幾度春。", "不知金屋裏，更貯若爲人。"]'),
('f89e3741-8dc3-413e-94e5-bbee754eb43a','下山逢故夫','徐之才','唐','唐诗','tang','','[]','踟躕下山婦，共申別離久。',24,'全唐诗/poet.tang.43000.json','["踟躕下山婦，共申別離久。", "爲問織縑人，何必長相守。"]'),
('7950d906-83ad-4868-83dd-f043f4545fc3','虜患','張陵','唐','唐诗','tang','','[]','今日漢家探使迴，蟻疊胡兵來未歇。',32,'全唐诗/poet.tang.43000.json','["今日漢家探使迴，蟻疊胡兵來未歇。", "春風渭水不敢流，總作六軍心上血。"]'),
('2401de54-8072-4143-89a6-c42b91acc0f7','夏日閨怨','蔡瓌','唐','唐诗','tang','','[]','桃徑李蹊絕芳園，炎氛熾日滿愁軒。',160,'全唐诗/poet.tang.43000.json','["桃徑李蹊絕芳園，炎氛熾日滿愁軒。", "枝上鳥驚朱槿落，池中魚戲綠蘋翻。", "君戀京師久留滯，妾怨高樓積年歲。", "非關曾入楚王宮，直爲相思腰轉細。", "臥簟乘閑乍逐涼，熏爐畏熱嬾焚香。", "雨霑柳葉如啼眼，露滴蓮花似汗妝。", "全由獨自羞看影，豔是孤眠疑夜永。", "無情拂鏡不成妝，有時却扇還風靜。", "近日書來道欲歸，鴛鴦文錦字息機。", "但恐愁容不相識，爲教恆著別時衣。"]'),
('122b367c-2425-4692-a76d-d59def95cec8','詠破扇','唐怡','唐','唐诗','tang','','[]','輪如明月盡，羅似薄雲穿。',24,'全唐诗/poet.tang.43000.json','["輪如明月盡，羅似薄雲穿。", "無由重掩笑，分在秋風前。"]'),
('9f0bc11b-7cd5-4952-b53e-237efceffed9','述懷','唐怡','唐','唐诗','tang','','[]','萬事皆零落，平生不可思。',24,'全唐诗/poet.tang.43000.json','["萬事皆零落，平生不可思。", "惟餘酒中趣，不減少年時。"]'),
('4bb18d0d-45f9-4cab-b16b-e132be9286c9','詠燭寄人','潘求仁','唐','唐诗','tang','','[]','燭與人相似，通宵遽白煎。',24,'全唐诗/poet.tang.43000.json','["燭與人相似，通宵遽白煎。", "不應須下淚，祗是爲人然。"]'),
('1f743f30-6678-4ce6-82de-3c7d5a445313','薛王花燭行','閻德隱','唐','唐诗','tang','','[]','王子仙車下鳳臺，紫纓金勒馭龍媒。',224,'全唐诗/poet.tang.43000.json','["王子仙車下鳳臺，紫纓金勒馭龍媒。", "□□□□□□出，環佩鏘鏘天上來。", "鳷鵲樓前雲半捲，鴛鴦殿上月裴回。", "玉盤錯落銀燈照，珠帳𤫩瓏寶扇開。", "盈盈二八誰家子，紅粉新妝勝桃李。", "從來六行比齊姜，自許千門奉楚王。", "楚王宮裏能服飾，顧盼傾城復傾國。", "合歡錦帶蒲萄花，連理香裙石榴色。", "金爐半夜起氛氳，翡翠被重蘇合熏。", "不學曹王遇神女，莫言羅敷邀使君。", "同心婉娩若琴瑟，更笑天河有靈匹。", "一朝福履盛王門，百代光輝增帝室。", "富貴榮華實可憐，路傍觀者謂神仙。", "祗應早得淮南術，會見雙飛入紫煙。"]'),
('751b7f22-75a0-4c36-88a5-4fa0f0d189a0','三月歌','閻德隱','唐','唐诗','tang','','[]','洛陽城路九春衢，洛陽城外柳千株。',32,'全唐诗/poet.tang.43000.json','["洛陽城路九春衢，洛陽城外柳千株。", "能得來時作眼覓，天津橋側錦屠蘇。"]'),
('e00a5c52-f109-4e69-8ef7-edbfc736c799','妾薄命','劉元叔','唐','唐诗','tang','','[]','自從離別守空閨，遙聞征戰赴雲梯。',192,'全唐诗/poet.tang.43000.json','["自從離別守空閨，遙聞征戰赴雲梯。", "夜夜思君遼海北，年年棄妾渭橋西。", "陽春白日照空暖，紫燕銜花向庭滿。", "彩鸞琴裏怨聲多，飛鵲鏡前妝梳斷。", "誰家夫壻不從征，應是漁陽別有情。", "莫道紅顏燕地少，家家還似洛陽城。", "旦逐新人殊未歸，還令秋至夜霜飛。", "北斗星前橫旅鴈，南樓月下擣寒衣。", "夜深聞鴈腸欲絕，獨坐縫衣燈又滅。", "暗啼羅帳空自憐，夢度陽關向誰說。", "每憐容貌宛如神，如何薄命不如人。", "待君朝夕燕山至，好作明年楊柳春。"]'),
('8923c73c-a3e2-46d5-88f2-b1cf9a631b74','古別離','常理','唐','唐诗','tang','','[]','君御狐白裘，妾居緗綺幬。',72,'全唐诗/poet.tang.43000.json','["君御狐白裘，妾居緗綺幬。", "粟鈿金夾膝，花錯玉搔頭。", "離別生庭草，征衣斷戍樓。", "蠨蛸網清曙，菡萏落紅秋。", "小膽空房怯，長眉滿鏡愁。", "爲傳兒女意，不用遠封侯。"]'),
('837d7051-f496-434f-b606-59bef749f048','妾薄命','常理','唐','唐诗','tang','','[]','十五玉童色，雙蛾青彎彎。',92,'全唐诗/poet.tang.43000.json','["十五玉童色，雙蛾青彎彎。", "鳥銜櫻桃花，此時刺繡閑。", "嬌小恣所愛，誤人金指環。", "豔花句引落，滅燭屏風關。", "妾怕愁中畫，君偷薄裏還。", "初謂來心平若案，誰知別意險如山。", "乍啼羅袖嬌遮面，不忍看君莫惜顏。"]'),
('1e91c2a3-f175-4e34-a97f-7aef63499698','虞姬怨','馮待徵','唐','唐诗','tang','','[]','妾本江南采蓮女，君是江東學劒人。',224,'全唐诗/poet.tang.43000.json','["妾本江南采蓮女，君是江東學劒人。", "逢君游俠英雄日，值妾年華桃李春。", "年華灼灼豔桃李，結髮簪花配君子。", "行逢楚漢正相持，辭家上馬從君起。", "歲歲年年事征戰，侍君帷幕損紅顏。", "不惜羅衣沾馬汗，不辭紅粉著刀環。", "相期相許定關中，鳴鑾鳴佩入秦宮。", "誰誤四面楚歌起，果知五星漢道雄。", "天時人事有興滅，智窮計屈心摧折。", "澤中馬力先戰疲，帳下蛾眉□□□。", "君王是日無神彩，賤妾此時容貌改。", "拔山意氣都已無，渡江面目今何在。", "終天隔地與君辭，恨似流波無息時。", "使妾本來不相識，豈見中途懷苦悲。"]'),
('49c1c2d5-918c-49a6-993d-64d823d54761','越谿怨','冷朝光','唐','唐诗','tang','','[]','越王宮裏如花人，越水谿頭采白蘋。',32,'全唐诗/poet.tang.43000.json','["越王宮裏如花人，越水谿頭采白蘋。", "白蘋未盡人先盡，誰見江南春復春。"]'),
('f2a99f66-7b2b-4b4f-9261-f8adaaace3ef','吳宮怨','衛萬','唐','唐诗','tang','','[]','君不見吳王宮閣臨江起，不見珠簾見江水。',67,'全唐诗/poet.tang.43000.json','["君不見吳王宮閣臨江起，不見珠簾見江水。", "曉氣晴來雙闕間，潮聲夜落千門裏。", "句踐城中非舊春，姑蘇臺下起黃塵。", "祗今唯有西江月，曾照吳王宮裏人。"]'),
('f83fac16-7b3e-4cfb-8744-0b76bc5a023f','春游吟','李章','唐','唐诗','tang','','[]','初春徧芳甸，十里藹盈矚。',52,'全唐诗/poet.tang.43000.json','["初春徧芳甸，十里藹盈矚。", "美人摘新英，步步翫春綠。", "所思杳何處，宛在吳江曲。", "可憐不得共芳菲，日暮歸來淚滿衣。"]'),
('0a7ec794-d196-4f0d-b07f-efaf5b13e97e','婕妤怨','王沈','唐','唐诗','tang','','[]','長信梨花暗欲棲，應門上鑰草萋萋。',34,'全唐诗/poet.tang.43000.json','["長信梨花暗欲棲，應門上鑰草萋萋。", "春風吹花亂撲戶，[班]絕車聲不至啼。"]'),
('915851e4-c9a8-4631-9179-8ccaac52ff41','夜夜曲','王偃','唐','唐诗','tang','','[]','北斗星移銀漢低，班姬愁思鳳城西。',32,'全唐诗/poet.tang.43000.json','["北斗星移銀漢低，班姬愁思鳳城西。", "青槐陌上行人絕，明月樓前烏夜啼。"]'),
('53f0639b-6b8d-4878-86fe-d900ee87fe42','明君詞','王偃','唐','唐诗','tang','','["\u9ec4\u6cb3"]','北望單于日半斜，明君馬上泣胡沙。',32,'全唐诗/poet.tang.43000.json','["北望單于日半斜，明君馬上泣胡沙。", "一雙淚滴黃河水，應得東流入漢家。"]'),
('991e24b9-eaf2-466d-91af-dff38b9283cd','擬古東飛伯勞歌','李暇','唐','唐诗','tang','','[]','秦王龍劒燕后琴，珊瑚寶匣鏤雙心。',80,'全唐诗/poet.tang.43000.json','["秦王龍劒燕后琴，珊瑚寶匣鏤雙心。", "誰家女兒抱香枕，開衾滅燭願侍寢。", "瓊窗半上金鏤幬，輕羅掩面不遮羞。", "青綺幃中坐相憶，紅鸞鏡裏見愁色。", "簷花照月鶯對棲，空將可憐暗中啼。"]'),
('7debe622-91bb-4f76-acfa-7652ced1ec2d','怨詩三首 一','李暇','唐','唐诗','tang','','[]','羅敷初總髻，蕙芳正嬌小。',24,'全唐诗/poet.tang.43000.json','["羅敷初總髻，蕙芳正嬌小。", "月落始歸船，春眠恆著曉。"]'),
('41f0d6a0-e797-44cd-a1a6-eb7b728e4722','怨詩三首 二','李暇','唐','唐诗','tang','','[]','何處期郎遊，小苑花臺間。',24,'全唐诗/poet.tang.43000.json','["何處期郎遊，小苑花臺間。", "相憶不可見，且復乘月還。"]'),
('1be94263-6da2-4941-957f-916e7aa92383','怨詩三首 三','李暇','唐','唐诗','tang','','[]','別前花照路，別後露垂葉。',24,'全唐诗/poet.tang.43000.json','["別前花照路，別後露垂葉。", "歌舞須及時，如何坐悲妾。"]'),
('942432cd-6095-423f-8923-fbb37c74e265','碧玉歌','李暇','唐','唐诗','tang','','[]','碧玉上官妓，出入千花林。',24,'全唐诗/poet.tang.43000.json','["碧玉上官妓，出入千花林。", "珠被玳瑁牀，感郎情意深。"]'),
('f23f7a83-bdb1-4f30-a69b-1ba8f97fa81b','見美人聞琴不聽','李播','唐','唐诗','tang','','[]','洛浦風流雪，陽臺朝暮雲。',24,'全唐诗/poet.tang.43000.json','["洛浦風流雪，陽臺朝暮雲。", "聞琴不肯聽，似妒卓文君。"]'),
('bc69461b-eb7c-4a52-9050-e5aaa2bba17a','賦詩','辛弘智','唐','唐诗','tang','','[]','君爲河邊草，逢春心剩生。',24,'全唐诗/poet.tang.43000.json','["君爲河邊草，逢春心剩生。", "妾如臺上鏡，得照始分明。"]'),
('03365949-e73b-49e1-b5c1-3de14cc2eaa9','自君之出矣','辛弘智','唐','唐诗','tang','','["\u95fa\u6028", "\u76f8\u601d", "\u5987\u5973", "\u4e50\u5e9c"]','自君之出矣，梁塵靜不飛。',24,'全唐诗/poet.tang.43000.json','["自君之出矣，梁塵靜不飛。", "思君如滿月，夜夜減容輝。"]'),
('785a7173-4151-4402-b93b-482fa27f2391','又自君之出矣','辛弘智','唐','唐诗','tang','','["\u601d\u5ff5", "\u4e50\u5e9c"]','自君之出矣，寶鏡爲誰明。',24,'全唐诗/poet.tang.43000.json','["自君之出矣，寶鏡爲誰明。", "思君如隴水，常聞嗚咽聲。"]'),
('797f4c02-692a-4ff2-a964-e6561b3eb802','題春夢秋歸故里','吉師老','唐','唐诗','tang','','[]','故國歸路賒，春晚在天涯。',48,'全唐诗/poet.tang.43000.json','["故國歸路賒，春晚在天涯。", "明月夜來夢，碧山秋到家。", "開窗聞落葉，遠墅見晴鴉。", "驚起曉庭際，鶯啼桃杏花。"]'),
('2574727e-02c7-4b65-b1bc-2f23c1777235','看蜀女轉昭君變','吉師老','唐','唐诗','tang','','[]','妖姬未著石榴裠，自道家連錦水濆。',64,'全唐诗/poet.tang.43000.json','["妖姬未著石榴裠，自道家連錦水濆。", "檀口解知千載事，清詞堪歎九秋文。", "翠眉顰處楚邊月，畫卷開時塞外雲。", "說盡綺羅當日恨，昭君傳意向文君。"]'),
('2c77c48d-9a3c-4bc7-8a2b-565214e334b3','放猨','吉師老','唐','唐诗','tang','','[]','放爾千山萬水身，野泉晴樹好爲鄰。',32,'全唐诗/poet.tang.43000.json','["放爾千山萬水身，野泉晴樹好爲鄰。", "啼時莫近瀟湘岸，明月孤舟有旅人。"]'),
('132e2505-fc0e-4073-82a9-bbf6d17337e2','鴛鴦','吉師老','唐','唐诗','tang','','[]','江島濛濛煙靄微，綠蕪深處刷毛衣。',32,'全唐诗/poet.tang.43000.json','["江島濛濛煙靄微，綠蕪深處刷毛衣。", "渡頭驚起一雙去，飛上文君舊錦機。"]'),
('f1b7e6e9-8eb9-4bf8-baac-678c6a4ef6dd','巫峽聽猿','吳商浩','唐','唐诗','tang','','[]','巴江猨嘯苦，響入客舟中。',48,'全唐诗/poet.tang.43000.json','["巴江猨嘯苦，響入客舟中。", "孤枕破殘夢，三聲隨曉風。", "連雲波澹澹，和霧雨濛濛。", "巫峽去家遠，不堪魂斷空。"]'),
('0350e624-409a-4f2d-b527-3addb1a1063d','長安春贈友人','吳商浩','唐','唐诗','tang','','[]','繁華堪泣帝城春，粉堞青樓勢礙雲。',64,'全唐诗/poet.tang.43000.json','["繁華堪泣帝城春，粉堞青樓勢礙雲。", "花對玉鉤簾外發，歌飄塵土路邊聞。", "幾多遠客魂空斷，何處王孫酒自醺。", "各有歸程千萬里，東風時節恨離羣。"]'),
('dc6e570e-5d4f-48d2-9692-dc8f9a20f72b','塞上即事','吳商浩','唐','唐诗','tang','','[]','身似星流跡似蓬，玉關孤望杳溟濛。',64,'全唐诗/poet.tang.43000.json','["身似星流跡似蓬，玉關孤望杳溟濛。", "寒沙萬里平鋪月，曉角一聲高捲風。", "戰士歿邊魂尚哭，單于獵處火猶紅。", "分明更想殘宵夢，故國依然在甬東。"]'),
('b064e9db-9ce2-4794-a240-67475590e4d5','宿山驛','吳商浩','唐','唐诗','tang','','[]','文戰何堪功未圖，又驅羸馬指天衢。',64,'全唐诗/poet.tang.43000.json','["文戰何堪功未圖，又驅羸馬指天衢。", "露華凝夜渚蓮盡，月彩滿輪山驛孤。", "岐路辛勤終日有，鄉關音信隔年無。", "好同范蠡扁舟興，高挂一帆歸五湖。"]'),
('8d865681-9856-429b-bc80-1dd0700683b5','北邙山','吳商浩','唐','唐诗','tang','','[]','北邙山草又青青，今日銷魂事可明。',64,'全唐诗/poet.tang.43000.json','["北邙山草又青青，今日銷魂事可明。", "綠酒醉來春未歇，白楊風起柳初晴。", "岡原旋葬松新長，年代無人闕半平。", "堪取金爐九還藥，不能隨夢向浮生。"]'),
('7c7762a9-55bd-4e6e-b442-9f8193a4cb3d','秋塘曉望','吳商浩','唐','唐诗','tang','','[]','鐘盡疎桐散曙鴉，故山煙樹隔天涯。',32,'全唐诗/poet.tang.43000.json','["鐘盡疎桐散曙鴉，故山煙樹隔天涯。", "西風一夜秋塘曉，零落幾多紅藕花。"]'),
('15a8fe92-3175-400a-a875-249a7a4fce19','水樓感事','吳商浩','唐','唐诗','tang','','[]','高柳螿啼雨後秋，年光空感淚如流。',32,'全唐诗/poet.tang.43000.json','["高柳螿啼雨後秋，年光空感淚如流。", "滿湖菱荇東歸晚，閑倚南軒盡日愁。"]'),
('464fcb8e-1bac-4cd7-aadb-5610655818e2','泊舟','吳商浩','唐','唐诗','tang','','[]','身逐煙波魂自驚，木蘭舟上一帆輕。',32,'全唐诗/poet.tang.43000.json','["身逐煙波魂自驚，木蘭舟上一帆輕。", "雲中有寺在何處，山底宿時聞磬聲。"]'),
('bedcaa71-c405-4222-83ac-0a3f9c61754d','湘雲','吳商浩','唐','唐诗','tang','','[]','□滿湘江雲瑩空，紛紛長對水溶溶。',32,'全唐诗/poet.tang.43000.json','["□滿湘江雲瑩空，紛紛長對水溶溶。", "日西遙望自歸處，盡挂九疑千萬峰。"]'),
('c57bdfc5-2bf5-4295-aaae-99563881bdaf','秋閨','沈祖仙','唐','唐诗','tang','','[]','白馬三軍客，青娥十載思。',48,'全唐诗/poet.tang.43000.json','["白馬三軍客，青娥十載思。", "玉庭霜落夜，羅幌月明時。", "鑪冷蜘蛛喜，燈高熠燿期。", "愁多不可曙，流涕坐空幃。"]'),
('82f2599b-31c7-420f-be1b-ef07d79c78c3','秋閨','邵士彥','唐','唐诗','tang','','[]','斜日空庭暮，幽閨積恨盈。',48,'全唐诗/poet.tang.43000.json','["斜日空庭暮，幽閨積恨盈。", "細風吹帳冷，微月度窗明。", "怨坐啼相續，愁眠夢不成。", "調琴欲有弄，畏作斷腸聲。"]'),
('60eba8cc-f726-4bbd-baca-de2989c7d579','擣衣','吳大江','唐','唐诗','tang','','[]','沙塞秋應晚，金閨恨已空。',48,'全唐诗/poet.tang.43000.json','["沙塞秋應晚，金閨恨已空。", "那堪裂紈素，時許出房櫳。", "杵影弄寒月，砧聲調夜風。", "裁縫雙淚盡，萬里寄雲中。"]'),
('32aa9ad8-f083-41d7-b5c3-bf8dfa13df44','題慈恩塔','荆叔','唐','唐诗','tang','','[]','漢國山河在，秦陵草樹深。',24,'全唐诗/poet.tang.43000.json','["漢國山河在，秦陵草樹深。", "暮雲千里色，無處不傷心。"]'),
('75c31f6f-4093-44fb-98c3-9c575e82e56c','三湘有懷','蕭靜','唐','唐诗','tang','','["\u9001\u522b", "\u60b2\u6101"]','柳絮飛來別洛陽，梅花落後到三湘。',32,'全唐诗/poet.tang.43000.json','["柳絮飛來別洛陽，梅花落後到三湘。", "世情已逐浮雲散，離恨空隨江水長。"]'),
('f6aae49f-b1b0-418c-8065-ccf0ac3dc7ef','九日對酒','元凜','唐','唐诗','tang','','[]','嘉辰復遇登高臺，良朋笑語傾金罍。',64,'全唐诗/poet.tang.43000.json','["嘉辰復遇登高臺，良朋笑語傾金罍。", "煙攤秋色正堪翫，風惹菊香無限來。", "未保亂離今日後，且謀歡洽玉山頹。", "誰知靖節當時事，空學狂歌倒載迴。"]'),
('b55bab28-3326-4f18-8634-b87dfacacdff','中秋夜不見月','元凜','唐','唐诗','tang','','[]','蟾輪何事色全微，賺得佳人出繡幃。',64,'全唐诗/poet.tang.43000.json','["蟾輪何事色全微，賺得佳人出繡幃。", "四野霧凝空寂寞，九霄雲鎖絕光輝。", "吟詩得句翻停筆，翫處臨尊却掩扉。", "公子倚欄猶悵望，嬾將紅燭草堂歸。"]'),
('9e1dde6b-ca3f-4a0f-bc8a-04e0076cf8d8','雷塘','徐振','唐','唐诗','tang','','[]','九重城闕悲涼盡，一聚園林怨恨長。',64,'全唐诗/poet.tang.43000.json','["九重城闕悲涼盡，一聚園林怨恨長。", "花憶所爲猶自笑，草知無道更應荒。", "詩名占得風流在，酒興催教運祚亡。", "若問皇天惆悵事，只應斜日照雷塘。"]'),
('242b4ada-ccaf-4507-a401-0e969dab6271','古意','徐振','唐','唐诗','tang','','[]','擾擾都城曉又昏，六街車馬五侯門。',32,'全唐诗/poet.tang.43000.json','["擾擾都城曉又昏，六街車馬五侯門。", "箕山渭水空明月，可是巢由絕子孫。"]'),
('b126375c-a50f-4aed-90a6-2534f8cec3af','寄人','張侹','唐','唐诗','tang','','[]','酷憐風月爲多情，還到春時別恨生。',32,'全唐诗/poet.tang.43000.json','["酷憐風月爲多情，還到春時別恨生。", "倚柱尋思倍惆悵，一塲春夢不分明。"]'),
('ebabaaeb-5a92-4be0-becd-98faaf89cb39','武昌阻風','方澤','唐','唐诗','tang','','[]','江上春風留客舟，無窮歸思滿東流。',32,'全唐诗/poet.tang.43000.json','["江上春風留客舟，無窮歸思滿東流。", "與君盡日閑臨水，貪看飛花忘却愁。"]'),
('bc699167-cda1-4e83-bf22-c5ebb0c30ffd','秋夜宿淮口','景池','唐','唐诗','tang','','[]','露白草猶青，淮舟倚岸停。',48,'全唐诗/poet.tang.43000.json','["露白草猶青，淮舟倚岸停。", "風帆幾處客，天地兩河星。", "樹靜禽眠草，沙寒鹿過汀。", "明朝誰結伴，直去泛滄溟。"]'),
('52c6042a-9a0c-4dd0-9cfa-d75d37e435e3','贈喬尊師','張鴻','唐','唐诗','tang','','[]','長忌時人識，有家雲澗深。',48,'全唐诗/poet.tang.43000.json','["長忌時人識，有家雲澗深。", "性惟耽嗜酒，貧不破除琴。", "靜鼓三通齒，頻湯一味參。", "知師最知我，相引坐檉陰。"]'),
('4a778c4d-8d35-4b73-bf1a-1f60cb687407','村行','姚揆','唐','唐诗','tang','','[]','天淡雨初晴，遊人恨不勝。',48,'全唐诗/poet.tang.43000.json','["天淡雨初晴，遊人恨不勝。", "亂山啼蜀魄，孤櫂宿巴陵。", "影暗村橋柳，光寒水寺燈。", "罷吟思故國，窗外有漁罾。"]'),
('47adf5f0-709b-4edc-bee7-71bc2675bd44','頴川客舍','姚揆','唐','唐诗','tang','','[]','素琴孤劒尚閑遊，誰共芳尊話唱酬。',64,'全唐诗/poet.tang.43000.json','["素琴孤劒尚閑遊，誰共芳尊話唱酬。", "鄉夢有時生枕上，客情終日在眉頭。", "雲拖雨脚連天去，樹夾河聲繞郡流。", "回首帝京歸未得，不堪吟倚夕陽樓。"]'),
('0e618eda-400e-4611-b45b-3dc0122b7432','獨不見','王訓','唐','唐诗','tang','','[]','日晚宜春暮，風軟上林朝。',48,'全唐诗/poet.tang.43000.json','["日晚宜春暮，風軟上林朝。", "對酒近初節，開樓蕩夜謠。", "石橋通小澗，竹路上青霄。", "持底誰見許，長愁成細腰。"]'),
('b945b076-18ae-4f09-aed3-b0986f44030a','歸去來引','張熾','唐','唐诗','tang','','[]','歸去來，歸期不可違。',22,'全唐诗/poet.tang.43000.json','["歸去來，歸期不可違。", "相見旋明月，浮雲共我歸。"]'),
('dd1e3a37-cd81-4b4b-998c-efdb7f8df9ae','結客少年場行','虞羽客','唐','唐诗','tang','','[]','幽幷俠少年，金絡控連錢。',120,'全唐诗/poet.tang.43000.json','["幽幷俠少年，金絡控連錢。", "竊符方救趙，擊筑正懷燕。", "輕生辭鳳闕，揮袂上祈連。", "陸離橫寶劒，出沒騖征旃。", "蒙輪恆顧敵，超乘忽爭先。", "摧枯逾百戰，拓地遠三千。", "骨都魂已散，樓蘭首復傳。", "龍城含宿霧，瀚海接遙天。", "歌吹金微返，振旅玉門旋。", "烽火今已息，非復照甘泉。"]'),
('53cd72f1-bdfe-402b-8fa8-13d8afcc74a4','塞上','鄭渥','唐','唐诗','tang','','[]','出門何處問西東，指畫翻爲語論同。',64,'全唐诗/poet.tang.43000.json','["出門何處問西東，指畫翻爲語論同。", "到此客頭潛覺白，未秋山葉已飄紅。", "帳前影落傳書鴈，日下聲交失馬翁。", "早晚回鞭復南去，大衣高蓋漢鄉風。"]'),
('5cd7e8bc-9298-4e18-b1cf-8fe71398c653','洛陽道','鄭渥','唐','唐诗','tang','','[]','客亭門外路東西，多少喧騰事不齊。',64,'全唐诗/poet.tang.43000.json','["客亭門外路東西，多少喧騰事不齊。", "楊柳惹鞭公子醉，苧麻掩淚魯人迷。", "通宵塵土飛山月，是處經營夾御堤。", "頃刻知音幾存歿，半回依約認輪蹄。"]'),
('209d0409-e140-4813-8b15-c82443376912','宜春郡城聞猨','崔江','唐','唐诗','tang','','[]','怨抱霜枝向月啼，數聲清繞郡城低。',32,'全唐诗/poet.tang.43000.json','["怨抱霜枝向月啼，數聲清繞郡城低。", "那堪日夜有雲雨，便似巫山與建溪。"]'),
('7f3801b7-f70f-4697-aa86-d86d9351e0af','謫宜陽到荆渚','李伉','唐','唐诗','tang','','[]','漢江江水水連天，被謫宜陽路幾千。',32,'全唐诗/poet.tang.43000.json','["漢江江水水連天，被謫宜陽路幾千。", "爲問野人山鳥語，問予歸櫂是何年。"]'),
('cabb20ae-5de8-4a89-8bb2-9fa8355a3a4f','九嶷山','劉望','唐','唐诗','tang','','[]','鼎湖冠劒有遺蹤，晉漢真人羽化同。',64,'全唐诗/poet.tang.43000.json','["鼎湖冠劒有遺蹤，晉漢真人羽化同。", "九轉藥成丹竈冷，五車雲去玉堂空。", "仙家日月蓬壺裏，塵世煙花夢寐中。", "徒有舊山流水畔，老松枝葉苦吟風。"]'),
('e20a10b1-b1a0-4369-8923-9a2ba3596dd0','郡城放猨獻衛使君','易思','唐','唐诗','tang','','[]','千巖萬壑與雲連，放出雕籠任自然。',64,'全唐诗/poet.tang.43000.json','["千巖萬壑與雲連，放出雕籠任自然。", "葉洒驚風啼暮雨，月凝殘雪飲流泉。", "臨岐莫似三聲日，避射須依繞樹年。", "應解感恩尋太守，攀蘿時復到樓前。"]'),
('c14ba46d-8982-450d-a89e-e56d92237218','題袁州龍興寺','易思','唐','唐诗','tang','','[]','百尺古松松下寺，寶幡朱蓋畫珊珊。',32,'全唐诗/poet.tang.43000.json','["百尺古松松下寺，寶幡朱蓋畫珊珊。", "閑庭甘露幾回落，青石綠苔猶未乾。"]'),
('ae67fcf9-cc58-40e9-a772-e64a753d2dc3','山中送弟方質','易思','唐','唐诗','tang','','[]','山中殷勤弟別兄，兄還送弟下山行。',32,'全唐诗/poet.tang.43000.json','["山中殷勤弟別兄，兄還送弟下山行。", "蘆花飛處秋風起，日暮不堪聞鴈聲。"]'),
('50ed340f-3b49-4865-be19-0255c52bf52a','尋易尊師不遇','易思','唐','唐诗','tang','','[]','爛熳紅霞光照衣，苔封白石路微微。',32,'全唐诗/poet.tang.43000.json','["爛熳紅霞光照衣，苔封白石路微微。", "華陽洞裏人何在，落盡松花不見歸。"]'),
('89d0803f-a44a-4348-a004-2f5f3da50319','秋日寄弟','趙防','唐','唐诗','tang','','[]','涼風颯庭戶，漸疑華髮侵。',48,'全唐诗/poet.tang.43000.json','["涼風颯庭戶，漸疑華髮侵。", "已經楊柳謝，猶聽蟪蛄吟。", "雨助灘聲出，雲連野色深。", "鶺鴒今在遠，年酒共誰斟。"]'),
('e8aed50c-ce5d-40e2-9104-b7f232096e48','楊岐山','劉廓','唐','唐诗','tang','','[]','千峰圍古寺，深處敞樓臺。',48,'全唐诗/poet.tang.43000.json','["千峰圍古寺，深處敞樓臺。", "景異尋常處，人須特達來。", "松杉寒更茂，嵐靄晝還開。", "欲續豐碑語，含毫恨不才。"]'),
('b06cc777-45e3-4469-aec4-89107c08dd8f','南源山','姚偓','唐','唐诗','tang','','[]','修徑投幽隱，輕裘怯暮寒。',48,'全唐诗/poet.tang.43000.json','["修徑投幽隱，輕裘怯暮寒。", "閑僧能解榻，倦客得休鞍。", "白雨鳴山麓，青燈語夜闌。", "明朝梯石路，更仗筍輿安。"]'),
('f6c6c4cf-9bbe-401a-96c8-984edc71dd0b','下第夜吟','戴衢','唐','唐诗','tang','','[]','擾擾東西南北情，何人於此悟浮生。',32,'全唐诗/poet.tang.43000.json','["擾擾東西南北情，何人於此悟浮生。", "還緣無月春風夜，暫得獨聞流水聲。"]'),
('090b7e2e-5691-41ad-a0af-27571fc7464e','句','戴衢','唐','唐诗','tang','','[]','坐落千門日，吟殘午夜燈。',12,'全唐诗/poet.tang.43000.json','["坐落千門日，吟殘午夜燈。"]'),
('147cef42-ffdc-4a29-b902-c693ded7739f','詠月','李建樞','唐','唐诗','tang','','[]','昨夜圓非今夜圓，却疑圓處減嬋娟。',32,'全唐诗/poet.tang.43000.json','["昨夜圓非今夜圓，却疑圓處減嬋娟。", "一年十二度圓缺，能得幾多時少年。"]'),
('52b31907-9837-444c-818a-e3416fabe791','謝人惠琴材','謝邈','唐','唐诗','tang','','[]','風撼桐絲帶月明，羽人乘醉截秋聲。',64,'全唐诗/poet.tang.43000.json','["風撼桐絲帶月明，羽人乘醉截秋聲。", "七弦妙制饒仙品，三尺良材稱道情。", "池小未開春浪泛，岳低猶欠暮雲生。", "何因乞與元中術，臨化無妨膝上橫。"]'),
('1a68fccd-0f54-4d5a-8890-6e1dd8cb7ace','謝僧寄拄杖','謝邈','唐','唐诗','tang','','[]','峭壁猨啼採處深，一枝奇異出孤岑。',64,'全唐诗/poet.tang.43000.json','["峭壁猨啼採處深，一枝奇異出孤岑。", "感師千里寄來意，發我片雲歸去心。", "窗外冷敲簷凍折，溪邊閑點戲魚沉。", "他年必藉相攜力，蹇步猶能返故林。"]'),
('3a2a3209-ca09-4207-b90f-4c125d569654','失題二首 一','唐備','唐','唐诗','tang','','[]','天若無雪霜，青松不如草。',24,'全唐诗/poet.tang.43000.json','["天若無雪霜，青松不如草。", "地若無山川，何人重平道。"]'),
('27d92c10-f2bc-4223-865a-b3611bbfc4d6','失題二首 二','唐備','唐','唐诗','tang','','[]','一日天無風，四溟波盡息。',24,'全唐诗/poet.tang.43000.json','["一日天無風，四溟波盡息。", "人心風不吹，波浪高百尺。"]'),
('a114a95b-97b8-491f-a049-4572de79fbe3','道傍木','唐備','唐','唐诗','tang','','[]','狂風拔倒樹，樹倒根已露。',24,'全唐诗/poet.tang.43000.json','["狂風拔倒樹，樹倒根已露。", "上有數枝藤，青青猶未悟。"]'),
('f61af241-e470-4cef-9910-d963a54841ce','失題','方棫','唐','唐诗','tang','','[]','午醉醒來晚，無人夢自驚。',24,'全唐诗/poet.tang.43000.json','["午醉醒來晚，無人夢自驚。", "夕陽如有意，長傍小窗明。"]'),
('8c4b5610-c5c6-4855-bff8-206911bccdea','失題','范夜','唐','唐诗','tang','','[]','舉意三江竭，興心四海枯。',24,'全唐诗/poet.tang.43000.json','["舉意三江竭，興心四海枯。", "南游李邕死，北望宋珪殂。"]'),
('b52d532f-fe8c-4ba0-a374-0f14c9fcf23b','失題','盧羣玉','唐','唐诗','tang','','[]','酒瀉銀瓶倒底清，夜深絲竹鳳凰鳴。',32,'全唐诗/poet.tang.43000.json','["酒瀉銀瓶倒底清，夜深絲竹鳳凰鳴。", "紅妝醉起一花落，更引春風無限情。"]'),
('15c15f7c-15a1-4b4b-b3e3-5f89dad851b4','投盧尚書','盧羣玉','唐','唐诗','tang','','[]','無力不任爲走役，有文安敢滯清平。',32,'全唐诗/poet.tang.43000.json','["無力不任爲走役，有文安敢滯清平。", "從來若把耕桑定，免恃雕蟲悞此生。"]'),
('04594d8e-1160-4f31-88d6-a5797f175c82','失題二首 一','楊行敏','唐','唐诗','tang','','[]','駑駘嘶叫知無定，騏驥低垂自有心。',32,'全唐诗/poet.tang.43000.json','["駑駘嘶叫知無定，騏驥低垂自有心。", "山上高松溪畔竹，清風纔動是知音。"]'),
('e8489e54-4cf8-4b83-93d1-9eeccbd70676','失題二首 二','楊行敏','唐','唐诗','tang','','[]','杜鵑花裏杜鵑啼，淺紫深紅更傍溪。',32,'全唐诗/poet.tang.43000.json','["杜鵑花裏杜鵑啼，淺紫深紅更傍溪。", "遲日霽光搜客思，曉來山路恨如迷。"]'),
('0e2555d3-3988-4425-89fc-40f5db11ddbf','吳江別王長史','張懷','唐','唐诗','tang','','[]','多年襆被玉山岑，鬢雪欺人忽滿簪。',64,'全唐诗/poet.tang.43000.json','["多年襆被玉山岑，鬢雪欺人忽滿簪。", "駑馬雖然貪短豆，野麋終是憶長林。", "鱸魚未得乘歸興，鷗鳥惟應信此心。", "見說新橋好風景，會須乘月濯煩襟。"]'),
('3b32b877-081c-4713-87ca-5095a5ca6844','題天台石橋','趙湘','唐','唐诗','tang','','[]','白石峰猶在，橫橋一徑微。',48,'全唐诗/poet.tang.43000.json','["白石峰猶在，橫橋一徑微。", "多年無客過，落日有雲歸。", "水淨苔生髮，山寒樹著衣。", "如何方廣寺，千古去人稀。"]'),
('fcfb1c37-bfc3-40ac-9b4a-18929c60a7a2','寄朗陵兄','楊持','唐','唐诗','tang','','[]','刺舉官猶屈，風謠政已成。',24,'全唐诗/poet.tang.43000.json','["刺舉官猶屈，風謠政已成。", "行看換龜組，奏最謁承明。"]'),
('16af518c-7417-4402-9a24-d32858116958','詠𣻕溪在歷陽西一里','李聰','唐','唐诗','tang','','[]','泠泠一帶清溪水，遠派□通歷陽市。',32,'全唐诗/poet.tang.43000.json','["泠泠一帶清溪水，遠派□通歷陽市。", "涓涓出自碧湖中，流入楚江煙霧裏。"]'),
('0352140f-db28-4a6d-bbb9-ab44da07780a','耒陽杜工部祠堂','徐介','唐','唐诗','tang','','[]','手接汨羅水，天心知所存。',48,'全唐诗/poet.tang.43000.json','["手接汨羅水，天心知所存。", "固教工部死，來伴大夫魂。", "流落同千古，風騷共一源。", "消凝傷往事，斜日隱頹垣。"]'),
('c1f0f7c7-ef32-42c8-92f5-7fe4672efe89','登單于臺','李士元','唐','唐诗','tang','','[]','悔上層樓望，翻成極目愁。',48,'全唐诗/poet.tang.43000.json','["悔上層樓望，翻成極目愁。", "路沿蔥嶺去，河背玉關流。", "馬散眠沙磧，兵閑倚戍樓。", "殘陽三會角，吹白旅人頭。"]'),
('e8b6c7dc-3204-4fcc-816c-e05748204638','登閣','李士元','唐','唐诗','tang','','[]','亂後獨來登大閣，凭闌舉目盡傷心。',64,'全唐诗/poet.tang.43000.json','["亂後獨來登大閣，凭闌舉目盡傷心。", "長堤過雨人行少，廢苑經秋草自深。", "破落侯家通永巷，蕭條宮樹接疎林。", "總輸釋氏青蓮館，依舊重重布地金。"]'),
('e580be6a-13b0-43fc-97a9-5748cf0cf4da','山中作','馮道之','唐','唐诗','tang','','[]','草堂在巖下，卜居聊自適。',72,'全唐诗/poet.tang.43000.json','["草堂在巖下，卜居聊自適。", "桂氣滿堦庭，松陰生枕席。", "遠瞻惟鳥度，旁信無人跡。", "靄靄雲生峰，潺潺水流石。", "頗尋黃卷理，庶就丹砂益。", "此即契吾生，何爲苦塵役。"]'),
('a33da592-a67a-4866-a95e-abf58db3b46f','短歌二首 一','徐謙','唐','唐诗','tang','','[]','窮通皆是運，榮辱豈關身。',24,'全唐诗/poet.tang.43000.json','["窮通皆是運，榮辱豈關身。", "不願門前客，看時逢故人。"]'),
('49511eb0-9fe4-4eba-b85b-c0d88bb5876f','短歌二首 二','徐謙','唐','唐诗','tang','','[]','意氣青雲裏，爽朗煙霞外。',24,'全唐诗/poet.tang.43000.json','["意氣青雲裏，爽朗煙霞外。", "不羨一囊錢，唯重心襟會。"]'),
('65c6f067-f897-47b0-9352-cc832be7195b','塞下曲','楊達','唐','唐诗','tang','','[]','秋日幷州路，黃榆落故關。',48,'全唐诗/poet.tang.43000.json','["秋日幷州路，黃榆落故關。", "孤城吹角罷，數騎射鵰還。", "帳幕遙臨水，牛羊自下山。", "行人正垂淚，烽火起雲間。"]'),
('462a63d2-b637-48f7-a395-e17ac2eac337','明妃怨','楊達','唐','唐诗','tang','','[]','漢國明妃去不還，馬駝弦管向陰山。',32,'全唐诗/poet.tang.43000.json','["漢國明妃去不還，馬駝弦管向陰山。", "匣中縱有菱花鏡，羞對單于照舊顏。"]'),
('9a24051a-8720-48fc-969e-d0c385f02198','送鄒尊師歸洞庭','楊逵','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','衆島在波心，曾居舊隱林。',48,'全唐诗/poet.tang.43000.json','["衆島在波心，曾居舊隱林。", "近聞飛檄急，轉憶臥雲深。", "賣藥唯供酒，歸舟只載琴。", "遙知明月夜，坐石自開襟。"]'),
('a2cb6031-e625-4c23-b3df-b46f20f4e5ed','送張兵曹赴營田','魏兼恕','唐','唐诗','tang','','[]','河曲今無戰，王師每務農。',48,'全唐诗/poet.tang.43000.json','["河曲今無戰，王師每務農。", "選才當重委，足食乃深功。", "草色孤城外，雲陰絕漠中。", "蕭關休歎別，歸望在乘騘。"]'),
('92ddcc0b-4a69-492b-8611-85f8446373e6','晚霽登汝南大雲閣','賈彥璋','唐','唐诗','tang','','[]','禪宮新歇雨，香閣晚登臨。',48,'全唐诗/poet.tang.43000.json','["禪宮新歇雨，香閣晚登臨。", "邑樹晴光起，川苗佳氣深。", "水包城下岸，雲細郢中岑。", "自歎牽卑日，聊開望遠心。"]'),
('0a1bad74-9d09-448f-a90e-9fb6482d4043','宿香山閣','賈彥璋','唐','唐诗','tang','','[]','暝望香山閣，梯雲宿半空。',48,'全唐诗/poet.tang.43000.json','["暝望香山閣，梯雲宿半空。", "軒窗閉潮海，枕席拂煙虹。", "朱網防棲鴿，紗燈護夕蟲。", "一聞雞唱曉，已見日曈曈。"]'),
('a7743a29-eba6-442f-bf74-4c03814ef69b','蘇著作山池','賈彥璋','唐','唐诗','tang','','[]','水樹子雲家，峯瀛宛不賒。',48,'全唐诗/poet.tang.43000.json','["水樹子雲家，峯瀛宛不賒。", "芥浮舟是葉，蓮發岫爲花。", "酌蟻開春甕，觀魚憑海查。", "游蘇多石友，題贈滿瑤華。"]'),
('d47dd530-e0e2-4fc3-bd82-bf23df3f7997','王龍驤墓','賈彥璋','唐','唐诗','tang','','[]','昔擅登壇寵，爰光典午朝。',48,'全唐诗/poet.tang.43000.json','["昔擅登壇寵，爰光典午朝。", "刀懸臨益夢，龍啓渡江謠。", "茂績當年舉，英魂此地銷。", "唯餘孤壠上，日夕起松飆。"]'),
('99a80573-86e7-46cf-84e7-97db424eed08','折楊柳','歐陽瑾','唐','唐诗','tang','','[]','垂柳拂妝臺，葳蕤葉半開。',48,'全唐诗/poet.tang.43000.json','["垂柳拂妝臺，葳蕤葉半開。", "年華枝上見，邊思曲中來。", "嫩色宜新雨，輕花伴落梅。", "朝朝倦攀折，征戍幾時回。"]'),
('7fc3952a-8dfd-4f22-bcdd-06dfe9c1cf91','江南曲','李叔卿','唐','唐诗','tang','','[]','湖上女，江南花，無雙越女春浣紗。',120,'全唐诗/poet.tang.43000.json','["湖上女，江南花，無雙越女春浣紗。", "風似箭，月如弦，少年吳兒曉進船。", "郗家子弟謝家郎，烏巾白袷紫香囊。", "菱歌思欲絕，楚舞斷人腸。", "歌舞未終涕雙隕，舊宮坡陁纔嶙隱。", "西山暮雨過江來，北渚春雲沿海盡。", "渡口水流緩，妾歸宵剩遲。", "含情爲君再理曲，月華照出澄江時。"]'),
('f48b4c67-9f39-4667-b557-723bbd4d5eb9','芳樹','李叔卿','唐','唐诗','tang','','[]','春看玫瑰樹，西鄰即宋家。',48,'全唐诗/poet.tang.43000.json','["春看玫瑰樹，西鄰即宋家。", "門深重暗葉，牆近度飛花。", "影拂桃陰淺，香傳李逕斜。", "靚妝愁日暮，流涕向窗紗。"]'),
('b6d3543d-429b-423e-9b80-70d66a4e9ec7','送楊諫議赴河西節度判官兼呈韓王二侍御','熊曜','唐','唐诗','tang','','[]','賢哉征西將，幕府多俊人。',108,'全唐诗/poet.tang.43000.json','["賢哉征西將，幕府多俊人。", "籌議秉刀尺，話言在經綸。", "先鞭羨之子，走馬辭咸秦。", "庭論許名實，數公當即真。", "行行弄文翰，婉婉光使臣。", "今者所從誰，不聞歌苦辛。", "黃雲蕭關道，白日驚沙塵。", "虜寇有時獵，漢兵行復巡。", "王師已無戰，傳檄奉良臣。"]'),
('dac0b9cb-3aee-4c3f-bc88-b822bcccb36d','登巴陵開元寺西閣贈衡嶽僧方外','李賓','唐','唐诗','tang','','[]','衡嶽有開士，五峰秀貞骨。',72,'全唐诗/poet.tang.43000.json','["衡嶽有開士，五峰秀貞骨。", "見君萬里心，海水照秋月。", "大臣南溟去，問道皆請謁。", "灑以甘露言，清涼潤肌髮。", "湖海落天鏡，香閣凌銀闕。", "登眺餐惠風，心花期啓發。"]'),
('a62a83c3-7e5d-409f-bba3-9fa3358461f6','登瓦官寺閣','李賓','唐','唐诗','tang','','[]','晨登瓦官閣，極眺金陵城。',120,'全唐诗/poet.tang.43000.json','["晨登瓦官閣，極眺金陵城。", "鍾山對北戶，淮水入南榮。", "漫漫雨花落，嘈嘈天樂鳴。", "兩廊振法鼓，四角吹風箏。", "杳無霄漢上，仰攀日月行。", "山空霸氣滅，地古寒陰生。", "寥廓雲海晚，蒼茫宮觀平。", "門餘閶闔字，樓識鳳凰名。", "雷作百川動，神扶萬栱傾。", "靈光一向貴，長此鎮吳京。"]'),
('a4a9a056-6d6e-4d72-b635-29c8a99c7f10','金陵懷古','唐堯臣','唐','唐诗','tang','','["\u957f\u6c5f"]','晉末英雄起，神器淪荒服。',216,'全唐诗/poet.tang.43000.json','["晉末英雄起，神器淪荒服。", "胡月蝕中原，白日升暘谷。", "金陵實形勝，關山固重複。", "巨壑隍北壖，長江塹西隩。", "鑿山擬嵩華，穿地象伊穀。", "草昧席羅圖，蓽路戴黃屋。", "一時因地險，五世享天祿。", "禮樂何煌煌，文章紛郁郁。", "多士春林秀，作頌清風穆。", "出入三百年，朝事幾翻覆。", "攙搶如雲勃，鯨鯢旋自曝。", "倦聞金鼎移，驟覩靈龜卜。", "吁嗟王氣盡，坐悲天運倏。", "天道何茫茫，善淫乃相復。", "行路偏衣半，遂亡大梁族。", "日隱汀洲上，登艫𦪇川陸。", "月迴吳山樹，風聞楚江鵠。", "因依蘭蕙藂，採擷不盈掬。"]'),
('cb6c3b55-ffa4-4f74-97b4-3acf36502034','詠浮漚爲辛明府作','鄭縉','唐','唐诗','tang','','[]','行潦散輕漚，清規吐未收。',84,'全唐诗/poet.tang.43000.json','["行潦散輕漚，清規吐未收。", "雨來波際合，風起浪中浮。", "晶晃明苔砌，參差繞芥舟。", "影疑星泛曉，光似露涵秋。", "皎皎珠同淨，漂漂梗共流。", "潔容無變染，圓知有謙柔。", "欲作微涓效，先從淡水游。"]'),
('20797ea1-e498-43a1-88db-e913d48b7fed','鶯','鄭縉','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u548f\u7269"]','欲囀聲猶澀，將飛羽未調。',24,'全唐诗/poet.tang.43000.json','["欲囀聲猶澀，將飛羽未調。", "高風不借便，何處得遷喬。"]'),
('16db7fcc-3f65-46cb-bcf9-85f63bb1f694','鸚鵡','吳英秀','唐','唐诗','tang','','[]','莫把金籠閉鸚鵡，箇箇聰明解人語。',32,'全唐诗/poet.tang.43000.json','["莫把金籠閉鸚鵡，箇箇聰明解人語。", "忽然更向君前言，三十六宮愁幾許。"]'),
('307c7884-0b30-4442-830c-081085bfc25d','馬','陳凝','唐','唐诗','tang','','[]','未明龍骨駿，幸得到神州。',48,'全唐诗/poet.tang.43000.json','["未明龍骨駿，幸得到神州。", "自有千金價，寧忘伯樂酬。", "雖知殊欵段，莫敢比驊騮。", "若遇追風便，當軒一舉頭。"]'),
('5c4da333-70ed-4782-8f92-db4cde0c760b','鳳','伊夢昌','唐','唐诗','tang','','[]','好是山家鳳，歌成非楚雞。',48,'全唐诗/poet.tang.43000.json','["好是山家鳳，歌成非楚雞。", "毫光灑風雨，紋綵動雲霓。", "竹實不得飽，桐孫何足栖。", "岐陽今好去，律呂正淒淒。"]'),
('3a2fae63-3b43-46c5-8df4-aba01b6c27bb','送韋員外赴朔方','鄭嚴','唐','唐诗','tang','','[]','白露邊秋早，皇華戎事催。',48,'全唐诗/poet.tang.43000.json','["白露邊秋早，皇華戎事催。", "已推仙省妙，更是幕中才。", "出餞傾朝列，深功佇帝臺。", "坐聞長策利，終見勒銘迴。"]'),
('db062845-57cf-4818-bc18-603c26ac64b0','險竿行','柳曾','唐','唐诗','tang','','[]','山險驚摧輈，水險能覆舟。',175,'全唐诗/poet.tang.43000.json','["山險驚摧輈，水險能覆舟。", "奈何平地不肯立，走上百尺高竿頭。", "我不知爾是人耶復猱耶？", "使我爲爾長嘆嗟。", "我聞孝子不許國，忠臣不愛家。", "爾今輕命重黃金，忠孝兩虧徒爾誇。", "始以險技悅君目，終以貪心媚君祿。", "百尺高竿百度緣，一足參差一家哭。", "險竿兒，聽我語，更有險徒險於汝。", "重於權者失君恩，落向天涯海邊去。", "險竿兒，爾須知，險途欲往爾可思。", "上得不下下不得，我謂此輩險於險竿兒。"]'),
('6232f4f5-94d3-4111-abad-c398fd80beb8','琵琶行','牛殳','唐','唐诗','tang','','[]','何人斸得一片木，三尺春冰五音足。',292,'全唐诗/poet.tang.43000.json','["何人斸得一片木，三尺春冰五音足。", "一彈決破真珠囊，迸落金盤聲斷續。", "飄飄颻颻寒丁丁，蟲豸出蟄神鬼驚。", "秋鴻叫侶代雲黑，猩猩夜啼蠻月明。", "潏潏汩汩聲不定，胡雛學漢語未正。", "若似長安月蝕時，滿城敲鼓聲噒噒。", "青山飛起不壓物，野水流來欲濕人。", "傷人憶得陳後主，春殿半酣細腰舞。", "黃鶯百舌正相呼，玉樹後庭花帶雨。", "二妃哭處山重重，二妃沒後雲溶溶。", "夜深霜露鎖空廟，零落一叢斑竹風。", "金谷園中草初綠，石崇一弄思歸曲。", "當時二十四友人，手把金杯聽不足。", "又似賈客蜀道間，千鐸萬磬鳴空山。", "未若此調呦呦兮啁啁，嘈嘈兮啾啾。", "引之於山，獸不能走。", "吹之於水，魚不能游。", "方知此藝不可有，人間萬事憑雙手。", "若何爲我再三彈，送却花前一尊酒。"]'),
('964d490c-6ecf-4afe-b2a7-67ae8b2281ce','方響歌','牛殳','唐','唐诗','tang','','[]','樂中何樂偏堪賞，無過夜深聽方響。',128,'全唐诗/poet.tang.43000.json','["樂中何樂偏堪賞，無過夜深聽方響。", "緩擊急擊曲未終，暴雨飄飄生坐上。", "鏗鏗鐺鐺寒重重，盤渦蹙派鳴蛟龍。", "高樓漏滴金壺水，碎電打著山寺鐘。", "又似公卿入朝去，環珮鳴玉長街路。", "忽然碎打入破聲，石崇推倒珊瑚樹。", "長短參差十六片，敲擊宮商無不遍。", "此樂不教外人聞，尋常只向堂前宴。"]'),
('a9dc3433-27c0-439c-bc86-d2de245f1628','經太華','衛光一','唐','唐诗','tang','','["\u9ec4\u6cb3"]','太華五千尋，重嵒合沓起。',48,'全唐诗/poet.tang.43000.json','["太華五千尋，重嵒合沓起。", "勢飛白雲外，影倒黃河裏。", "上有千蓮葉，服之久不死。", "山高採難得，歎息徒仰止。"]'),
('236688b7-72dc-4ceb-975c-8a8d590a0b1e','季夏入北山','林璠','唐','唐诗','tang','','[]','整駕俟明發，逶迤歷險途。',48,'全唐诗/poet.tang.43000.json','["整駕俟明發，逶迤歷險途。", "天形逼峰盡，地勢入谿無。", "樹繞圓潭密，雲橫疊障孤。", "誰憐後時者，六月未南圖。"]'),
('d89d9747-8682-45a1-b213-f0e937ab90b2','適思','顏胄','唐','唐诗','tang','','[]','芳歲不我與，颯然涼風生。',204,'全唐诗/poet.tang.43000.json','["芳歲不我與，颯然涼風生。", "繁華掃地歇，蟋蟀充堂鳴。", "感物增憂思，奮衣出遊行。", "行值古墓林，白骨下縱橫。", "田豎鞭髑髏，村童掃精靈。", "精靈無奈何，像設安所榮。", "石人徒瞑目，表柱燒無聲。", "試讀碑上文，乃是昔時英。", "位極君詔葬，勳高盈忠貞。", "寵終禁樵採，立嗣修墳塋。", "運否前政缺，羣盜多蚊䖟。", "即此丘壠壞，鐵心爲霑纓。", "當其崇樹日，豈意侵奪併。", "冥漠生變故，淒涼結幽明。", "悲端豈自我，外物紛相縈。", "所適非所見，前登江上城。", "倚樓臨綠水，一望解傷情。"]'),
('e3184ca5-f7a3-45fb-b93a-f419915ba9f2','古意','邢象玉','唐','唐诗','tang','','[]','家中酒新熟，園裏葉初榮。',96,'全唐诗/poet.tang.43000.json','["家中酒新熟，園裏葉初榮。", "佇杯欲取醉，悒然思友生。", "忽聞有奇客，何姓復何名。", "嗜酒陶彭澤，能琴阮步兵。", "何須問寒暑，徑共坐山亭。", "舉袂祛啼鳥，揚巾掃落英。", "心神無俗累，歌詠有新聲。", "新聲是何曲，滄浪之水清。"]'),
('aee47902-bd67-4fa5-ad94-7bb246a7a305','採蓮曲','張敬徽','唐','唐诗','tang','','[]','遊女泛江晴，蓮紅水復清。',48,'全唐诗/poet.tang.43000.json','["遊女泛江晴，蓮紅水復清。", "競多愁日暮，爭疾畏船傾。", "波動疑釵落，風生覺袖輕。", "相看未盡意，歸浦櫂歌聲。"]'),
('695fe028-91f4-4e6a-9fac-4c989146d3a1','采蓮','徐玄之','唐','唐诗','tang','','[]','越豔荆姝慣采蓮，蘭橈畫檝滿長川。',80,'全唐诗/poet.tang.43000.json','["越豔荆姝慣采蓮，蘭橈畫檝滿長川。", "秋來江水澄如練，映水紅妝如可見。", "此時蓮浦珠翠光，此日荷風羅綺香。", "纖手周遊不暫息，紅英爛熳殊未極。", "夕鳥棲林人欲稀，長歌哀怨采蓮歸。"]'),
('3fb1ebdf-1ca2-4548-8037-55b5ac7153b6','同崔員外溫泉宮即事','郭汭','唐','唐诗','tang','','[]','輦輅移雙闕，宸遊整六師。',72,'全唐诗/poet.tang.43000.json','["輦輅移雙闕，宸遊整六師。", "天迴紫微座，日轉羽林旗。", "雷氣寒戈戟，軍容壯武貔。", "弓鳴射雁處，泉暖躍龍時。", "惠化成觀俗，謳謠入賦詩。", "同歡王道盛，相與詠雍熙。"]'),
('5ac3d0a2-fb47-4283-a056-9e05a5bb9c1a','題沈黎城','權徹','唐','唐诗','tang','','[]','蘇子臥北海，馬翁渡南洲。',84,'全唐诗/poet.tang.43000.json','["蘇子臥北海，馬翁渡南洲。", "迹恨事乃立，功達名遂休。", "夜聞羽書至，召募此邊州。", "鐵騎燿楚甲，玉匣橫吳鉤。", "雪厚羣山凍，蓬飛荒塞秋。", "久戍曷辭苦，數戰期封侯。", "不學豎儒輩，談經空白頭。"]'),
('06d46ef2-27de-44aa-b03c-e9229bdd5937','登樂遊原懷古','豆盧回','唐','唐诗','tang','','[]','緬惟漢宣帝，初謂皇曾孫。',180,'全唐诗/poet.tang.43000.json','["緬惟漢宣帝，初謂皇曾孫。", "雖在襁褓中，亦遭巫蠱冤。", "至哉丙廷尉，感激義彌敦。", "馳逐蓮勺道，出入諸陵門。", "一朝風雲會，竟登天位尊。", "握符升寶曆，負扆御華軒。", "赫奕文物備，葳蕤休瑞繁。", "卒爲中興主，垂名於後昆。", "雄圖奄已謝，餘址空復存。", "昔爲樂遊苑，今爲狐兔園。", "朝見牧豎集，夕聞棲鳥喧。", "蕭條灞亭岸，寂寞杜陵原。", "羃䍥野煙起，蒼茫嵐氣昏。", "二曜屢迴薄，四時更涼溫。", "天道尚如此，人理安可論。"]'),
('ef5565ad-3603-4539-a43e-a3b8d6b31aed','靜女歌','張南容','唐','唐诗','tang','','[]','靜女樂於靜，動合古人則。',104,'全唐诗/poet.tang.43000.json','["靜女樂於靜，動合古人則。", "妙年工詩書，弱歲勤組織。", "端居愁若癡，誰復理容色。", "十五坐幽閨，四鄰不相識。", "夭夭鄰家子，百花裝首餙。", "日月淇上遊，笑人不踰閾。", "河水自濁濟自清，仙臺蛾眉秦鏡明。", "爲照齊王門下醜，何如漢帝掌中輕。"]'),
('3ae6a8e8-1f8a-4337-93cc-f2e23d4b126e','古興二首 一','沈徽','唐','唐诗','tang','','[]','蔓草自細微，女蘿始夭夭。',72,'全唐诗/poet.tang.43000.json','["蔓草自細微，女蘿始夭夭。", "夤緣至百尺，榮耀非一朝。", "敷色高碧嶺，流芳薄丹霄。", "如何摧秀木，正爲餘波漂。", "莖葉落巖跡，英蕤從風飆。", "洪柯不足恃，況乃託陵苕。"]'),
('4f90f5aa-0968-487d-b177-0be514cb6750','古興二首 二','沈徽','唐','唐诗','tang','','[]','長安富豪右，信是天下樞。',72,'全唐诗/poet.tang.43000.json','["長安富豪右，信是天下樞。", "戚里笙歌發，禁門冠蓋趨。", "攀雲無醜士，唾地盡成珠。", "日晏下雙闕，煙花亂九衢。", "恩榮在片言，零落亦須臾。", "何意還自及，曲池今已蕪。"]'),
('024d7799-ac7c-4acb-b356-2971dd55bc42','晚望','林琨','唐','唐诗','tang','','[]','清晨孤亭裏，極目對前岑。',72,'全唐诗/poet.tang.43000.json','["清晨孤亭裏，極目對前岑。", "遠與天水合，長霞生夕林。", "蒼然平楚意，杳靄半秋陰。", "落日川上盡，關城雲外深。", "方予事巖壑，及此欲抽簪。", "詩就蓬山道，還茲契宿心。"]'),
('b584bd8d-c8ba-4c1f-9041-aa387849e116','陽春歌','吳象之','唐','唐诗','tang','','[]','簾低曉露濕，簾捲鶯聲急。',48,'全唐诗/poet.tang.43000.json','["簾低曉露濕，簾捲鶯聲急。", "欲起把箜篌，如凝綵弦澀。", "孤眠愁不轉，點淚聲相及。", "淨掃階上花，風來更吹入。"]'),
('66f7b878-59d0-46a5-92a4-2ae713e2dfe7','少年行','吳象之','唐','唐诗','tang','','[]','承恩借獵小平津，使氣常遊中貴人。',32,'全唐诗/poet.tang.43000.json','["承恩借獵小平津，使氣常遊中貴人。", "一擲千金渾是膽，家無四壁不知貧。"]'),
('ec53a259-f2a7-43b2-a254-eab08ad6dc44','晚至鄉亭','鄭德玄','唐','唐诗','tang','','[]','長亭日已暮，駐馬暫盤桓。',48,'全唐诗/poet.tang.43000.json','["長亭日已暮，駐馬暫盤桓。", "山川杳不極，徒侶默相看。", "雲夕荆臺暗，風秋郢路寒。", "客心一如此，誰復采芳蘭。"]'),
('64bab1eb-a0a9-4555-9193-f59f730cf14d','舟行旦發','張軫','唐','唐诗','tang','','[]','夜帆時未發，同侶暗相催。',48,'全唐诗/poet.tang.43000.json','["夜帆時未發，同侶暗相催。", "山曉月初下，江鳴潮欲來。", "稍分揚子岸，不辨越王臺。", "自客水鄉裏，舟行知幾迴。"]'),
('f099a2b5-e9d1-4b4d-8487-592d3a33cdac','奉和夏日遊山應制','蔡文恭','唐','唐诗','tang','','[]','首夏林壑清，薄暮煙霞上。',72,'全唐诗/poet.tang.43000.json','["首夏林壑清，薄暮煙霞上。", "連巖聳百仞，絕壑臨千丈。", "照灼晚花鮮，潺湲夕流聲。", "悠然動睿思，息駕尋真賞。", "掞彼渦川作，懷茲洛濱想。", "竊吹等齊竽，何用承恩獎。"]'),
('569a80c0-9309-40c8-ad66-9a41d3fcd404','旅泊江津言懷','賈宗','唐','唐诗','tang','','[]','征途幾迢遰，客子倦西東。',72,'全唐诗/poet.tang.43000.json','["征途幾迢遰，客子倦西東。", "乘流如泛梗，逐吹似驚蓬。", "飄颻萬里外，辛苦百年中。", "異縣心期阻，他鄉風月同。", "雲歸全嶺暗，日落半江紅。", "自然堪迸淚，非是泣途窮。"]'),
('cafced51-dc7d-4afa-9ee6-f0a6a1316328','大梁行','唐堯客','唐','唐诗','tang','','[]','客有成都來，爲我彈鳴琴。',192,'全唐诗/poet.tang.43000.json','["客有成都來，爲我彈鳴琴。", "前彈別鶴操，後奏大梁吟。", "大梁傷客情，荒臺對古城。", "版築有陳跡，歌吹舞遺聲。", "雄哉魏公子，疇日好羅英。", "秀士三千人，煌煌列衆星。", "金槌奪晉鄙，白刃刎侯嬴。", "邯鄲救趙北，函谷走秦兵。", "君子榮且昧，忠信莫之明。", "間諜忽來及，雄圖靡克成。", "千齡萬化盡，但見汴水清。", "舊國多孤壘，夷門荆棘生。", "蒼梧綵雲沒，湘浦綠池平。", "聞有東山去，蕭蕭班馬鳴。", "河洲搴宿莽，日夕淚霑纓。", "因之唁公子，慷慨此歌行。"]'),
('0ba4c978-518e-469b-b32e-50ca49a12a4d','秋日送別','朱晦','唐','唐诗','tang','','[]','荒郊古陌時時斷，野水浮雲處處秋。',32,'全唐诗/poet.tang.43000.json','["荒郊古陌時時斷，野水浮雲處處秋。", "唯有河邊衰柳樹，蟬聲相送到揚州。"]'),
('afe4ff37-0c30-4219-a48a-52df8169e0f6','送人歸山','石召','唐','唐诗','tang','','[]','相逢唯道在，誰不共知貧。',48,'全唐诗/poet.tang.43000.json','["相逢唯道在，誰不共知貧。", "歸路分殘雨，停舟別故人。", "霜明松嶺曉，花暗竹房春。", "亦有棲閑意，何年可寄身。"]'),
('4985a178-54f7-4000-b4c5-4ce5b2068ee0','早行遇雪','石召','唐','唐诗','tang','','[]','荒郊昨夜雪，羸馬又須行。',24,'全唐诗/poet.tang.43000.json','["荒郊昨夜雪，羸馬又須行。", "四顧無人迹，雞鳴第一聲。"]'),
('32b4a897-bac7-4278-8e4d-523b7ec7e8f1','送安養閻主簿還竹寺','林珝','唐','唐诗','tang','','[]','分手怨河梁，南征歷漢陽。',48,'全唐诗/poet.tang.43000.json','["分手怨河梁，南征歷漢陽。", "江山追宋玉，雲雨夢襄王。", "醉裏宜城近，歌中郢路長。", "更尋棲枳處，猶是念仇香。"]'),
('a5edaba1-8b4a-4420-a7ae-eee6e8356765','晚投南村','衛葉','唐','唐诗','tang','','[]','客行逢日暮，原野散秋暉。',48,'全唐诗/poet.tang.43000.json','["客行逢日暮，原野散秋暉。", "南陌人初斷，西林鳥盡歸。", "暗蓬沙上轉，寒葉月中飛。", "村落無多在，聲聲近擣衣。"]'),
('d6524abb-984c-4f99-a2a1-ca0966b3dc7c','題季子廟','李季華','唐','唐诗','tang','','[]','季子讓社稷，又能聽國風。',24,'全唐诗/poet.tang.43000.json','["季子讓社稷，又能聽國風。", "寧知千載後，蘋藻冷祠宮。"]'),
('d4790d81-875d-4e8a-af11-4ab1f2894735','聽琴','王玄','唐','唐诗','tang','','[]','拂塵開按匣，何事獨顰眉。',24,'全唐诗/poet.tang.43000.json','["拂塵開按匣，何事獨顰眉。", "古調俗不樂，正聲君自知。"]'),
('7ba354c7-862a-44e8-b1d9-ae356d78754a','失鷺鶿','李歸唐','唐','唐诗','tang','','[]','惜養來來歲月深，籠開不見意沈吟。',32,'全唐诗/poet.tang.43000.json','["惜養來來歲月深，籠開不見意沈吟。", "也知祗在秋江上，明月蘆花何處尋。"]'),
('4cbe84d0-fc90-4d10-a085-f51ae7cf7159','銅雀妓','朱光弼','唐','唐诗','tang','','[]','魏王銅雀妓，日暮管弦清。',24,'全唐诗/poet.tang.43000.json','["魏王銅雀妓，日暮管弦清。", "一見西陵樹，心悲舞不成。"]'),
('ae2826eb-9d80-4b13-8182-ab08df506fe9','宮詞','朱光弼','唐','唐诗','tang','','[]','夢裏君王近，宮中河漢高。',24,'全唐诗/poet.tang.43000.json','["夢裏君王近，宮中河漢高。", "秋風能再熱，團扇不辭勞。"]'),
('53d1c4fb-7ffc-4557-9c0e-cc9b7ec63b9d','惆悵詩九首 一','顧甄遠','唐','唐诗','tang','','[]','魂黯黯兮情脈脈，簾風清兮窗月白。',32,'全唐诗/poet.tang.43000.json','["魂黯黯兮情脈脈，簾風清兮窗月白。", "夢驚枕上爐燼銷，不見蘂珠宮裏客。"]'),
('0df629a7-308c-45f7-9e1c-d9de57bbb85f','惆悵詩九首 二','顧甄遠','唐','唐诗','tang','','[]','禁漏聲稀蟾魂冷，紗廚筠簟波光淨。',32,'全唐诗/poet.tang.43000.json','["禁漏聲稀蟾魂冷，紗廚筠簟波光淨。", "獨坐愁吟暗斷魂，滿窗風動芭蕉影。"]'),
('b3ca18d4-068c-4fec-ae9a-a27b7882ccd0','惆悵詩九首 三','顧甄遠','唐','唐诗','tang','','[]','別恨離腸空惻惻，風動虛軒池水白。',32,'全唐诗/poet.tang.43000.json','["別恨離腸空惻惻，風動虛軒池水白。", "莫言靈圃步難尋，有心終效偷桃客。"]'),
('62f27757-a831-474c-b588-22561a4a3a51','惆悵詩九首 四','顧甄遠','唐','唐诗','tang','','[]','秋遇人間好風景，焦桐韻滿華堂靜。',32,'全唐诗/poet.tang.43000.json','["秋遇人間好風景，焦桐韻滿華堂靜。", "鑑鸞釵燕恨何窮，忍向銀牀空抱影。"]'),
('6c280f26-1606-4096-b8a7-ae35d2645a6b','惆悵詩九首 五','顧甄遠','唐','唐诗','tang','','[]','綠槐影裏傍青樓，陌上行人空舉頭。',32,'全唐诗/poet.tang.43000.json','["綠槐影裏傍青樓，陌上行人空舉頭。", "煙水露花無處問，搖鞭凝睇不勝愁。"]'),
('a0076939-533d-488a-842e-a2e9b5799cc7','惆悵詩九首 六','顧甄遠','唐','唐诗','tang','','[]','役盡心神銷盡骨，恩情未斷忽分離。',32,'全唐诗/poet.tang.43000.json','["役盡心神銷盡骨，恩情未斷忽分離。", "平生此恨無言處，只有衣襟淚得知。"]'),
('78101e80-4201-4736-a13c-cba8070534b8','惆悵詩九首 七','顧甄遠','唐','唐诗','tang','','[]','濃醪豔唱愁難破，骨瘦魂消病已成。',32,'全唐诗/poet.tang.43000.json','["濃醪豔唱愁難破，骨瘦魂消病已成。", "若爲多羅年少死，始甘人道有風情。"]'),
('2de8f5a6-eb4a-455d-adc5-9676bce23c47','惆悵詩九首 八','顧甄遠','唐','唐诗','tang','','[]','淚滿羅衣酒滿巵，一聲歌斷怨傷離。',32,'全唐诗/poet.tang.43000.json','["淚滿羅衣酒滿巵，一聲歌斷怨傷離。", "如今兩地心中事，直是瞿曇也不知。"]'),
('b6437c34-9a3d-4b3b-b540-37f4aa79f8e8','惆悵詩九首 九','顧甄遠','唐','唐诗','tang','','[]','橫泥杯觴醉復醒，愁牽時有小詩成。',32,'全唐诗/poet.tang.43000.json','["橫泥杯觴醉復醒，愁牽時有小詩成。", "早知惹得千般恨，悔不天生解薄情。"]'),
('9d5e324d-804a-492a-b9fb-aa7552eac045','登清居臺','魏巒','唐','唐诗','tang','','[]','迤邐清居臺，連延白雲外。',24,'全唐诗/poet.tang.43000.json','["迤邐清居臺，連延白雲外。", "側聆天上語，下視飛鳥背。"]'),
('231db098-b836-4d6f-be61-9af01afdd48e','游昌化精舍','柳明獻','唐','唐诗','tang','','[]','寶臺侵漢遠，金地接霞高。',24,'全唐诗/poet.tang.43000.json','["寶臺侵漢遠，金地接霞高。", "何必遊天外，忻此契盧敖。"]'),
('ecb05cce-2d14-4415-b734-60647ef2eaa8','善卷先生壇','蔡崑','唐','唐诗','tang','','[]','幾到壇邊登閣望，因思遺跡詠今朝。',32,'全唐诗/poet.tang.43000.json','["幾到壇邊登閣望，因思遺跡詠今朝。", "當時爲有重華出，不是先生傲帝堯。"]'),
('b5a73857-b6d8-4a4d-9a6e-3f4158ef51a2','句','蔡崑','唐','唐诗','tang','','[]','飄飄隨暮雨，颯颯落秋山。',12,'全唐诗/poet.tang.43000.json','["飄飄隨暮雨，颯颯落秋山。"]'),
('52f1f593-6365-46d8-a9b7-916ee86c0e90','題鄜州相思鋪','令狐挺','唐','唐诗','tang','','[]','誰把相思號此河，塞垣車馬往來多。',32,'全唐诗/poet.tang.43000.json','["誰把相思號此河，塞垣車馬往來多。", "只應自古征人淚，灑向空川作逝波。"]'),
('44759fb1-54f5-4277-88e2-906e1a6c94ac','鳳歸雲二首 一','滕潛','唐','唐诗','tang','','[]','金井欄邊見羽儀，梧桐枝上宿寒枝。',32,'全唐诗/poet.tang.43000.json','["金井欄邊見羽儀，梧桐枝上宿寒枝。", "五陵公子憐文彩，畫與佳人刺繡衣。"]'),
('b7501ed6-09a7-451e-8725-8519d1692a72','鳳歸雲二首 二','滕潛','唐','唐诗','tang','','[]','飲啄蓬山最上頭，和煙飛下禁城秋。',32,'全唐诗/poet.tang.43000.json','["飲啄蓬山最上頭，和煙飛下禁城秋。", "曾將弄玉歸雲去，金翿斜開十二樓。"]'),
('416ba3ce-61fe-4665-bcd8-d5dcef069342','藥圃','夏侯子雲','唐','唐诗','tang','','[]','綠葉紅英遍，僊經自討論。',24,'全唐诗/poet.tang.43000.json','["綠葉紅英遍，僊經自討論。", "偶移巖畔菊，鋤斷白雲根。"]'),
('b15fdd82-86cf-4656-ad17-254bcf5806a0','讀孝經','方愚','唐','唐诗','tang','','[]','星彩滿天朝北極，源流是處赴東溟。',32,'全唐诗/poet.tang.43000.json','["星彩滿天朝北極，源流是處赴東溟。", "爲臣爲子不忠孝，辜負宣尼一卷經。"]'),
('d357ebc8-1e93-4c76-88f9-1a3547d5baec','贈葛氏小娘子','潘雍','唐','唐诗','tang','','[]','曾聞仙子住天台，欲結靈姻媿短才。',32,'全唐诗/poet.tang.43000.json','["曾聞仙子住天台，欲結靈姻媿短才。", "若許隨君洞中住，不同劉阮卻歸來。"]'),
('67fa64fa-b2b7-48c0-bf26-565b9b1e53b3','送孫舍人歸湘州','梁陟','唐','唐诗','tang','','[]','盛才傾世重，清論滿朝歸。',48,'全唐诗/poet.tang.43000.json','["盛才傾世重，清論滿朝歸。", "作隼他年計，爲鴛此日飛。", "比肩移日近，抗首出郊畿。", "爲報清漳水，分明照錦衣。"]'),
('c7eece6b-5e73-4643-8b57-4eb825ea7fe4','再登河陽城懷古','朱延','唐','唐诗','tang','','[]','客遊倦旅思，憩駕陟崇墉。',48,'全唐诗/poet.tang.43000.json','["客遊倦旅思，憩駕陟崇墉。", "元凱標奇跡，安仁擅美蹤。", "遠近濁河流，出沒青山峰。", "佇想空不極，懷古悵無從。"]'),
('5f3f5f57-ae35-44bc-a3c5-eae1a86764a7','題瑩上人院','寇埴','唐','唐诗','tang','','[]','捨筏求香偈，因泉演妙音。',48,'全唐诗/poet.tang.43000.json','["捨筏求香偈，因泉演妙音。", "是明捐俗網，何獨在山林。", "繚繞藤軒密，逶迤竹徑深。", "爲傳同學志，茲宇可清心。"]'),
('8c747565-0818-4de3-b929-1faf9fcd9cc1','燕啣泥','馮渚','唐','唐诗','tang','','[]','雙燕碌碌飛入屋，屋中老人喜燕歸，裴回繞我牀頭飛。',108,'全唐诗/poet.tang.43000.json','["雙燕碌碌飛入屋，屋中老人喜燕歸，裴回繞我牀頭飛。", "去年爲爾逐黃雀，雨多屋漏泥土落。", "爾莫厭老翁茅屋低，梁頭作窠梁下棲。", "爾不見東家黃𪅏鳴嘖嘖，虵盤瓦溝鼠穿壁。", "豪家大屋爾莫居，驕兒少婦採爾雛。", "井旁寫水泥自足，啣泥上屋隨爾欲。"]'),
('4fed232a-097f-43f8-9f53-7bed49602af0','日暖萬年枝','王約','唐','唐诗','tang','','[]','靄靄彤庭裏，沈沈玉砌陲。',72,'全唐诗/poet.tang.43000.json','["靄靄彤庭裏，沈沈玉砌陲。", "初升九華日，潛暖萬年枝。", "煦嫗光偏好，青葱色轉宜。", "每因韶景麗，長沐惠風吹。", "隱映當龍闕，氛氳隔鳳池。", "朝陽光照處，唯有近臣知。"]'),
('a06f15f0-0c00-4503-86cb-66916821e0e0','日暖萬年枝','郭求','唐','唐诗','tang','','[]','旭日升溟海，芳枝散曙煙。',72,'全唐诗/poet.tang.43000.json','["旭日升溟海，芳枝散曙煙。", "溫仁臨樹久，煦嫗在條偏。", "陽德符君惠，嘉名表聖年。", "若承恩渥厚，常屬棟梁賢。", "生植雖依地，光華只信天。", "不才堪仄陋，徒望向榮先。"]'),
('af868c3a-69a9-425d-ba51-bfcea5bb6f44','日暖萬年枝','鄭師貞','唐','唐诗','tang','','[]','禁樹敷榮早，偏將麗日宜。',72,'全唐诗/poet.tang.43000.json','["禁樹敷榮早，偏將麗日宜。", "光搖連北闕，影泛滿南枝。", "得地方知照，逢時異赫曦。", "葉和盈數積，根是永年移。", "宵露猶殘潤，薰風更共吹。", "餘暉誠可託，況近鳳凰池。"]'),
('218797a3-a043-49fd-bd48-c0340ca0ef48','日華川上動','石殷士','唐','唐诗','tang','','[]','曙霞攢旭日，浮景弄晴川。',72,'全唐诗/poet.tang.43000.json','["曙霞攢旭日，浮景弄晴川。", "晃曜層潭上，悠揚極浦前。", "岸高時擁媚，波遠漸澄鮮。", "萍實空隨浪，珠胎不照淵。", "早暄依曲渚，微動觸輕漣。", "孰假咸池望，幽情得古篇。"]'),
('1e9df2ae-2597-482c-9f83-7d8f29503d58','聞擊壤','石殷士','唐','唐诗','tang','','[]','堯年聽野老，擊壤復何云。',72,'全唐诗/poet.tang.43000.json','["堯年聽野老，擊壤復何云。", "自謂歡由己，寧知德在君。", "氣平閑易暢，聲賀作難分。", "耕鑿方隨日，恩威比望雲。", "簣桴均下調，和木等南薰。", "無落於吾事，誰將帝力聞。"]'),
('02e148e9-c58a-4492-aafc-7d1617f088cb','初日照華清宮','柴宿','唐','唐诗','tang','','[]','靈山初照澤，遠近見離宮。',72,'全唐诗/poet.tang.43000.json','["靈山初照澤，遠近見離宮。", "影動參差裏，光分縹緲中。", "鮮飆收晚翠，佳氣滿晴空。", "林潤溫泉入，樓深複道通。", "璇題生烱晃，珠綴引𦝰朧。", "鳳輦何時幸，朝朝此望同。"]'),
('451339f4-5089-443c-a899-fcc85073519d','瑜不掩瑕','柴宿','唐','唐诗','tang','','[]','朗玉微瑕在，分明異璞瑜。',72,'全唐诗/poet.tang.43000.json','["朗玉微瑕在，分明異璞瑜。", "堅貞寧可雜，美惡自能殊。", "待價知彌久，稱忠定不誣。", "光輝今見黜，毫髮外呈符。", "豈假良工指，堪爲達士模。", "他山儻磨琢，慕愛是洪鑪。"]'),
('8c2e3ce4-3733-4d80-a046-ef515841595c','秋日懸清光','陶拱','唐','唐诗','tang','','[]','秋至雲容歛，天中日景清。',72,'全唐诗/poet.tang.43000.json','["秋至雲容歛，天中日景清。", "懸空寒色淨，委照曙光盈。", "泫泫看彌上，輝輝望最明。", "烟霞輪乍透，葵藿影初生。", "鑒下應無極，升高自有程。", "何當迴盛彩，一爲表精誠。"]'),
('3441db69-4620-4172-abb8-8fc971c8416e','三讓月成魄','劉𤤺','唐','唐诗','tang','','[]','爲禮依天象，周旋逐月成。',48,'全唐诗/poet.tang.43000.json','["爲禮依天象，周旋逐月成。", "教人三讓美，爲客一宵生。", "初進輪猶暗，終辭影漸明。", "幸陪賓主位，取捨任虧盈。"]'),
('d8ac2ba7-7fd5-4b3b-bfc1-80c305540538','海上生明月','朱華','唐','唐诗','tang','','[]','皎皎秋中月，團圓海上生。',72,'全唐诗/poet.tang.43000.json','["皎皎秋中月，團圓海上生。", "影開金鏡滿，輪抱玉壺清。", "漸出三山𡵒，將凌一漢橫。", "素娥嘗藥去，烏鵲遶枝驚。", "照水光偏白，浮雲色最明。", "此時堯砌下，蓂莢自將榮。"]'),
('04803420-1f5b-48f0-abba-2940006ba36b','月夜梧桐葉上見寒露','戴察','唐','唐诗','tang','','[]','蕭疎桐葉上，月白露初團。',72,'全唐诗/poet.tang.43000.json','["蕭疎桐葉上，月白露初團。", "滴瀝清光滿，熒煌素彩寒。", "風搖愁玉墜，枝動惜珠乾。", "氣冷疑秋晚，聲微覺夜闌。", "凝空流欲遍，潤物淨宜看。", "莫厭窺臨倦，將晞聚更難。"]'),
('647dd75f-1aac-421b-99d0-f2340cbd5f33','清露被臯蘭','孫顧','唐','唐诗','tang','','[]','九臯蘭葉茂，八月露華清。',72,'全唐诗/poet.tang.43000.json','["九臯蘭葉茂，八月露華清。", "稍與秋陰合，還將曉色幷。", "向空羅細影，臨水泫微明。", "的皪添幽興，芊綿動遠情。", "夕芳人未採，初降鶴先驚。", "爲感生成惠，心同葵藿傾。"]'),
('b1aee806-847b-4ece-aa92-d35007d6ed33','宿煙含白露','孫頠','唐','唐诗','tang','','[]','㭊㭊有新意，微微曙色幽。',72,'全唐诗/poet.tang.43000.json','["㭊㭊有新意，微微曙色幽。", "露含疎月淨，光與曉煙浮。", "迥野遙凝素，空林望已秋。", "著霜寒未結，凝葉滴還流。", "比玉偏清潔，如珠詎可收。", "裴回阡陌上，瞻想但淹留。"]'),
('9a9d66ce-8f64-4e4d-8e55-db4ae6930a88','送薛大夫和蕃','孫頠','唐','唐诗','tang','','[]','亞相獨推賢，乘軺向遠邊。',72,'全唐诗/poet.tang.43000.json','["亞相獨推賢，乘軺向遠邊。", "一心傾漢日，萬里望胡天。", "忠信皇恩重，要荒聖德傳。", "戎人方屈膝，塞月復嬋娟。", "別思流鶯晚，歸朝候雁先。", "當書外垣傳，迴奏赤墀前。"]'),
('d1e4a3b6-d543-4a9e-b882-3d549ea54129','風光草際浮','陳璀','唐','唐诗','tang','','[]','春風泛搖草，旭日遍神州。',72,'全唐诗/poet.tang.43000.json','["春風泛搖草，旭日遍神州。", "已向花間積，還來葉上浮。", "曉光緣圃麗，芳氣滿街流。", "澹蕩依朱萼，颻颺帶玉溝。", "向空看轉媚，臨水見彌幽。", "況被崇蘭色，王孫正可遊。"]'),
('5d0a0a78-ea03-4019-95e2-b78bf56c6d5f','風光草際浮','裴杞','唐','唐诗','tang','','[]','澹蕩和風至，芊綿碧草長。',72,'全唐诗/poet.tang.43000.json','["澹蕩和風至，芊綿碧草長。", "徐吹遙撲翠，半偃乍浮光。", "葉似翻宵露，藂疑扇夕陽。", "逶迤明曲渚，照耀滿迴塘。", "白芷生還暮，崇蘭泛更香。", "誰知攬結處，含思向餘芳。"]'),
('8af44a21-c183-4401-88cb-d0acc94e60cf','風光草際浮','陳祜','唐','唐诗','tang','','[]','香發王孫草，春生君子風。',72,'全唐诗/poet.tang.43000.json','["香發王孫草，春生君子風。", "光搖低偃處，影散豔陽中。", "稍稍移蘋末，微微轉蕙叢。", "浮煙傾綠野，遠色澹晴空。", "泛彩池塘媚，含芳景氣融。", "清暉誰不挹，幾許賞心同。"]'),
('d5b57f9a-e648-49e6-a9fb-8423b5b8d301','風光草際浮','吳秘','唐','唐诗','tang','','[]','草色春沙裏，風光曉正幽。',72,'全唐诗/poet.tang.43000.json','["草色春沙裏，風光曉正幽。", "輕明搖不散，郁昱麗仍浮。", "吹緩苗難轉，暉閑葉本柔。", "碧凝煙彩入，紅是日華流。", "耐可披襟對，誰應滿掬收。", "恭聞掇芳客，爲此尚淹留。"]'),
('d06f033a-f2dd-4220-9183-23c72c3ce227','風光草際浮','張復元','唐','唐诗','tang','','[]','纖纖春草長，遲日度風光。',72,'全唐诗/poet.tang.43000.json','["纖纖春草長，遲日度風光。", "靃靡含新彩，霏微籠遠芳。", "殊姿媚原野，佳色滿池塘。", "最好垂清露，偏宜帶豔陽。", "淺深浮嫩綠，輕麗拂餘香。", "好助鶯遷勢，乘時冀便翔。"]'),
('d91937ab-5cf5-44d3-9c14-5643edde669e','冬至日祥風應候','穆寂','唐','唐诗','tang','','[]','節逢清景至，占氣二儀中。',72,'全唐诗/poet.tang.43000.json','["節逢清景至，占氣二儀中。", "獨喜登臺日，先知應候風。", "呈祥光舜化，表慶感堯聰。", "既與乘時叶，還將入律同。", "微微萬井遍，習習九門通。", "更繞鑪煙起，殷勤報歲功。"]'),
('b5faeeb2-dd13-4ee4-8fbf-2c5b6581fb41','清風戒寒','穆寂','唐','唐诗','tang','','[]','風清物候殘，蕭灑報將寒。',72,'全唐诗/poet.tang.43000.json','["風清物候殘，蕭灑報將寒。", "掃得天衢靜，吹來眼界寬。", "條鳴方有異，蟲思亂無端。", "就樹收鮮膩，衝池起澀瀾。", "過山嵐可掬，度月色宜看。", "華實從茲始，何嗟歲序殫。"]'),
('709a5417-c173-4053-a93d-c0b8b99c7728','風草不留霜','王景中','唐','唐诗','tang','','[]','繁霜當永夜，寒草正驚風。',72,'全唐诗/poet.tang.43000.json','["繁霜當永夜，寒草正驚風。", "飄素衰蘋末，流光晚蕙叢。", "悠揚方泛影，皎潔却飛空。", "不定離披際，難凝蘙薈中。", "低昂閑散質，肅殺想成功。", "獨感玄暉詠，依依此夕同。"]'),
('28e74089-f68a-4a49-bd30-cc095f5030c9','春雲','鄧倚','唐','唐诗','tang','','[]','搖曳自西東，依林又逐風。',72,'全唐诗/poet.tang.43000.json','["搖曳自西東，依林又逐風。", "勢移青道裏，影泛綠波中。", "夕霽方明日，朝陽復蔽空。", "度關隨去馬，出塞引歸鴻。", "色任寒暄變，光將遠近同。", "爲霖如見用，還得助成功。"]'),
('4a3075d8-babf-4491-8b39-ed06a0a9416f','登雲梯','湯洙','唐','唐诗','tang','','[]','謝客常游處，層巒枕碧溪。',72,'全唐诗/poet.tang.43000.json','["謝客常游處，層巒枕碧溪。", "經過殊俗境，登陟象雲梯。", "步步勞山屐，行行躡澗霓。", "迥臨天路廣，俯眺夕陽低。", "賞詠情彌愜，風塵事已暌。", "前修如可慕，投足固思齊。"]'),
('827aca67-c59b-4bd8-aec4-920f427d649f','登雲梯','殷琮','唐','唐诗','tang','','[]','碧落遠澄澄，青山路可昇。',72,'全唐诗/poet.tang.43000.json','["碧落遠澄澄，青山路可昇。", "身輕疑易蹋，步獨覺難憑。", "邐迤排將近，迴翔勢漸登。", "上寧愁屈曲，高更喜超騰。", "江樹遙分藹，山嵐宛若凝。", "赤城容許到，敢憚百千層。"]'),
('a310c412-bcc5-4642-b824-0728a95b8351','秋山極天淨','朱延齡','唐','唐诗','tang','','[]','雨洗高秋淨，天臨大野閑。',72,'全唐诗/poet.tang.43000.json','["雨洗高秋淨，天臨大野閑。", "葱蘢清萬象，繚繞出層山。", "日落千峯上，雲銷萬壑間。", "綠蘿霜後翠，紅葉雨來殷。", "散彩輝吳甸，分形壓楚關。", "欲尋霄漢路，延首願登攀。"]'),
('2288e93c-1406-41e2-8eb0-fa0f3087e452','春臺晴望','鄭蕡','唐','唐诗','tang','','[]','追賞層臺迥，登臨四望頻。',72,'全唐诗/poet.tang.43000.json','["追賞層臺迥，登臨四望頻。", "熙熙山雨霽，處處柳條新。", "草長秦城夕，花明漢苑春。", "晴林翻去鳥，紫陌閱行人。", "旅客風塵厭，山家夢寐親。", "遷鶯思出谷，鶱翥待芳辰。"]'),
('dfd7859a-5ccb-49be-bf58-fe4effbcd1dc','天驥呈材','鄭蕡','唐','唐诗','tang','','[]','毛骨合天經，拳奇步驟輕。',72,'全唐诗/poet.tang.43000.json','["毛骨合天經，拳奇步驟輕。", "曾邀于闐駕，新出貳師營。", "噴勒金鈴響，追風汗血生。", "酒亭留去跡，吳坂認嘶聲。", "力可通衢試，材堪聖代呈。", "王良如故盻，垂耳欲長鳴。"]'),
('d568ec12-6d9e-4acf-9b8c-ea8d4e353c20','律中應鐘','裴元','唐','唐诗','tang','','[]','律窮方數寸，室暗在三重。',72,'全唐诗/poet.tang.43000.json','["律窮方數寸，室暗在三重。", "伶管灰先動，秦正節已逢。", "商聲辭玉笛，羽調入金鐘。", "密葉翻霜彩，輕冰歛水容。", "望鴻南去絕，迎氣北來濃。", "願託無凋性，寒林自比松。"]'),
('c27ad1ce-3f14-4970-b516-196ae4a2f2ee','閏月定四時','杜周士','唐','唐诗','tang','','[]','得閏因貞歲，吾君敬授時。',72,'全唐诗/poet.tang.43000.json','["得閏因貞歲，吾君敬授時。", "體元承夏道，推曆法堯咨。", "直取歸餘改，非如再失欺。", "葭灰初變律，斗柄正當離。", "寒暑功前定，春秋氣可推。", "更憐幽谷羽，鳴躍尚須期。"]'),
('2daee0b2-9317-4643-ab56-a4b62452083e','閏月定四時','樂伸','唐','唐诗','tang','','[]','聖代承堯曆，恆將閏正時。',72,'全唐诗/poet.tang.43000.json','["聖代承堯曆，恆將閏正時。", "六旬餘可借，四序應如期。", "分至寧愆素，盈虛信不欺。", "斗杓重指甲，灰琯再推離。", "羲氏兼和氏，行之又則之。", "願言符大化，永永作元龜。"]'),
('ce6f0cb6-e492-480e-a98b-2c3794970400','閏月定四時','徐至','唐','唐诗','tang','','[]','積數歸成閏，羲和職舊司。',72,'全唐诗/poet.tang.43000.json','["積數歸成閏，羲和職舊司。", "分銖標斗建，盈縮正人時。", "節候潛相應，星辰自合期。", "寸陰寧越度，長曆信無欺。", "定向銅壺辨，還從玉律推。", "高明終不謬，委鑑本無私。"]'),
('e5880a5b-23eb-4480-94a5-9630a958dd3a','新陽改故陰','紇干諷','唐','唐诗','tang','','[]','律管才推候，寒郊忽變陰。',72,'全唐诗/poet.tang.43000.json','["律管才推候，寒郊忽變陰。", "微和方應節，積慘已辭林。", "暗覺餘澌斷，潛驚麗景侵。", "禁城佳氣換，北陸翠煙深。", "有截知遐布，無私荷照臨。", "韶光如可及，鶯谷免幽沈。"]'),
('699277cd-b4fb-4601-926d-a973d9b363d1','春水綠波','朱休','唐','唐诗','tang','','[]','芳時淑氣和，春水澹煙波。',72,'全唐诗/poet.tang.43000.json','["芳時淑氣和，春水澹煙波。", "滉瀁滋蘭杜，淪漣長芰荷。", "晚光扶翠瀲，潭影寫青莎。", "歸雁追飛盡，纖鱗遊泳多。", "朝宗終到海，潤下每盈科。", "願假中流便，從茲發櫂歌。"]'),
('2fdeec9a-29f8-4c48-99cc-06bf1892071a','海水不揚波','李沛','唐','唐诗','tang','','[]','明朝崇大道，寰海免波揚。',72,'全唐诗/poet.tang.43000.json','["明朝崇大道，寰海免波揚。", "既合千年聖，能安百谷王。", "天心隨澤廣，水德共靈長。", "不撓魚彌樂，無瀾葦可航。", "化流霑率土，恩浸及殊方。", "豈只朝宗國，惟聞有越裳。"]'),
('79a8cdc5-efef-43d8-83aa-9278f6abc423','四水合流','李沛','唐','唐诗','tang','','[]','禹鑿山川地，因通四水流。',72,'全唐诗/poet.tang.43000.json','["禹鑿山川地，因通四水流。", "縈迴過鳳闕，會合出皇州。", "天影長波裏，寒聲古度頭。", "入河無晝夜，歸海有謙柔。", "順物宜投石，逢時可載舟。", "羨魚猶未已，臨水欲垂鉤。"]'),
('f623da90-5e65-4093-8c65-c482a78a90fb','登聖善寺閣望龍門','成㟧','唐','唐诗','tang','','[]','高閣聊登望，遙分禹鑿門。',72,'全唐诗/poet.tang.43000.json','["高閣聊登望，遙分禹鑿門。", "剎連多寶塔，樹滿給孤園。", "香境超三界，清流振陸渾。", "報慈弘孝理，行道得真源。", "空淨祥煙霽，時光受日溫。", "願從初地起，長奉下生尊。"]'),
('5ab71b92-9e7a-4f5e-a952-7f2d8ef399c5','秋霽望廬山瀑布','夏侯楚','唐','唐诗','tang','','["\u5e90\u5c71"]','常思瀑布幽，晴晀喜逢秋。',72,'全唐诗/poet.tang.43000.json','["常思瀑布幽，晴晀喜逢秋。", "一帶連青嶂，千尋倒碧流。", "濕雲應悞鶴，飜浪定驚鷗。", "星浦虹初下，爐峰煙未收。", "巖高時褭褭，天淨起悠悠。", "儻見朝宗日，還須濟巨舟。"]'),
('5238376f-7c3c-4fdf-a496-3e9fd7254e7d','濟川用舟檝','胡權','唐','唐诗','tang','','[]','渺渺水連天，歸程想幾千。',72,'全唐诗/poet.tang.43000.json','["渺渺水連天，歸程想幾千。", "孤舟辭曲岸，輕檝濟長川。", "迥指波濤雪，迴瞻島嶼煙。", "心迷滄海上，目斷白雲邊。", "泛濫雖無定，維持且自專。", "還如聖明代，理國用英賢。"]'),
('159dfda2-df2e-427b-9a37-0ef3ea06da85','洛出書','郭邕','唐','唐诗','tang','','[]','德合天貺呈，龍飛聖人作。',72,'全唐诗/poet.tang.43000.json','["德合天貺呈，龍飛聖人作。", "光宅被寰區，圖書薦河洛。", "象登四氣順，文闢九疇錯。", "氤氳瑞彩浮，左右靈儀廓。", "微造功不宰，神行利攸博。", "一見皇家慶，方知禹功薄。"]'),
('816b26fc-46d1-4670-8f02-8526f6cb3792','洛出書','張欽敬','唐','唐诗','tang','','[]','浮空九洛水，瑞聖千年質。',72,'全唐诗/poet.tang.43000.json','["浮空九洛水，瑞聖千年質。", "奇象八卦分，圖書九疇出。", "含微卜筮遠，抱數陰陽密。", "中得天地心，傍探鬼神吉。", "昔聞夏禹代，今獻唐堯日。", "謬此敘彝倫，寰宇賀清謐。"]'),
('fc0d5bc3-5d28-42fb-8ace-59ff9222840d','洛出書','叔孫玄觀','唐','唐诗','tang','','[]','清洛含溫溜，玄龜薦寶書。',72,'全唐诗/poet.tang.43000.json','["清洛含溫溜，玄龜薦寶書。", "波開綠字出，瑞應紫宸居。", "物著羣靈首，文成列卦初。", "美珍翔閣鳳，慶邁躍舟魚。", "俾姒惟何遠，休皇復在諸。", "東都主人意，歌頌望乘輿。"]'),
('52846318-0a58-4595-b3df-a6c3b1a6fdf9','玉壺冰','王季友','唐','唐诗','tang','','[]','玉壺知素結，止水復中澄。',72,'全唐诗/poet.tang.43000.json','["玉壺知素結，止水復中澄。", "堅白能虛受，清寒得自凝。", "分形同曉鏡，照物掩宵燈。", "璧映圓光入，人驚爽氣凌。", "金罍何足貴，瑤席幾回升。", "正值求珪瓚，提攜共飲冰。"]'),
('0a1bd1d7-792a-4bc0-b8ee-7c3cbf0e997c','美玉','南巨川','唐','唐诗','tang','','[]','抱玉將何適，良工正在斯。',72,'全唐诗/poet.tang.43000.json','["抱玉將何適，良工正在斯。", "有瑕寧自掩，匪石幸君知。", "雕琢嗟成器，緇磷志不移。", "飾罇光宴賞，入珮奉威儀。", "象德曾留記，如虹竊可奇。", "終希逢善價，還得桂林枝。"]'),
('2d21f515-a565-4c51-8ef2-703b1b7e7608','琢玉','丁居晦','唐','唐诗','tang','','[]','卞玉何時獻，初疑尚在荆。',72,'全唐诗/poet.tang.43000.json','["卞玉何時獻，初疑尚在荆。", "琢來聞制器，價衒勝連城。", "虹氣衝天白，雲浮入信貞。", "珮爲廉節德，杯作侈奢名。", "露璞方期辨，雕文幸既成。", "他山豈無石，寧及此時呈。"]'),
('b47b8db0-c2d6-44c3-86bb-aeb57db2cbd2','白珪無玷','辛宏','唐','唐诗','tang','','[]','片玉表堅貞，逢時寶自呈。',72,'全唐诗/poet.tang.43000.json','["片玉表堅貞，逢時寶自呈。", "色鮮同雪白，光潤奪冰清。", "皎皎無瑕玷，鏘鏘有珮聲。", "崑山標重價，垂棘振香名。", "抱璞心常苦，全真道未行。", "琢磨忻大匠，還冀動連城。"]'),
('1756a5ca-ccc8-4132-8b74-107f3f2a44d6','鮫人潛織','康翊仁','唐','唐诗','tang','','[]','珠館馮夷室，靈鮫信所潛。',72,'全唐诗/poet.tang.43000.json','["珠館馮夷室，靈鮫信所潛。", "幽閑雲碧牖，滉瀁水精簾。", "機動龍梭躍，絲縈藕淬添。", "七襄牛女恨，三日大人嫌。", "透手擊吳練，凝冰笑越縑。", "無因聽札札，空想濯纖纖。"]'),
('96b06cda-b50c-4082-b840-589ec8df9b9c','瑕瑜不相掩','陳中師','唐','唐诗','tang','','[]','出石溫然玉，瑕瑜素在中。',72,'全唐诗/poet.tang.43000.json','["出石溫然玉，瑕瑜素在中。", "妍媸因異彩，音韻信殊風。", "讓美心方竝，求疵意本同。", "光華開縝密，清潤仰磨礱。", "秀質非攘善，貞姿肯廢忠。", "今來儻成器，分別在良工。"]'),
('845ae1dd-9719-47fe-8d9c-fd9ea02ee06b','戛玉有餘聲','管雄甫','唐','唐诗','tang','','[]','戛玉音難盡，凝人思轉清。',72,'全唐诗/poet.tang.43000.json','["戛玉音難盡，凝人思轉清。", "依稀流戶牖，髣髴在簷楹。", "更逐松風起，還將澗水幷。", "樂中和舊曲，天際轉餘聲。", "漂渺浮煙遠，溫柔入耳輕。", "想如君子佩，時得上堂鳴。"]'),
('1fb288d8-2f69-4c73-9be3-66d96f1555dc','珠還合浦','鄧陟','唐','唐诗','tang','','[]','至寶含沖粹，清虛映浦灣。',72,'全唐诗/poet.tang.43000.json','["至寶含沖粹，清虛映浦灣。", "素輝明蕩漾，圓彩色玢㻞。", "昔逐諸侯去，今隨太守還。", "影搖波裏月，光動水中山。", "魚目徒相比，驪龍乍可攀。", "願將車飾用，長得耀君顏。"]'),
('ee030f15-d143-4389-a74a-365493e254b7','濁水求珠','呂價','唐','唐诗','tang','','[]','至寶誠難得，潛光在濁流。',72,'全唐诗/poet.tang.43000.json','["至寶誠難得，潛光在濁流。", "深沈當處晦，皎潔庶來求。", "綴履將還用，褰裳必更收。", "蚌胎應自別，魚目豈能儔。", "日彩逢高鑒，星光詎暗投。", "不因今日取，泥滓出無由。"]'),
('e983c9f5-8294-4a13-a963-9ab6a6263690','暗投明珠','苑䛆','唐','唐诗','tang','','[]','至寶欣懷日，良茲豈可儔。',72,'全唐诗/poet.tang.43000.json','["至寶欣懷日，良茲豈可儔。", "神光非易鑒，夜色信難投。", "錯落珍寰宇，圓明隔淺流。", "精靈辭合浦，素彩耀神州。", "抱影希人識，承時望帝求。", "誰言按劒者，猜忌却生讐。"]'),
('60d6657f-858d-4e9e-b239-b3f2c50fa265','暗投明珠','羅泰','唐','唐诗','tang','','[]','媚川時未識，在掌共傳名。',72,'全唐诗/poet.tang.43000.json','["媚川時未識，在掌共傳名。", "報德能欺暗，投人自欲明。", "月臨幽室朗，星沒曉河傾。", "的皪驪龍頷，熒煌彩鳳呈。", "守恩辭合浦，擅美掩連城。", "魚目應難近，誰知按劒情。"]'),
('706fcbe2-210b-4051-bdb0-5a98d8f8bd9d','暗投明珠','崔藩','唐','唐诗','tang','','[]','至寶看懷袖，明珠出後收。',72,'全唐诗/poet.tang.43000.json','["至寶看懷袖，明珠出後收。", "向人光不定，離掌勢難留。", "皎澈虛臨夜，孤圓冷瑩秋。", "乍來驚月落，疾轉怕星流。", "有淚甘瑕棄，無媒自暗投。", "今朝感恩處，將欲報隋侯。"]'),
('280781cf-06b6-4862-84b2-9c6fc6ff16d7','泗濱得石磬','李勳','唐','唐诗','tang','','[]','浮磬潛清深，依依呈碧潯。',72,'全唐诗/poet.tang.43000.json','["浮磬潛清深，依依呈碧潯。", "出水見貞質，在懸含玉音。", "對此喜還歎，幾秋還到今。", "器古契良覿，韻和諧宿心。", "何爲值明鑒，適得離幽沈。", "自茲入清廟，無復泥沙侵。"]'),
('88c72130-515b-42be-8313-6b9dccadaf16','玄元皇帝應見賀聖祚無疆','趙鐸','唐','唐诗','tang','','[]','聖主今司契，神功格上玄。',98,'全唐诗/poet.tang.43000.json','["聖主今司契，神功格上玄。", "豈唯求[傅]野，更有叶鈞天。", "審夢西山下，焚香北闕前。", "道光尊聖日，福應集靈年。", "咫尺真容近，巍峩大象懸。", "觴從百寮獻，形爲萬方傳。", "聲教唯皇矣，英威固邈然。", "慚無美周頌，徒上祝堯篇。"]'),
('ee392d1d-7b31-400d-8ccd-fd7ee2e8a258','太常寺觀舞聖壽樂','徐元鼎','唐','唐诗','tang','','[]','舞字傳新慶，人文邁舊章。',72,'全唐诗/poet.tang.43000.json','["舞字傳新慶，人文邁舊章。", "沖融和氣洽，悠遠聖功長。", "盛德流無外，明時樂未央。", "日華增顧眄，風物助低昂。", "翥鳳方齊首，高鴻忽斷行。", "雲門與茲曲，同是奉陶唐。"]'),
('e9069ce9-e769-4a7e-9d3f-49b344f90a54','太清宮聞滴漏','嚴巨川','唐','唐诗','tang','','[]','玉漏移中禁，齊車入太清。',72,'全唐诗/poet.tang.43000.json','["玉漏移中禁，齊車入太清。", "漸知催辨色，復聽續餘聲。", "乍逐微風轉，時因雜珮輕。", "青樓人罷夢，紫陌騎將行。", "殘魄棲初盡，餘寒滴更生。", "慚非朝謁客，空有振衣情。"]'),
('1cab6dab-3218-4ea4-9a4e-8303d0e99782','仲秋太常寺觀公卿輅車拜陵','嚴巨川','唐','唐诗','tang','','[]','南呂初開律，金風已戒涼。',72,'全唐诗/poet.tang.43000.json','["南呂初開律，金風已戒涼。", "拜陵將展敬，車輅儼成行。", "士庶觀祠禮，公卿習舊章。", "郊原佳氣引，園寢瑞煙長。", "鹵簿辭丹闕，威儀列太常。", "聖心何所寄，惟德在無忘。"]'),
('ba485e79-4621-40fd-89d8-7c33ca2aa7f1','貢舉人謁先師聞雅樂','呂炅','唐','唐诗','tang','','[]','禮聖來羣彥，觀光在此時。',72,'全唐诗/poet.tang.43000.json','["禮聖來羣彥，觀光在此時。", "聞歌音乍遠，合樂和還遲。", "調朗能諧竹，聲微又契絲。", "輕泠流簨簴，繚繞動纓緌。", "九變將隨節，三終必盡儀。", "國風由是正，王化自雍熙。"]'),
('9a3087bf-84cc-497d-918a-436f37cc31c0','望凌煙閣','劉公興','唐','唐诗','tang','','[]','畫閣凌虛搆，遙瞻在九天。',72,'全唐诗/poet.tang.43000.json','["畫閣凌虛搆，遙瞻在九天。", "丹楹崇壯麗，素壁繪勳賢。", "靄靄浮元氣，亭亭出瑞煙。", "近看分百辟，遠揖誤羣仙。", "圖列青雲外，儀刑紫禁前。", "望中空霽景，驤首幾留連。"]'),
('5a8fee4b-0706-4947-8b9e-f116eea3373f','觀北番謁廟','王卓','唐','唐诗','tang','','[]','肅肅層城裏，巍巍祖廟清。',96,'全唐诗/poet.tang.43000.json','["肅肅層城裏，巍巍祖廟清。", "聖恩覃布濩，異域獻精誠。", "冠蓋分行列，戎夷變姓名。", "禮終齊百拜，心潔盡忠貞。", "瑞氣千重色，簫韶九奏聲。", "仗移迎日轉，斾動逐風輕。", "休運威儀盛，豐年俎豆盈。", "不堪慚頌德，空此望簪纓。"]'),
('16dd0637-0bcc-4759-b064-776da70f2563','舞干羽兩階','石倚','唐','唐诗','tang','','[]','干羽能柔遠，前階舞正陳。',72,'全唐诗/poet.tang.43000.json','["干羽能柔遠，前階舞正陳。", "欲稱文德盛，先表樂聲新。", "肅肅行初列，森森氣益振。", "動容和律呂，變曲靜風塵。", "化美超千古，恩波及七旬。", "已知天下服，不獨有苗人。"]'),
('2d01852e-e3fa-416a-82ff-cff069998185','御製段太尉碑','葉元良','唐','唐诗','tang','','[]','多難全高節，時清軫聖君。',72,'全唐诗/poet.tang.43000.json','["多難全高節，時清軫聖君。", "園塋標石篆，雨露降天文。", "義激忠貞沒，詞傷蘭蕙焚。", "國人皆墮淚，王府已銘勳。", "揭出臨新陌，長留對古墳。", "睿情幽感處，應使九泉聞。"]'),
('373093db-3cd8-47a0-9b39-0aefcd2e7665','恩賜魏文貞公諸孫舊第以導直臣','裴大章','唐','唐诗','tang','','[]','邢茅雖舊錫，邸第是初榮。',72,'全唐诗/poet.tang.43000.json','["邢茅雖舊錫，邸第是初榮。", "迹往傷遺事，恩深感直聲。", "雲孫方慶襲，池館忽春生。", "古甃開泉井，新禽繞畫楹。", "自然垂帶礪，況復激忠貞。", "必使千年後，長書竹帛名。"]'),
('91ce82d0-8ae8-40ef-9d4e-6194323b8e0e','恩賜耆老布帛','崔宗','唐','唐诗','tang','','[]','渙汗中天發，殊私海外存。',72,'全唐诗/poet.tang.43000.json','["渙汗中天發，殊私海外存。", "衰顏逢聖代，華髮受皇恩。", "燭物明堯日，垂衣闢禹門。", "惜時悲落景，賜帛慰餘魂。", "厚澤沾祥詠，微生保子孫。", "盛明今尚齒，歡洽九衢罇。"]'),
('2cbb0e31-91ab-4f39-bc03-2907b59ba12e','東都父老望幸','鄭馥','唐','唐诗','tang','','[]','鑾輿秦地久，羽衛洛陽空。',96,'全唐诗/poet.tang.43000.json','["鑾輿秦地久，羽衛洛陽空。", "彼土雖憑固，茲川乃得中。", "龍顏覲白日，鶴髮仰清風。", "望幸誠逾邈，懷來意不窮。", "昔因封泰岳，今佇躡維嵩。", "天地心無異，神祇理亦同。", "翠華翔渭北，玉檢候關東。", "衆願其難阻，明君早勒功。"]'),
('47c36bbc-9c5d-474e-a665-96380be371b7','言行相顧','吳叔達','唐','唐诗','tang','','[]','聖人垂政教，萬古請常傳。',72,'全唐诗/poet.tang.43000.json','["聖人垂政教，萬古請常傳。", "立志言爲本，修身行乃先。", "相須寧得闕，相顧在無偏。", "榮辱當於己，忠貞必動天。", "大名如副寶，至道亦通玄。", "千里猶能應，何云邇者焉。"]'),
('8a3c4291-c6ef-4103-9530-5451427b0910','言行相顧','孟翺','唐','唐诗','tang','','[]','將使言堪復，常聞行欲先。',72,'全唐诗/poet.tang.43000.json','["將使言堪復，常聞行欲先。", "比珪斯不玷，修己直如弦。", "跬步非全進，吹噓稟自然。", "當令夫子察，無宿仲由賢。", "正遇興邦際，因懷入署年。", "坐知清監下，相顧有人焉。"]'),
('11210021-3b5c-4722-92cf-f13791de36df','人不易知','鄭昉','唐','唐诗','tang','','[]','如面誠非一，深心豈易知。',96,'全唐诗/poet.tang.43000.json','["如面誠非一，深心豈易知。", "入秦書十上，投楚歲三移。", "和玉翻爲泣，齊竽或濫吹。", "周行雖有寘，殷鑒在前規。", "寅亮推多士，清通固賞奇。", "病諸方號哲，敢相反成疵。", "冬日承餘愛，霜雲喜暫披。", "無令見瞻後，迴照復云疲。"]'),
('695fd1e1-d269-47cc-b763-281bcca61505','早春送郎官出宰','袁求賢','唐','唐诗','tang','','[]','仙郎今出宰，聖主下憂民。',72,'全唐诗/poet.tang.43000.json','["仙郎今出宰，聖主下憂民。", "紫陌軒車送，丹墀雨露新。", "趨程猶犯雪，行縣正逢春。", "粉署時迴首，銅章已在身。", "鳴琴化欲展，起草戀空頻。", "今日都門外，悠悠別漢臣。"]'),
('5860e1df-75d6-4ffd-827f-2e41b9d12468','餞王將軍赴雲中','孟匡明','唐','唐诗','tang','','[]','一師憑廟畧，分閫佐元戎。',72,'全唐诗/poet.tang.43000.json','["一師憑廟畧，分閫佐元戎。", "勢亞彤弓寵，時推金印雄。", "關山橫代北，旌節壯河東。", "日轉前茅影，春生細柳風。", "飲冰君命速，揮涕餞筵空。", "佇聽陰山靜，誰爭萬里功。"]'),
('6bcc0e82-0463-4d75-b1ba-b433de5f0172','西戎即敘','李子昂','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','懸首藁街中，天兵破犬戎。',96,'全唐诗/poet.tang.43000.json','["懸首藁街中，天兵破犬戎。", "營收低隴月，旗偃度湟風。", "肅殺三邊勁，蕭條萬里空。", "元戎咸服罪，餘孽盡輸忠。", "聖理符軒化，仁恩契禹功。", "降逾洞庭險，梟擬郅支窮。", "已散軍容捷，還資廟算通。", "今朝觀即敘，非與獻獒同。"]'),
('95be36d7-c16c-4180-bc4f-02a21d195c5e','禁中春松','員南溟','唐','唐诗','tang','','[]','鬱鬱貞松樹，陰陰在紫宸。',72,'全唐诗/poet.tang.43000.json','["鬱鬱貞松樹，陰陰在紫宸。", "蔥蘢偏近日，青翠更宜春。", "雅韻風來起，輕煙霽後新。", "葉深棲語鶴，枝亞拂朝臣。", "全節長依地，凌雲欲致身。", "山苗蔭不得，生植荷陶鈞。"]'),
('04543aec-e5d7-4f0d-9aab-12729628de8e','玉燭','員南溟','唐','唐诗','tang','','[]','曆象璿璣正，休徵玉燭明。',72,'全唐诗/poet.tang.43000.json','["曆象璿璣正，休徵玉燭明。", "四時佳氣滿，五緯太階平。", "律呂風光至，煙雲瑞色呈。", "年和知歲稔，道泰喜秋成。", "寰海皇恩被，乾坤至化清。", "自憐同野老，帝力詎能名。"]'),
('fe98dde4-a7a5-4654-94d9-6d7d964c473e','文宣王廟古松','李胄','唐','唐诗','tang','','[]','列植成均裏，分行古廟前。',72,'全唐诗/poet.tang.43000.json','["列植成均裏，分行古廟前。", "陰森非一日，蒼翠自何年。", "寒影煙霜暗，晨光枝葉妍。", "近簷陰更靜，臨砌色相鮮。", "每愧聞鐘磬，多慚接豆籩。", "更宜教胄子，於此學貞堅。"]'),
('41372553-e1d9-4f4e-ae73-99b636159134','華林園早梅','鄭述誠','唐','唐诗','tang','','[]','曉日東樓路，林端見早梅。',72,'全唐诗/poet.tang.43000.json','["曉日東樓路，林端見早梅。", "獨凌寒氣發，不逐衆花開。", "素彩風前豔，韶光雪後催。", "蘂香霑紫陌，枝亞拂青苔。", "止渴曾爲用，和羹舊有才。", "含情欲攀折，瞻望幾裴回。"]'),
('9fd37ade-73a8-4c75-9c6b-8dbb4d973486','龍池春草','宋迪','唐','唐诗','tang','','[]','鳳闕韶光遍，龍池草色勻。',72,'全唐诗/poet.tang.43000.json','["鳳闕韶光遍，龍池草色勻。", "煙波全讓綠，堤柳不爭新。", "翻葉迎紅日，飄香借白蘋。", "幽姿偏占暮，芳意欲留春。", "已勝生金埓，長思藉玉輪。", "翠華如見幸，正好及茲辰。"]'),
('8c774ffa-39b3-407d-8131-e5883dbf5d1b','龍池春草','万俟造','唐','唐诗','tang','','[]','暖積龍池綠，晴連御苑春。',72,'全唐诗/poet.tang.43000.json','["暖積龍池綠，晴連御苑春。", "迎風莖未偃，裛露色猶新。", "苒苒分階砌，離離雜荇蘋。", "細叢依遠渚，疎影落輕淪。", "遲引縈花蝶，偏宜拾翠人。", "那憐獻賦者，惆悵惜茲辰。"]'),
('79aa98c9-e800-47ff-a9b7-1b993d2ae05b','貢院樓北新栽小松','錢衆仲','唐','唐诗','tang','','[]','愛此凌霜操，移來獨占春。',72,'全唐诗/poet.tang.43000.json','["愛此凌霜操，移來獨占春。", "貞心初得地，勁節始依人。", "籠月煙猶薄，當軒色轉新。", "枝低無宿羽，葉靜不留塵。", "每與芝蘭近，常慙雨露均。", "幸因逢顧盼，生植及茲辰。"]'),
('f97571bd-2817-4661-80f4-fb88f6ac0461','玉壺冰','錢衆仲','唐','唐诗','tang','','[]','冬律初陰結，寒冰貯玉壺。',72,'全唐诗/poet.tang.43000.json','["冬律初陰結，寒冰貯玉壺。", "霜姿雖異稟，虹氣亦相符。", "對月光宜竝，臨池影不孤。", "貞堅方共濟，同處豈殊途。", "色瑩連城璧，形分照乘珠。", "提攜今在此，抱素節寧渝。"]'),
('7c2d7e4b-a065-4bda-8246-c9105fa92d7f','潘安仁戴星看河陽花發','呂敞','唐','唐诗','tang','','[]','行春潘令至，勤恤戴星光。',72,'全唐诗/poet.tang.43000.json','["行春潘令至，勤恤戴星光。", "爲政宵忘寢，臨人俗冀康。", "曉花迎徑發，新蘂滿城香。", "秀色霑輕露，鮮輝麗早陽。", "津橋見來往，空霧拂衣裳。", "桃李今無數，從茲願比方。"]'),
('1547b022-a776-43d1-a0c5-9518849a4427','龜茲聞鶯','呂敞','唐','唐诗','tang','','[]','邊樹正參差，新鶯復陸離。',72,'全唐诗/poet.tang.43000.json','["邊樹正參差，新鶯復陸離。", "嬌非胡俗變，啼是漢音移。", "繡羽花間覆，繁聲風外吹。", "人言曾不辨，鳥語却相知。", "出谷情何寄，遷喬義取斯。", "今朝鄉陌伴，幾處坐高枝。"]'),
('21d09fe6-cc93-4368-a86e-f685324f6ff6','好鳥鳴高枝','鄭衮','唐','唐诗','tang','','[]','養翮非無待，遷喬信自卑。',72,'全唐诗/poet.tang.43000.json','["養翮非無待，遷喬信自卑。", "影高遲日度，聲遠好風隨。", "雲拂千尋直，花催百囀奇。", "驚人時向晚，求友聽應知。", "委質經三歲，先鳴在一枝。", "上林如可托，弱羽願差池。"]'),
('712eb10c-2b04-48b9-a948-c018e73811fc','金谷園花發懷古','張公乂','唐','唐诗','tang','','[]','今日春風至，花開石氏園。',72,'全唐诗/poet.tang.43000.json','["今日春風至，花開石氏園。", "未全紅豔折，半與素光翻。", "點綴疎林遍，微明古徑繁。", "窺臨鶯欲語，寂寞李無言。", "谷變迷鋪錦，臺餘認樹萱。", "川流人事共，千載竟誰論。"]'),
('e52d049b-48e6-4ef5-827c-d6f8ca1a9101','織鳥','張何','唐','唐诗','tang','','[]','季春三月裏，戴勝下桑來。',72,'全唐诗/poet.tang.43000.json','["季春三月裏，戴勝下桑來。", "映日華冠動，迎風繡羽開。", "候驚蠶事晚，織向女工裁。", "旅宿依花定，輕飛遶樹迴。", "欲過高閣柳，更拂小庭梅。", "所寄一枝在，寧憂弋者猜。"]'),
('36061c40-4244-414e-b100-5053aad3a53b','出籠鶻','濮陽瓘','唐','唐诗','tang','','[]','玉鏃分花袖，金鈴出綵籠。',72,'全唐诗/poet.tang.43000.json','["玉鏃分花袖，金鈴出綵籠。", "搖心長捧日，逸翰鎮生風。", "一點青霄裏，千聲碧落中。", "星眸隨狡兔，霜爪落飛鴻。", "每念提攜力，常懷搏擊功。", "以君能惠好，不敢沒遙空。"]'),
('269d9b2b-9585-49e6-a4cc-8df405285e73','試越裳貢白雉','王若嵒','唐','唐诗','tang','','[]','素翟宛昭彰，遙遙自越裳。',72,'全唐诗/poet.tang.43000.json','["素翟宛昭彰，遙遙自越裳。", "冰晴朝映日，玉羽夜含霜。", "歲月三年遠，山川九澤長。", "來從碧海路，入見白雲鄉。", "作瑞興周后，登歌美漢皇。", "朝天資孝理，惠化且無疆。"]'),
('a42bcd2a-2b00-46e3-8e8a-e442618b1e73','勅賜三相馬','張隨','唐','唐诗','tang','','[]','上苑驊騮出，中宮詔命傳。',72,'全唐诗/poet.tang.43000.json','["上苑驊騮出，中宮詔命傳。", "九天班錫禮，三相代勞年。", "顧主聲猶發，追風力正全。", "鳴珂龍闕下，噴玉鳳池前。", "四足疑雲滅，雙瞳比鏡懸。", "爲因能致遠，今日表求賢。"]'),
('a8193c82-c72c-4fee-a840-d962c43548a3','河中獻捷','張隨','唐','唐诗','tang','','[]','叛將忘恩久，王師不戰通。',72,'全唐诗/poet.tang.43000.json','["叛將忘恩久，王師不戰通。", "凱歌千里內，喜氣二儀中。", "寇盡條山下，兵迴漢苑東。", "將軍初執訊，明主欲論功。", "落日煙塵靜，寒郊壁壘空。", "蒼生幸無事，自此樂堯風。"]'),
('68ae46d8-db38-45fc-af5d-bf118af7bcbc','天驥呈材','徐仁嗣','唐','唐诗','tang','','[]','至德符天道，龍媒應聖明。',72,'全唐诗/poet.tang.43000.json','["至德符天道，龍媒應聖明。", "追風奇質異，噴玉彩毛輕。", "躞蹀形難狀，連拳勢乍呈。", "効材矜逸態，絕影表殊名。", "岐路寧辭遠，關山豈憚行。", "鹽車雖不駕，今日亦長鳴。"]'),
('9af30ac8-5dd8-43bf-bb26-53968e3f07e7','天驥呈材','盧征','唐','唐诗','tang','','[]','異產應堯年，龍媒順制牽。',72,'全唐诗/poet.tang.43000.json','["異產應堯年，龍媒順制牽。", "權奇初得地，躞蹀欲行天。", "詎假調金埒，寧須動玉鞭。", "嘶風深有戀，逐日定無前。", "周滿誇常馭，燕昭恨不傳。", "應知流赭汗，來自海西偏。"]'),
('3ee5acee-aed5-4f5e-a352-0c7e81c33cd4','雲夜聽猨吟','顧偉','唐','唐诗','tang','','[]','寒巖飛暮雪，絕壁夜猨吟。',72,'全唐诗/poet.tang.43000.json','["寒巖飛暮雪，絕壁夜猨吟。", "歷歷和羣雁，寥寥思客心。", "繞枝猶避箭，過嶺却投林。", "風冷聲偏苦，山寒響更深。", "聽時無有定，靜裏固難尋。", "一宿扶桑月，聊看懷好音。"]'),
('772cebf1-5025-4f38-9d1a-b7301d8b1fec','寒蟬樹','沈鵬','唐','唐诗','tang','','[]','一葉初飛日，寒蟬益易驚。',72,'全唐诗/poet.tang.43000.json','["一葉初飛日，寒蟬益易驚。", "入林慙織細，依樹媿身輕。", "大幹時容息，喬枝或借鳴。", "心由飲露靜，響爲逐風清。", "忝有翩翾分，應憐嘒唳聲。", "不知微薄影，早晚挂緌纓。"]'),
('a87eb3ba-764c-4568-bf8f-710002b9e154','臨川羨魚','薛少殷','唐','唐诗','tang','','[]','曾是歸家客，今年且未旋。',72,'全唐诗/poet.tang.43000.json','["曾是歸家客，今年且未旋。", "遊鱗方有待，織網豈能捐。", "向水煙波夕，吟風歲月遷。", "莓苔生古岸，葭菼變清川。", "不逐滄波叟，還宗內外篇。", "良辰難自擲，此日願忘筌。"]'),
('adf5c241-a413-40ac-a83e-bc5345fabbbc','臨川羨魚','張元正','唐','唐诗','tang','','[]','有客百愁侵，求魚正在今。',72,'全唐诗/poet.tang.43000.json','["有客百愁侵，求魚正在今。", "廣川何渺漫，高岸幾登臨。", "風水寧相阻，煙霞豈憚深。", "不應同逐鹿，詎肯比從禽。", "結網非無力，忘筌自有心。", "永存芳餌在，佇立思沈沈。"]'),
('d6331791-3b3b-49f0-a08e-90f43c1fec60','荅王無功入長安詠秋蓬見示','辛學士','唐','唐诗','tang','','[]','托根雖異所，飄葉早相依。',24,'全唐诗/poet.tang.43000.json','["托根雖異所，飄葉早相依。", "因風若有便，更共入雲飛。"]'),
('b416ce8e-4855-4983-9856-0e7925285ca6','哭李遠','盧尚書','唐','唐诗','tang','','[]','昨日舟還浙水湄，今朝丹旐欲何爲。',64,'全唐诗/poet.tang.43000.json','["昨日舟還浙水湄，今朝丹旐欲何爲。", "纔收北浦一竿釣，未了西齋半局棊。", "洛下已傳平子賦，臨川爭寫謝公詩。", "不堪舊里經行處，風木蕭蕭鄰笛悲。"]'),
('54b2743f-7ccb-477e-aa67-ca75ad73f933','湘中怨諷','鄭僕射','唐','唐诗','tang','','[]','青鷁苦幽獨，隔江相對稀。',24,'全唐诗/poet.tang.43000.json','["青鷁苦幽獨，隔江相對稀。", "夜寒蘆葉雨，空作一聲歸。"]'),
('da767889-3e56-488a-abb5-cf3c7a954ac8','登汾上閣','鄭中丞','唐','唐诗','tang','','[]','汾桂秋水闊，宛似到閶門。',24,'全唐诗/poet.tang.43000.json','["汾桂秋水闊，宛似到閶門。", "惆悵江湖思，惟將南客論。"]'),
('797359d4-7b87-457b-88bb-5998760e42b4','爲御史銜命出關讞獄道中看華山有詩','韓常侍','唐','唐诗','tang','','[]','野麋蒙象暫如犀，心不驚鷗角駭雞。',32,'全唐诗/poet.tang.43000.json','["野麋蒙象暫如犀，心不驚鷗角駭雞。", "一路好山無伴看，斷腸煙景寄猨啼。"]'),
('fd2a1d78-f91a-4084-b818-929fb76a3807','寄織錦篇與薛郎中','韓常侍','唐','唐诗','tang','','[]','錦字龍梭織錦篇，鳳皇文采間非煙。',32,'全唐诗/poet.tang.43000.json','["錦字龍梭織錦篇，鳳皇文采間非煙。", "並他時世新花樣，虛費工夫不直錢。"]'),
('d473c537-1d3a-47f5-bd23-2ac19d730adc','和人憶鶴','韓常侍','唐','唐诗','tang','','[]','拂拂雲衣冠紫煙，已爲丁令一千年。',32,'全唐诗/poet.tang.43000.json','["拂拂雲衣冠紫煙，已爲丁令一千年。", "留君且伴居山客，幸有松梢明月天。"]'),
('3cc4ddd2-57bc-4d5e-859c-b77437537497','句','韓常侍','唐','唐诗','tang','','[]','情多不似家山水，夜夜聲聲旁枕流。',16,'全唐诗/poet.tang.43000.json','["情多不似家山水，夜夜聲聲旁枕流。"]'),
('31773c95-527b-4174-adf7-e69aa3fdbdc8','贈米都知','梁補闕','唐','唐诗','tang','','[]','供奉三朝四十年，聖時流落髮衰殘。',32,'全唐诗/poet.tang.43000.json','["供奉三朝四十年，聖時流落髮衰殘。", "貪將樂府歌明代，不把清吟換好官。"]'),
('ccbd3c97-e050-461c-9167-2dd3d7283a84','題安國觀','盧尚書','唐','唐诗','tang','','[]','夕照紗窗起暗塵，青松遶殿不知春。',32,'全唐诗/poet.tang.43000.json','["夕照紗窗起暗塵，青松遶殿不知春。", "君看白首誦經者，半是宮中歌舞人。"]'),
('65606422-0e3f-4983-a7db-e6b68f3c6c1b','自商山宿隱居','蘇廣文','唐','唐诗','tang','','[]','聞道桃源堪避秦，尋幽數日不逢人。',64,'全唐诗/poet.tang.43000.json','["聞道桃源堪避秦，尋幽數日不逢人。", "煙霞洞裏無雞犬，風雨林中有鬼神。", "黃公石上三芝秀，陶令門前五柳春。", "醉臥白雲閑入夢，不知何物是吾身。"]'),
('e6dacbc1-e355-4e5f-8cc4-6645eca8acc6','夜歸華川因寄幕府','蘇廣文','唐','唐诗','tang','','[]','山村寥落野人稀，竹裏衡門掩翠微。',64,'全唐诗/poet.tang.43000.json','["山村寥落野人稀，竹裏衡門掩翠微。", "溪路夜隨明月入，亭臯春伴白雲歸。", "嵇康懶慢仍耽酒，范蠡逋逃又拂衣。", "汀畔數鷗閑不起，只應知我已忘機。"]'),
('d9ab5e33-655c-44b0-8b70-46217142d1fe','春日過田明府遇焦山人','蘇廣文','唐','唐诗','tang','','[]','陶公歸隱白雲溪，買得春泉溉藥畦。',64,'全唐诗/poet.tang.43000.json','["陶公歸隱白雲溪，買得春泉溉藥畦。", "夜靜林間風虎嘯，月明竹上露禽棲。", "陳倉邑吏驚烽火，太白山人訝鼓鼙。", "相見只言秦漢事，武陵溪裏草萋萋。"]'),
('559906a6-ebc6-4198-8edb-8595e19ee359','題升山','任生','唐','唐诗','tang','','[]','城外升山寺，城中望宛然。',24,'全唐诗/poet.tang.43000.json','["城外升山寺，城中望宛然。", "及登無半日，欲到已經年。"]'),
('c0e28adc-3a45-4785-94f9-0f97f65ce9ba','投曹文姬詩','任生','唐','唐诗','tang','','[]','玉皇前殿掌書仙，一染塵心下九天。',32,'全唐诗/poet.tang.43000.json','["玉皇前殿掌書仙，一染塵心下九天。", "莫怪濃香薰骨膩，雲衣曾惹御爐煙。"]'),
('88dc04e9-e4ba-4f75-9cbf-400f5d76f6bb','絕句','吳公','唐','唐诗','tang','','[]','去國投茲土，編茅隱舊蹤。',24,'全唐诗/poet.tang.43000.json','["去國投茲土，編茅隱舊蹤。", "年年秋水上，獨對數株松。"]'),
('ad2878de-6f63-496e-a5f4-531e77314284','獻盧常侍','曹生','唐','唐诗','tang','','[]','拜玉亭前閑送客，此時孤恨感離鄉。',32,'全唐诗/poet.tang.43000.json','["拜玉亭前閑送客，此時孤恨感離鄉。", "尋思往歲絕纓事，肯向朱門泣夜長。"]'),
('706207ec-8207-47dd-815b-f2b4448bf4ef','賦新月','繆氏子','唐','唐诗','tang','','[]','初月如弓未上弦，分明挂在碧霄邊。',32,'全唐诗/poet.tang.43000.json','["初月如弓未上弦，分明挂在碧霄邊。", "時人莫道蛾眉小，三五團圓照滿天。"]'),
('a42d2e42-00bc-4a8b-9594-794dfb7d9cac','悼妓詩','京兆韋氏子','唐','唐诗','tang','','[]','惆悵金泥簇蝶裙，春來猶見伴行雲。',32,'全唐诗/poet.tang.43000.json','["惆悵金泥簇蝶裙，春來猶見伴行雲。", "不教布施剛留得，渾似初逢李少君。"]'),
('07400aad-ddbe-4eba-af00-017c29311a3e','長寧公主宅流杯','景龍文館學士','唐','唐诗','tang','','[]','憑高瞰逈足怡心，[菌]閣桃源不暇尋。',34,'全唐诗/poet.tang.43000.json','["憑高瞰逈足怡心，[菌]閣桃源不暇尋。", "餘雪依林成玉樹，殘霙點岫即瑤岑。"]'),
('dbfbbb23-04da-4d66-874b-1d0bd0db25b8','侍宴桃園詠桃花應制','神龍從臣','唐','唐诗','tang','','[]','源水叢花無數開，丹跗紅萼間青梅。',32,'全唐诗/poet.tang.43000.json','["源水叢花無數開，丹跗紅萼間青梅。", "從今結子三千歲，預喜仙遊復摘來。"]'),
('65cb8082-6449-4f49-9402-f2b27cbfb9e9','玉龍子詩','天寶時人','唐','唐诗','tang','','[]','聖運潛符瑞玉龍，自興雲雨更無蹤。',32,'全唐诗/poet.tang.43000.json','["聖運潛符瑞玉龍，自興雲雨更無蹤。", "不如渭水沙中得，爭保鑾輿復九重。"]'),
('3f06bbad-53b4-44c7-8f29-f9cdbf68167e','寄兄','僖宗朝北省官','唐','唐诗','tang','','[]','涉江今日恨偏多，援筆長吁欲奈何。',32,'全唐诗/poet.tang.43000.json','["涉江今日恨偏多，援筆長吁欲奈何。", "倘使淚流西去得，便應添作錦江波。"]'),
('e813e68b-6afa-4a6d-a4de-e89d3214f8c2','題屈原祠','洪州將軍','唐','唐诗','tang','','[]','蒼藤古木幾經春，舊祀祠堂小水濱。',32,'全唐诗/poet.tang.43000.json','["蒼藤古木幾經春，舊祀祠堂小水濱。", "行客謾陳三酎酒，大夫元是獨醒人。"]'),
('10294dd8-7c8d-42eb-b270-210d350cf261','題端正樹','貞元文士','唐','唐诗','tang','','[]','昔日偏霑雨露榮，德皇西幸賜嘉名。',32,'全唐诗/poet.tang.43000.json','["昔日偏霑雨露榮，德皇西幸賜嘉名。", "馬嵬此去無多地，合向楊妃冢上生。"]'),
('6137c425-f193-43a5-acc8-9bd3561576ec','寄內詩','河北士人','唐','唐诗','tang','','[]','握筆題詩易，荷戈征戍難。',48,'全唐诗/poet.tang.43000.json','["握筆題詩易，荷戈征戍難。", "慣從鴛被暖，怯向鴈門寒。", "瘦盡寬衣帶，啼多漬枕檀。", "試留青黛著，迴日畫眉看。"]'),
('f9b1a6d7-661c-4fbe-8000-860c2602fdc9','代妻荅詩','河北士人','唐','唐诗','tang','','[]','蓬鬢荆釵世所稀，布裙猶是嫁時衣。',32,'全唐诗/poet.tang.43000.json','["蓬鬢荆釵世所稀，布裙猶是嫁時衣。", "胡麻好種無人種，合是歸時底不歸。"]'),
('81fc4aab-1b16-468c-9275-8063ebff1238','丙申歲詩','元和舉子','唐','唐诗','tang','','[]','元和天子丙申年，三十三人同得仙。',32,'全唐诗/poet.tang.43000.json','["元和天子丙申年，三十三人同得仙。", "袍似爛銀文似錦，相將白日上青天。"]'),
('ce882edb-1da3-42ad-bf57-81c16314e90e','刺安南事詩','懿宗朝舉子','唐','唐诗','tang','','[]','南荒不擇吏，致我交趾覆。',132,'全唐诗/poet.tang.43000.json','["南荒不擇吏，致我交趾覆。", "聯綿三四年，致我交趾辱。", "儒者鬬則退，武者兵益黷。", "軍容滿天下，戰將多金玉。", "刮得齊民瘡，分爲猛士祿。", "雄雄許昌師，忠武冠其族。", "去爲萬騎風，住爲一川肉。", "時有殘卒迴，千門萬戶哭。", "哀聲動閭里，怨氣成山谷。", "誰能聽鼓聲，不忍看金鏃。", "念此堪淚流，悠悠潁川綠。"]'),
('3d2e3d64-a7e8-42d9-9e2b-e1093c1203c5','歌','白衫舉子','唐','唐诗','tang','','[]','執板狂歌乞個錢，塵中流浪且隨緣。',32,'全唐诗/poet.tang.43000.json','["執板狂歌乞個錢，塵中流浪且隨緣。", "直饒到老常如此，猶勝危時弄化權。"]'),
('ece0696f-706a-4087-8c90-64e4a9746af4','覩野花思京師舊遊','唐末朝士','唐','唐诗','tang','','[]','曾過街西看牡丹，牡丹纔謝便心闌。',32,'全唐诗/poet.tang.43000.json','["曾過街西看牡丹，牡丹纔謝便心闌。", "如今變作村園眼，鼓子花開也喜歡。"]'),
('ac2ec0ba-10b1-4ae3-8859-1e7752625331','哥舒歌','西鄙人','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u8d5e\u9882", "\u4e94\u8a00\u7edd\u53e5", "\u6c11\u6b4c"]','北斗七星高，哥舒夜帶刀。',24,'全唐诗/poet.tang.43000.json','["北斗七星高，哥舒夜帶刀。", "至今窺牧馬，不敢過臨洮。"]'),
('d4c479f9-4094-4baf-9efb-7032b61b4abc','荅人','太上隱君','唐','唐诗','tang','','[]','偶來松樹下，高枕石頭眠。',24,'全唐诗/poet.tang.43000.json','["偶來松樹下，高枕石頭眠。", "山中無曆日，寒盡不知年。"]'),
('d2f674f0-c7ef-4bdd-8462-26f10814d808','向竹吟','黃山隱','唐','唐诗','tang','','[]','積塵爲太山，掬水成東海。',48,'全唐诗/poet.tang.43000.json','["積塵爲太山，掬水成東海。", "富貴有時乖，希夷無日改。", "絳節出崆峒，霓衣發光彩。", "古者有七賢，六個今何在。"]'),
('99c7447e-3b32-4c4c-ac43-1b0cfcdfcce9','歌','婺州山中人','唐','唐诗','tang','','[]','靜居青嶂裏，高嘯紫煙中。',24,'全唐诗/poet.tang.43000.json','["靜居青嶂裏，高嘯紫煙中。", "塵世連仙界，瓊田前路通。"]'),
('edb3c7eb-b288-48ab-99a4-fa6cfcab9668','五子之歌 一','同谷子','唐','唐诗','tang','','[]','邦惟固本自安寧，臨下常須馭朽驚。',32,'全唐诗/poet.tang.43000.json','["邦惟固本自安寧，臨下常須馭朽驚。", "何事十旬遊不返，禍胎從此召殷兵。"]'),
('76e74dfc-abc7-45c9-becf-d87106eff26c','五子之歌 二','同谷子','唐','唐诗','tang','','[]','酒色聲禽號四荒，那堪峻宇又彫墙。',32,'全唐诗/poet.tang.43000.json','["酒色聲禽號四荒，那堪峻宇又彫墙。", "靜思今古爲君者，未或因茲不滅亡。"]'),
('d77d3397-803e-4837-8c46-7de3abf83055','五子之歌 三','同谷子','唐','唐诗','tang','','[]','唯彼陶唐有冀方，少年都不解思量。',32,'全唐诗/poet.tang.43000.json','["唯彼陶唐有冀方，少年都不解思量。", "如今算得當時事，首爲盤遊亂紀綱。"]'),
('3d48f15b-c077-41ae-92e6-f919030224f8','五子之歌 四','同谷子','唐','唐诗','tang','','[]','明明我祖萬邦君，典則貽將示子孫。',32,'全唐诗/poet.tang.43000.json','["明明我祖萬邦君，典則貽將示子孫。", "惆悵太康荒墜後，覆宗絕祀滅其門。"]'),
('fa9b4ec1-9bb9-43e5-b8c4-f0a5849b2976','五子之歌 五','同谷子','唐','唐诗','tang','','[]','仇讐萬姓遂無依，顏厚何曾解忸怩。',32,'全唐诗/poet.tang.43000.json','["仇讐萬姓遂無依，顏厚何曾解忸怩。", "五子既歌邦已失，一場前事悔難追。"]'),
('5f4fd1c5-7855-4e13-80ea-b1bc42a67de3','獻公佐詩','崔公佐客','唐','唐诗','tang','','[]','破額幞頭衫也穿，使君猶許對華筵。',32,'全唐诗/poet.tang.43000.json','["破額幞頭衫也穿，使君猶許對華筵。", "今朝幸倚文章守，遮莫青蛾笑揭天。"]'),
('81f9e068-6c89-4ab9-acac-53577be934fc','贈妓茂英','洛中舉子','唐','唐诗','tang','','[]','憶昔當初過柳樓，茂英年小尚嬌羞。',64,'全唐诗/poet.tang.43000.json','["憶昔當初過柳樓，茂英年小尚嬌羞。", "隔窗未省聞高語，對鏡曾窺學上頭。", "一別中原俱老大，再來南國見風流。", "彈弦酌酒話前事，零落碧雲生暮愁。"]'),
('ae719d0b-4811-4169-b7dd-8f056e9fbc37','又贈妓茂英','洛中舉子','唐','唐诗','tang','','[]','少插花枝少下籌，須防女伴妬風流。',32,'全唐诗/poet.tang.43000.json','["少插花枝少下籌，須防女伴妬風流。", "坐中若打占相令，除却尚書莫點頭。"]'),
('e8e098f0-39bf-45a2-95d2-6f4f6196b897','寄故姬','江陵士子','唐','唐诗','tang','','[]','陰雲羃羃下陽臺，惹著襄王更不迴。',64,'全唐诗/poet.tang.43000.json','["陰雲羃羃下陽臺，惹著襄王更不迴。", "五度看花空有淚，一心如結不曾開。", "纖蘿自合依芳樹，覆水寧思返舊杯。", "惆悵高麗坡底宅，春光無復下山來。"]'),
('9b75ff3c-1cd8-482c-9630-4a5f8f718cb8','吟','織錦人','唐','唐诗','tang','','[]','學織繚綾功未多，亂拈機杼錯拋梭。',32,'全唐诗/poet.tang.43000.json','["學織繚綾功未多，亂拈機杼錯拋梭。", "莫教官錦行家見，把此文章笑殺他。"]'),
('82d9c5ed-b2c7-49ae-94e3-e87546c8f61f','句','織錦人','唐','唐诗','tang','','[]','如今不重文章士，莫把文章誇向人。',16,'全唐诗/poet.tang.43000.json','["如今不重文章士，莫把文章誇向人。"]'),
('5a19f611-8a36-48e8-8c2e-f5c48f52c8f8','送南中尉','吏部選人','唐','唐诗','tang','','[]','羨君初拜職，嗟我獨無名。',24,'全唐诗/poet.tang.43000.json','["羨君初拜職，嗟我獨無名。", "且是正員尉，全勝兼試卿。"]'),
('dfbbaab5-110b-43ad-b000-6f2f066510c5','題紫微觀','建業卜者','唐','唐诗','tang','','[]','昨日朝天過紫微，醮壇風冷杏花稀。',32,'全唐诗/poet.tang.43000.json','["昨日朝天過紫微，醮壇風冷杏花稀。", "碧桃泥我傳消息，何事人間更不歸。"]'),
('c3a5a06a-e6c6-4c64-af4a-8bb4e1d6ccc6','題鄧仙客墓','天嶠遊人','唐','唐诗','tang','','[]','鶴老芝田雞在籠，上清那與俗塵同。',32,'全唐诗/poet.tang.43000.json','["鶴老芝田雞在籠，上清那與俗塵同。", "既言白日升仙去，何事人間有殯宮。"]'),
('8b19f000-da4b-4773-8faf-fab469cce0ca','題故翠微宮','驪山遊人','唐','唐诗','tang','','[]','翠微寺本翠微宮，樓閣亭臺幾十重。',32,'全唐诗/poet.tang.43000.json','["翠微寺本翠微宮，樓閣亭臺幾十重。", "天子不來僧又去，樵夫時倒一株松。"]'),
('e96c2374-51c8-4ddf-9880-e9b39d722814','吟','衡州舟子','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','野鵲灘西一櫂孤，月光遙接洞庭湖。',32,'全唐诗/poet.tang.43000.json','["野鵲灘西一櫂孤，月光遙接洞庭湖。", "堪嗟迴雁峰前過，望斷家山一字無。"]'),
('15456482-98d0-439e-8624-d53efd852b90','月夜','華山老人','唐','唐诗','tang','','[]','澗水泠泠聲不絕，溪流茫茫野花發。',32,'全唐诗/poet.tang.43000.json','["澗水泠泠聲不絕，溪流茫茫野花發。", "自去自來人不知，歸時常對空山月。"]'),
('20704ece-bf81-41c6-826d-1215212340f8','終南','終南山翁','唐','唐诗','tang','','[]','霜鶴鳴時夕風急，亂鴉又向寒林集。',32,'全唐诗/poet.tang.43000.json','["霜鶴鳴時夕風急，亂鴉又向寒林集。", "此君輟櫂悲且吟，獨對蓮花一峰立。"]'),
('e4263f1e-e295-45f5-b808-746af8db52a0','大慶堂賜宴元璫有詩呈吳越王','吳越失姓名人','唐','唐诗','tang','','[]','非爲親賢展綺筵，恆常寧敢恣遊盤。',64,'全唐诗/poet.tang.43000.json','["非爲親賢展綺筵，恆常寧敢恣遊盤。", "綠搓楊柳綿初軟，紅暈櫻桃粉未乾。", "谷鳥乍啼聲似澀，甘霖方霽景猶寒。", "笙歌風緊人酣醉，却遶珍叢爛熳看。"]'),
('56c30ecb-14a3-417d-9ef7-6bf756deeb0d','又和大慶堂賜宴元璫有詩呈吳越王','吳越失姓名人','唐','唐诗','tang','','[]','櫻桃花下會親賢，風遠銅壺轉露盤。',64,'全唐诗/poet.tang.43000.json','["櫻桃花下會親賢，風遠銅壺轉露盤。", "蝶下粉牆梅乍折，蟻浮金斝酒難乾。", "雲和緩奏泉聲咽，珠箔低垂水影寒。", "狂簡斐然吟詠足，却邀羣彥重吟看。"]'),
('6c982d54-f0f9-42fa-abfb-b676bc06bc54','再和大慶堂賜宴元璫有詩呈吳越王','吳越失姓名人','唐','唐诗','tang','','[]','我有嘉賓宴乍歡，畫簾紋細鳳雙盤。',64,'全唐诗/poet.tang.43000.json','["我有嘉賓宴乍歡，畫簾紋細鳳雙盤。", "影籠沼沚修篁密，聲透笙歌羯鼓乾。", "散後便依書篋寐，渴來潛想玉壺寒。", "櫻桃零落紅桃媚，更俟旬餘共醉看。"]'),
('a053b123-0b29-4377-b901-82582c68a04a','重和大慶堂賜宴元璫有詩呈吳越王','吳越失姓名人','唐','唐诗','tang','','[]','冷宴殷勤展小園，舞鞇柔軟綵虬盤。',64,'全唐诗/poet.tang.43000.json','["冷宴殷勤展小園，舞鞇柔軟綵虬盤。", "篸花盡日疑頭重，病酒經宵覺口乾。", "嘉樹倚樓青瑣暗，晚雲藏雨碧山寒。", "文章天子文章別，八采盧郎未可看。"]'),
('0f5ad3a2-5f02-454d-a820-2a19cc438e66','御製春遊長句','吳越失姓名人','唐','唐诗','tang','','[]','天意分明道已光，春遊嘉景勝仙鄉。',128,'全唐诗/poet.tang.43000.json','["天意分明道已光，春遊嘉景勝仙鄉。", "玉爐煙直風初靜，銀漢雲銷日正長。", "柳帶似眉全展綠，杏苞似臉半開香。", "黃鶯歷歷啼紅樹，紫燕關關語畫梁。", "低檻晚晴籠翡翠，小池波暖浴鴛鴦。", "馬嘶廣陌貪新草，人醉花堤怕夕陽。", "比屋管弦呈妙曲，連營羅綺鬬時妝。", "全吳霸越千年後，獨此昇平顯萬方。"]'),
('8e9c75d7-efad-4f3c-b815-7a38db500c61','明月湖醉後薔薇花歌','無名氏','唐','唐诗','tang','','[]','萬朵當軒紅灼灼，晚陰照水塵不著。',258,'全唐诗/poet.tang.43000.json','["萬朵當軒紅灼灼，晚陰照水塵不著。", "西施醉後情不禁，侍兒扶下蘂珠閣。", "柔條嫩蘂輕𩸬鰓，一低一昂合又開。", "深紅淺綠狀不得，日斜池畔香風來。", "紅能柔，綠能軟，濃淡參差相宛轉。", "舞蝶雙雙誰喚來，輕綃片片何人剪。", "白髮使君思帝鄉，驅妻領女遊花傍。", "持盃憶著曲江事，千花萬葉垂宮墙。", "復有同心初上第，日暮華筵移水際。", "笙歌日日徵教坊，傾國名倡盡佳麗。", "我曾此處同諸生，飛盂落盞紛縱橫。", "將欲得到上天路，剛向直道中行去。", "一朝失勢當如此，萬事如灰壯心死。", "誰知奏御數萬言，翻割龜符四千里。", "丈夫達則賢，窮則愚，胡爲紫，胡爲朱。", "莫思身外窮通事，且醉花前一百壺。"]'),
('4cc12782-cd3c-4b6e-a929-39f538f45ea5','春二首 一','無名氏','唐','唐诗','tang','','[]','褭褭東風吹水國，金鴉影暖南山北。',64,'全唐诗/poet.tang.43000.json','["褭褭東風吹水國，金鴉影暖南山北。", "蒲抽小劒割湘波，柳拂長眉舞春色。", "白銅堤下煙蒼蒼，林端細蘂參差香。", "綠桑枝下見桃葉，迴看青雲空斷腸。"]'),
('80156189-2d99-41ce-aab7-f041119c4d52','春二首 二','無名氏','唐','唐诗','tang','','[]','烏足遲遲日宮裏，天門擊鼓龍蛇起。',64,'全唐诗/poet.tang.43000.json','["烏足遲遲日宮裏，天門擊鼓龍蛇起。", "風師剪翠換枯條，青帝挼藍染江水。", "蜂蝶繽紛抱香蘂，錦鱗跳擲紅雲尾。", "繡衣白馬不歸來，雙成倚檻春心醉。"]'),
('8f345357-26c3-4dfc-8e76-49f8624e7514','夏','無名氏','唐','唐诗','tang','','[]','赤帝旗迎火雲起，南山石裂吳牛死。',64,'全唐诗/poet.tang.43000.json','["赤帝旗迎火雲起，南山石裂吳牛死。", "繡楹夜夜箔鰕鬚，象榻重重簟湘水。", "彤彤日脚燒冰井，古陌塵飛野煙靜。", "漢帝高堂汗若珠，班姬明月無停影。"]'),
('5e52f451-32d0-4fd4-9032-f1d808c18500','秋','無名氏','唐','唐诗','tang','','[]','月色驅秋下穹昊，梁間燕語辭巢早。',64,'全唐诗/poet.tang.43000.json','["月色驅秋下穹昊，梁間燕語辭巢早。", "古苔凝紫貼瑤堦，露槿啼紅墮江草。", "越客羈魂挂長道，西風欲揭南山倒。", "粉娥恨骨不勝衣，映門楚碧蟬聲老。"]'),
('353b265c-fa15-4dc0-a037-83d9d63f96d0','冬','無名氏','唐','唐诗','tang','','[]','蒼茫枯磧陰雲滿，古木號空晝光短。',64,'全唐诗/poet.tang.43000.json','["蒼茫枯磧陰雲滿，古木號空晝光短。", "雲擁三峯嶽色低，冰堅九曲河聲斷。", "浩汗霜風刮天地，溫泉火井無生意。", "澤國龍蛇凍不伸，南山瘦柏銷殘翠。"]'),
('c414007e-44a0-410f-8262-6793c6a35907','雞頭','無名氏','唐','唐诗','tang','','[]','湖浪參差疊寒玉，水仙曉展鉢盤綠。',64,'全唐诗/poet.tang.43000.json','["湖浪參差疊寒玉，水仙曉展鉢盤綠。", "淡黃根老栗皺圓，染青刺短金罌熟。", "紫羅小囊光緊蹙，一掬真珠藏蝟腹。", "叢叢引觜傍蓮洲，滿川恐作天雞哭。"]'),
('ff01b7b3-16d8-4508-990e-f67db21ac971','紅薔薇','無名氏','唐','唐诗','tang','','[]','九天碎霞明澤國，造化工夫潛剪刻。',64,'全唐诗/poet.tang.43000.json','["九天碎霞明澤國，造化工夫潛剪刻。", "淺碧眉長約細枝，深紅刺短鉤春色。", "晴日當樓曉香歇，錦帶盤空欲成結。", "謝豹聲催麥隴秋，春風吹落猩猩血。"]'),
('bf510c42-d553-4816-8896-43ac1e832bfc','斑竹簟','無名氏','唐','唐诗','tang','','[]','龍鱗滿牀波浪濕，血光點點湘娥泣。',64,'全唐诗/poet.tang.43000.json','["龍鱗滿牀波浪濕，血光點點湘娥泣。", "一片晴霞凍不飛，深沈盡訝蛟人立。", "百朵排花蜀纈明，珊瑚枕滑葛衣輕。", "閑窗獨臥曉不起，冷浸羈魂錦江裏。"]');
